INSERT INTO "questions" ("id", "question", "options", "correct", "section") VALUES
(1,	'Яким чином у конституційному праві розуміється доктрина дружнього ставлення до міжнародного права?',	'["\u0412\u0438\u043c\u0430\u0433\u0430\u0454 \u0432\u0440\u0430\u0445\u0443\u0432\u0430\u043d\u043d\u044f \u0454\u0432\u0440\u043e\u043f\u0435\u0439\u0441\u044c\u043a\u043e\u0433\u043e \u0442\u0430 \u043c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u043e\u0433\u043e \u043f\u0440\u0430\u0432\u0430 \u043f\u0440\u0438 \u0442\u043b\u0443\u043c\u0430\u0447\u0435\u043d\u043d\u0456 \u043a\u043e\u043d\u0441\u0442\u0438\u0442\u0443\u0446\u0456\u0457.", "\u041c\u043e\u0436\u0435 \u0432 \u0434\u0435\u044f\u043a\u0438\u0445 \u0432\u0438\u043f\u0430\u0434\u043a\u0430\u0445 \u043f\u0440\u0438\u0437\u0432\u043e\u0434\u0438\u0442\u0438 \u0434\u043e \u0441\u0443\u0431\u0441\u0438\u0434\u0456\u0430\u0440\u043d\u043e\u0433\u043e \u0437\u0430\u0441\u0442\u043e\u0441\u0443\u0432\u0430\u043d\u043d\u044f \u043d\u043e\u0440\u043c \u041a\u043e\u043d\u0441\u0442\u0438\u0442\u0443\u0446\u0456\u0457 \u043f\u043e\u0440\u0456\u0432\u043d\u044f\u043d\u043e \u0437 \u043c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u0438\u043c\u0438 \u0430\u043a\u0442\u0430\u043c\u0438", "\u0490\u0440\u0443\u043d\u0442\u0443\u0454\u0442\u044c\u0441\u044f \u043d\u0430 \u043f\u0440\u0456\u043e\u0440\u0438\u0442\u0435\u0442\u043d\u043e\u043c\u0443 \u0432\u0438\u043a\u043e\u0440\u0438\u0441\u0442\u0430\u043d\u043d\u0456 \u0454\u0432\u0440\u043e\u043f\u0435\u0439\u0441\u044c\u043a\u043e\u0433\u043e \u0442\u0430 \u043c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u043e\u0433\u043e \u0437\u0430\u043a\u043e\u043d\u043e\u0434\u0430\u0432\u0441\u0442\u0432\u0430 \u043f\u0440\u0438 \u0442\u043b\u0443\u043c\u0430\u0447\u0435\u043d\u043d\u0456 \u041a\u043e\u043d\u0441\u0442\u0438\u0442\u0443\u0446\u0456\u0457.", "\u041f\u0435\u0440\u0435\u0434\u0431\u0430\u0447\u0430\u0454 \u0434\u043e\u0442\u0440\u0438\u043c\u0430\u043d\u043d\u044f \u0434\u0435\u0440\u0436\u0430\u0432\u043e\u044e \u0432\u0437\u044f\u0442\u0438\u0445 \u043d\u0430 \u0441\u0435\u0431\u0435 \u043c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u043e- \u043f\u0440\u0430\u0432\u043e\u0432\u0438\u0445 \u0437\u043e\u0431\u043e\u0432\u02bc\u044f\u0437\u0430\u043d\u044c \u043f\u0440\u0438 \u043f\u0440\u0438\u0439\u043d\u044f\u0442\u0442\u0456 \u041a\u043e\u043d\u0441\u0442\u0438\u0442\u0443\u0446\u0456\u0457, \u0432\u043d\u0435\u0441\u0435\u043d\u043d\u0456 \u0434\u043e \u043d\u0435\u0457 \u0437\u043c\u0456\u043d \u0442\u0430 \u0434\u043e\u043f\u043e\u0432\u043d\u0435\u043d\u044c."]',	0,	'КОНСТИТУЦІЙНЕ ПРАВО'),
(2,	'Розроблено законопроєкт про внесення змін до розділу ІІІ «Вибори. Референдум» Конституції України. Хто із зазначених суб’єктів має право внести його на розгляд до Верховної Ради України?',	'["\u0449\u043e\u043d\u0430\u0439\u043c\u0435\u043d\u0448\u0435 150 \u043d\u0430\u0440\u043e\u0434\u043d\u0438\u0445 \u0434\u0435\u043f\u0443\u0442\u0430\u0442\u0456\u0432 \u0423\u043a\u0440\u0430\u0457\u043d\u0438", "\u0426\u0435\u043d\u0442\u0440\u0430\u043b\u044c\u043d\u0430 \u0432\u0438\u0431\u043e\u0440\u0447\u0430 \u043a\u043e\u043c\u0456\u0441\u0456\u044f \u0423\u043a\u0440\u0430\u0457\u043d\u0438", "\u041a\u0430\u0431\u0456\u043d\u0435\u0442 \u041c\u0456\u043d\u0456\u0441\u0442\u0440\u0456\u0432 \u0423\u043a\u0440\u0430\u0457\u043d\u0438", "\u0449\u043e\u043d\u0430\u0439\u043c\u0435\u043d\u0448\u0435 300 \u043d\u0430\u0440\u043e\u0434\u043d\u0438\u0445 \u0434\u0435\u043f\u0443\u0442\u0430\u0442\u0456\u0432 \u0423\u043a\u0440\u0430\u0457\u043d\u0438"]',	3,	'КОНСТИТУЦІЙНЕ ПРАВО'),
(3,	'Повідомлення якого з наведених органів про проведення мітингу є необхідною умовою реалізації права на мирні зібрання?',	'["\u043f\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043d\u0438\u0446\u0442\u0432\u0430 \u0423\u043f\u043e\u0432\u043d\u043e\u0432\u0430\u0436\u0435\u043d\u043e\u0433\u043e \u0412\u0435\u0440\u0445\u043e\u0432\u043d\u043e\u0457 \u0420\u0430\u0434\u0438 \u0423\u043a\u0440\u0430\u0457\u043d\u0438 \u0437 \u043f\u0440\u0430\u0432 \u043b\u044e\u0434\u0438\u043d\u0438", "\u0442\u0435\u0440\u0438\u0442\u043e\u0440\u0456\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0443\u043f\u0440\u0430\u0432\u043b\u0456\u043d\u043d\u044f \u043d\u0430\u0446\u0456\u043e\u043d\u0430\u043b\u044c\u043d\u043e\u0457 \u043f\u043e\u043b\u0456\u0446\u0456\u0457", "\u043e\u043a\u0440\u0443\u0436\u043d\u043e\u0433\u043e \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0442\u0438\u0432\u043d\u043e\u0433\u043e \u0441\u0443\u0434\u0443", "\u043c\u0456\u0441\u0446\u0435\u0432\u043e\u0457 \u0434\u0435\u0440\u0436\u0430\u0432\u043d\u043e\u0457 \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0446\u0456\u0457"]',	3,	'КОНСТИТУЦІЙНЕ ПРАВО'),
(4,	'Який субʼєкт, згідно з Конституцією України, повноважний визначати засади реалізації стратегічного курсу держави на набуття повноправного членства України в НАТО?',	'["\u041a\u0430\u0431\u0456\u043d\u0435\u0442 \u041c\u0456\u043d\u0456\u0441\u0442\u0440\u0456\u0432 \u0423\u043a\u0440\u0430\u0457\u043d\u0438", "\u041f\u0440\u0435\u0437\u0438\u0434\u0435\u043d\u0442 \u0423\u043a\u0440\u0430\u0457\u043d\u0438", "\u0412\u0435\u0440\u0445\u043e\u0432\u043d\u0430 \u0420\u0430\u0434\u0430 \u0423\u043a\u0440\u0430\u0457\u043d\u0438", "\u0420\u0430\u0434\u0430 \u043d\u0430\u0446\u0456\u043e\u043d\u0430\u043b\u044c\u043d\u043e\u0457 \u0431\u0435\u0437\u043f\u0435\u043a\u0438 \u0456 \u043e\u0431\u043e\u0440\u043e\u043d\u0438 \u0423\u043a\u0440\u0430\u0457\u043d\u0438"]',	2,	'КОНСТИТУЦІЙНЕ ПРАВО'),
(5,	'Інспектор митної служби, здійснюючи митний контроль в пункті пропуску на українсько-румунському кордоні, володіє українською, румунською та англійською мовами. Яку мову має право застосовувати інспектор при здійсненні митного контролю під час перетину іноземцями державного кордону між Румунією та Україною?',	'["\u0423\u043a\u0440\u0430\u0457\u043d\u0441\u044c\u043a\u0443, \u0430\u043d\u0433\u043b\u0456\u0439\u0441\u044c\u043a\u0443 \u0430\u0431\u043e \u0440\u0443\u043c\u0443\u043d\u0441\u044c\u043a\u0443 \u043c\u043e\u0432\u0443 \u0437\u0430\u043b\u0435\u0436\u043d\u043e \u0432\u0456\u0434 \u043f\u043e\u0442\u0440\u0435\u0431\u0438, \u0442\u0430\u043a \u044f\u043a \u043d\u0438\u043c\u0438 \u0432\u043e\u043b\u043e\u0434\u0456\u0454 \u0456\u043d\u0441\u043f\u0435\u043a\u0442\u043e\u0440.", "\u0423\u043a\u0440\u0430\u0457\u043d\u0441\u044c\u043a\u0443 \u0430\u0431\u043e \u0440\u0443\u043c\u0443\u043d\u0441\u044c\u043a\u0443 \u043c\u043e\u0432\u0443, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u043c\u0438\u0442\u043d\u0438\u0439 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u0437\u0434\u0456\u0439\u0441\u043d\u044e\u0454\u0442\u044c\u0441\u044f \u043d\u0430 \u043a\u043e\u0440\u0434\u043e\u043d\u0456 \u0437 \u0420\u0443\u043c\u0443\u043d\u0456\u0454\u044e.", "\u0412\u0438\u043a\u043b\u044e\u0447\u043d\u043e \u0443\u043a\u0440\u0430\u0457\u043d\u0441\u044c\u043a\u0443 \u043c\u043e\u0432\u0443 \u044f\u043a \u0454\u0434\u0438\u043d\u0443 \u0434\u0435\u0440\u0436\u0430\u0432\u043d\u0443 \u043c\u043e\u0432\u0443 \u0432 \u0423\u043a\u0440\u0430\u0457\u043d\u0456.", "\u0412\u0438\u043a\u043b\u044e\u0447\u043d\u043e \u0430\u043d\u0433\u043b\u0456\u0439\u0441\u044c\u043a\u0443 \u043c\u043e\u0432\u0443 \u044f\u043a \u043c\u043e\u0432\u0443 \u043c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u043e\u0433\u043e \u0441\u043f\u0456\u043b\u043a\u0443\u0432\u0430\u043d\u043d\u044f."]',	0,	'КОНСТИТУЦІЙНЕ ПРАВО'),
(6,	'Указом Президента України затверджено рішення Ради національної безпеки та оборони України «Про затвердження Положення про Державний реєстр санкцій». На кого покладається контроль за виконанням рішення?',	'["\u041f\u0440\u0435\u043c\u02bc\u0454\u0440-\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430 \u0423\u043a\u0440\u0430\u0457\u043d\u0438.", "\u0413\u043e\u043b\u043e\u0432\u0443 \u0412\u0435\u0440\u0445\u043e\u0432\u043d\u043e\u0457 \u0440\u0430\u0434\u0438 \u0423\u043a\u0440\u0430\u0457\u043d\u0438.", "\u041f\u0440\u0435\u0437\u0438\u0434\u0435\u043d\u0442\u0430 \u0423\u043a\u0440\u0430\u0457\u043d\u0438.", "\u0421\u0435\u043a\u0440\u0435\u0442\u0430\u0440\u044f \u0420\u0430\u0434\u0438 \u043d\u0430\u0446\u0456\u043e\u043d\u0430\u043b\u044c\u043d\u043e\u0457 \u0431\u0435\u0437\u043f\u0435\u043a\u0438 \u0456 \u043e\u0431\u043e\u0440\u043e\u043d\u0438 \u0423\u043a\u0440\u0430\u0457\u043d\u0438."]',	3,	'КОНСТИТУЦІЙНЕ ПРАВО'),
(14,	'Який або які органи Конституційного Суду України відкривають провадження у справі за конституційним зверненням?',	'["\u041a\u043e\u043b\u0435\u0433\u0456\u044f \u0430\u0431\u043e \u0412\u0435\u043b\u0438\u043a\u0430 \u043f\u0430\u043b\u0430\u0442\u0430 \u0441\u0443\u0434\u0434\u0456\u0432 \u041a\u043e\u043d\u0441\u0442\u0438\u0442\u0443\u0446\u0456\u0439\u043d\u043e\u0433\u043e \u0421\u0443\u0434\u0443 \u0423\u043a\u0440\u0430\u0457\u043d\u0438", "\u041a\u043e\u043b\u0435\u0433\u0456\u044f \u0430\u0431\u043e \u0421\u0435\u043d\u0430\u0442 \u041a\u043e\u043d\u0441\u0442\u0438\u0442\u0443\u0446\u0456\u0439\u043d\u043e\u0433\u043e \u0421\u0443\u0434\u0443 \u0423\u043a\u0440\u0430\u0457\u043d\u0438", "\u041a\u043e\u043b\u0435\u0433\u0456\u044f \u0430\u0431\u043e \u0421\u0435\u043a\u0440\u0435\u0442\u0430\u0440\u0456\u0430\u0442 \u041a\u043e\u043d\u0441\u0442\u0438\u0442\u0443\u0446\u0456\u0439\u043d\u043e\u0433\u043e \u0421\u0443\u0434\u0443 \u0423\u043a\u0440\u0430\u0457\u043d\u0438", "\u0412\u0438\u043a\u043b\u044e\u0447\u043d\u043e \u041a\u043e\u043b\u0435\u0433\u0456\u044f \u0441\u0443\u0434\u0434\u0456\u0432 \u041a\u043e\u043d\u0441\u0442\u0438\u0442\u0443\u0446\u0456\u0439\u043d\u043e\u0433\u043e \u0421\u0443\u0434\u0443 \u0423\u043a\u0440\u0430\u0457\u043d\u0438"]',	0,	'КОНСТИТУЦІЙНЕ ПРАВО'),
(7,	'У місті проживає 130569 осіб, із них 122300 є громадянами України. Станом на 1 січня 2023 року кількість виборців у місті становить 75000. Станом на 1 серпня така кількість становить 74900. У день місцевих виборів (27 жовтня) до списків виборців внесено 75427 громадян. За якою виборчою системою повині були бути проведені вибори міського голови (27 жовтня)?',	'["\u041c\u0430\u0436\u043e\u0440\u0438\u0442\u0430\u0440\u043d\u043e\u044e \u0441\u0438\u0441\u0442\u0435\u043c\u043e\u044e \u0430\u0431\u0441\u043e\u043b\u044e\u0442\u043d\u043e\u0457 \u0431\u0456\u043b\u044c\u0448\u043e\u0441\u0442\u0456.", "\u041c\u0430\u0436\u043e\u0440\u0438\u0442\u0430\u0440\u043d\u043e\u044e \u0441\u0438\u0441\u0442\u0435\u043c\u043e\u044e \u0432\u0456\u0434\u043d\u043e\u0441\u043d\u043e\u0457 \u0431\u0456\u043b\u044c\u0448\u043e\u0441\u0442\u0456.", "\u041f\u0440\u043e\u043f\u043e\u0440\u0446\u0456\u0439\u043d\u043e\u044e \u0441\u0438\u0441\u0442\u0435\u043c\u043e\u044e \u0456\u0437 \u0432\u0456\u0434\u043a\u0440\u0438\u0442\u0438\u043c\u0438 \u0441\u043f\u0438\u0441\u043a\u0430\u043c\u0438.", "\u041f\u0440\u043e\u043f\u043e\u0440\u0446\u0456\u0439\u043d\u043e\u044e \u0441\u0438\u0441\u0442\u0435\u043c\u043e\u044e \u0456\u0437 \u0437\u0430\u043a\u0440\u0438\u0442\u0438\u043c\u0438 \u0441\u043f\u0438\u0441\u043a\u0430\u043c\u0438."]',	1,	'КОНСТИТУЦІЙНЕ ПРАВО'),
(8,	'Що відповідно до Закону України «Про столицю України місто-герой Київ» НЕ належить до системи органів місцевого самоврядування в м. Києві?',	'["\u041c\u0456\u0441\u044c\u043a\u0430 \u0440\u0430\u0434\u0430.", "\u041c\u0456\u0441\u044c\u043a\u0438\u0439 \u0433\u043e\u043b\u043e\u0432\u0430.", "\u0420\u0430\u0439\u043e\u043d\u043d\u0456 \u0440\u0430\u0434\u0438.", "\u0420\u0430\u0439\u043e\u043d\u043d\u0456 \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0446\u0456\u0457 \u043c\u0456\u0441\u044c\u043a\u043e\u0457 \u0440\u0430\u0434\u0438."]',	3,	'КОНСТИТУЦІЙНЕ ПРАВО'),
(9,	'Хто НЕ є субʼєктом, що здійснює обрання (призначення) членів Вищої Ради правосуддя?',	'["\u0417\u2019\u0457\u0437\u0434 \u0441\u0443\u0434\u0434\u0456\u0432 \u0423\u043a\u0440\u0430\u0457\u043d\u0438.", "\u041f\u0440\u0435\u0437\u0438\u0434\u0435\u043d\u0442 \u0423\u043a\u0440\u0430\u0457\u043d\u0438.", "\u0412\u0438\u0449\u0430 \u043a\u0432\u0430\u043b\u0456\u0444\u0456\u043a\u0430\u0446\u0456\u0439\u043d\u0430 \u043a\u043e\u043c\u0456\u0441\u0456\u044f \u0441\u0443\u0434\u0434\u0456\u0432 \u0423\u043a\u0440\u0430\u0457\u043d\u0438.", "\u0412\u0435\u0440\u0445\u043e\u0432\u043d\u0430 \u0420\u0430\u0434\u0430 \u0423\u043a\u0440\u0430\u0457\u043d\u0438."]',	2,	'КОНСТИТУЦІЙНЕ ПРАВО'),
(10,	'До територіального підрозділу Державної міграційної служби України надійшло звернення щодо припинення громадянства України особи, стосовно якої встановлено факт наявності громадянства російської федерації. Яке рішення має прийняти уповноважений орган у такій ситуації?',	'["\u0420\u043e\u0437\u043f\u043e\u0447\u0430\u0442\u0438 \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0442\u0438\u0432\u043d\u0443 \u043f\u0440\u043e\u0446\u0435\u0434\u0443\u0440\u0443 \u043f\u043e\u0437\u0431\u0430\u0432\u043b\u0435\u043d\u043d\u044f \u0433\u0440\u043e\u043c\u0430\u0434\u044f\u043d\u0441\u0442\u0432\u0430", "\u041f\u0435\u0440\u0435\u0434\u0430\u0442\u0438 \u043c\u0430\u0442\u0435\u0440\u0456\u0430\u043b\u0438 \u0434\u043e \u0441\u0443\u0434\u0443 \u0434\u043b\u044f \u0432\u0438\u0440\u0456\u0448\u0435\u043d\u043d\u044f \u043f\u0438\u0442\u0430\u043d\u043d\u044f \u043f\u0440\u043e \u043f\u043e\u0437\u0431\u0430\u0432\u043b\u0435\u043d\u043d\u044f \u0433\u0440\u043e\u043c\u0430\u0434\u044f\u043d\u0441\u0442\u0432\u0430", "\u041f\u0435\u0440\u0435\u0434\u0430\u0442\u0438 \u043a\u043b\u043e\u043f\u043e\u0442\u0430\u043d\u043d\u044f \u043f\u0440\u043e \u043f\u043e\u0437\u0431\u0430\u0432\u043b\u0435\u043d\u043d\u044f \u0433\u0440\u043e\u043c\u0430\u0434\u044f\u043d\u0441\u0442\u0432\u0430 \u043d\u0430 \u0440\u043e\u0437\u0433\u043b\u044f\u0434 \u041f\u0440\u0435\u0437\u0438\u0434\u0435\u043d\u0442\u0430 \u0423\u043a\u0440\u0430\u0457\u043d\u0438", "\u0412\u0456\u0434\u043c\u043e\u0432\u0438\u0442\u0438, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u043f\u043e\u0437\u0431\u0430\u0432\u043b\u0435\u043d\u043d\u044f \u0433\u0440\u043e\u043c\u0430\u0434\u044f\u043d\u0441\u0442\u0432\u0430 \u0423\u043a\u0440\u0430\u0457\u043d\u0438 \u043d\u0435 \u0434\u043e\u043f\u0443\u0441\u043a\u0430\u0454\u0442\u044c\u0441\u044f"]',	3,	'КОНСТИТУЦІЙНЕ ПРАВО'),
(11,	'Що НЕ є підставою для анулювання реєстраційного свідоцтва політичної партії?',	'["\u0412\u0438\u044f\u0432\u043b\u0435\u043d\u043d\u044f \u043f\u0440\u043e\u0442\u044f\u0433\u043e\u043c \u0442\u0440\u044c\u043e\u0445 \u0440\u043e\u043a\u0456\u0432 \u0437 \u0434\u043d\u044f \u0440\u0435\u0454\u0441\u0442\u0440\u0430\u0446\u0456\u0457 \u043f\u043e\u043b\u0456\u0442\u0438\u0447\u043d\u043e\u0457 \u043f\u0430\u0440\u0442\u0456\u0457 \u043d\u0435\u0434\u043e\u0441\u0442\u043e\u0432\u0456\u0440\u043d\u0438\u0445 \u0432\u0456\u0434\u043e\u043c\u043e\u0441\u0442\u0435\u0439 \u0443 \u043f\u043e\u0434\u0430\u043d\u0438\u0445 \u043d\u0430 \u0440\u0435\u0454\u0441\u0442\u0440\u0430\u0446\u0456\u044e \u0434\u043e\u043a\u0443\u043c\u0435\u043d\u0442\u0430\u0445;", "\u041d\u0435\u0432\u0438\u0441\u0443\u0432\u0430\u043d\u043d\u044f \u043f\u043e\u043b\u0456\u0442\u0438\u0447\u043d\u043e\u044e \u043f\u0430\u0440\u0442\u0456\u0454\u044e \u0441\u0432\u043e\u0457\u0445 \u043a\u0430\u043d\u0434\u0438\u0434\u0430\u0442\u0456\u0432 \u043f\u043e \u0432\u0438\u0431\u043e\u0440\u0430\u0445 \u041f\u0440\u0435\u0437\u0438\u0434\u0435\u043d\u0442\u0430 \u0423\u043a\u0440\u0430\u0457\u043d\u0438 \u0442\u0430 \u0432\u0438\u0431\u043e\u0440\u0430\u0445 \u043d\u0430\u0440\u043e\u0434\u043d\u0438\u0445 \u0434\u0435\u043f\u0443\u0442\u0430\u0442\u0456\u0432 \u0423\u043a\u0440\u0430\u0457\u043d\u0438 \u043f\u0440\u043e\u0442\u044f\u0433\u043e\u043c \u0434\u0435\u0441\u044f\u0442\u0438 \u0440\u043e\u043a\u0456\u0432;", "\u0414\u0456\u044f\u043b\u044c\u043d\u0456\u0441\u0442\u044c \u043f\u043e\u043b\u0456\u0442\u0438\u0447\u043d\u043e\u0457 \u043f\u0430\u0440\u0442\u0456\u0457, \u0441\u043f\u0440\u044f\u043c\u043e\u0432\u0430\u043d\u0430 \u043d\u0430 \u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u0441\u0443\u0432\u0435\u0440\u0435\u043d\u0456\u0442\u0435\u0442\u0443 \u0456 \u0442\u0435\u0440\u0438\u0442\u043e\u0440\u0456\u0430\u043b\u044c\u043d\u043e\u0457 \u0446\u0456\u043b\u0456\u0441\u043d\u043e\u0441\u0442\u0456 \u0423\u043a\u0440\u0430\u0457\u043d\u0438, \u043f\u043e\u0441\u044f\u0433\u0430\u043d\u043d\u044f \u043d\u0430 \u043f\u0440\u0430\u0432\u0430 \u0456 \u0441\u0432\u043e\u0431\u043e\u0434\u0438 \u043b\u044e\u0434\u0438\u043d\u0438; \u041d\u0435 \u0437\u0430\u0431\u0435\u0437\u043f\u0435\u0447\u0435\u043d\u043d\u044f \u043f\u043e\u043b\u0456\u0442\u0438\u0447\u043d\u043e\u044e \u043f\u0430\u0440\u0442\u0456\u0454\u044e \u043f\u0440\u043e\u0442\u044f\u0433\u043e\u043c \u0448\u0435\u0441\u0442\u0438 \u043c\u0456\u0441\u044f\u0446\u0456\u0432 \u0437 \u0434\u043d\u044f", "\u0440\u0435\u0454\u0441\u0442\u0440\u0430\u0446\u0456\u0457 \u0443\u0442\u0432\u043e\u0440\u0435\u043d\u043d\u044f \u0442\u0430 \u0440\u0435\u0454\u0441\u0442\u0440\u0430\u0446\u0456\u044e \u0441\u0432\u043e\u0457\u0445 \u043e\u0431\u043b\u0430\u0441\u043d\u0438\u0445 \u043e\u0440\u0433\u0430\u043d\u0456\u0437\u0430\u0446\u0456\u0439 \u0443 \u0431\u0456\u043b\u044c\u0448\u043e\u0441\u0442\u0456 \u043e\u0431\u043b\u0430\u0441\u0442\u0435\u0439 \u0423\u043a\u0440\u0430\u0457\u043d\u0438, \u043c\u0456\u0441\u0442\u0430\u0445 \u041a\u0438\u0454\u0432\u0456, \u0421\u0435\u0432\u0430\u0441\u0442\u043e\u043f\u043e\u043b\u0456 \u0442\u0430 \u0432 \u0410\u0432\u0442\u043e\u043d\u043e\u043c\u043d\u0456\u0439 \u0420\u0435\u0441\u043f\u0443\u0431\u043b\u0456\u0446\u0456 \u041a\u0440\u0438\u043c."]',	2,	'КОНСТИТУЦІЙНЕ ПРАВО'),
(12,	'Обласна рада простою більшістю голосів депутатів висловила недовіру голові обласної державної адміністрації. Якими є наслідки такого рішення обласної державної адміністрації?',	'["\u041f\u0440\u0435\u0437\u0438\u0434\u0435\u043d\u0442 \u043f\u0440\u0438\u0439\u043c\u0430\u0454 \u0440\u0456\u0448\u0435\u043d\u043d\u044f \u043f\u0440\u043e \u0432\u0456\u0434\u0441\u0442\u0430\u0432\u043a\u0443 \u0430\u0431\u043e \u0437\u0430\u043b\u0438\u0448\u0435\u043d\u043d\u044f \u043d\u0430 \u043f\u043e\u0441\u0430\u0434\u0456 \u0433\u043e\u043b\u043e\u0432\u0438 \u043e\u0431\u043b\u0430\u0441\u043d\u043e\u0457 \u0434\u0435\u0440\u0436\u0430\u0432\u043d\u043e\u0457 \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0446\u0456\u0457\u0456 \u0434\u0430\u0454 \u0440\u0430\u0434\u0456 \u043e\u0431\u0491\u0440\u0443\u043d\u0442\u043e\u0432\u0430\u043d\u0443 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u044c", "\u041f\u0440\u0435\u0437\u0438\u0434\u0435\u043d\u0442 \u0423\u043a\u0440\u0430\u0457\u043d\u0438 \u0434\u043e\u0440\u0443\u0447\u0430\u0454 \u041a\u0430\u0431\u0456\u043d\u0435\u0442\u0443 \u041c\u0456\u043d\u0456\u0441\u0442\u0440\u0456\u0432 \u0423\u043a\u0440\u0430\u0457\u043d\u0438 \u043f\u0440\u043e\u0432\u0435\u0441\u0442\u0438 \u043f\u0435\u0440\u0435\u0432\u0456\u0440\u043a\u0443 \u0434\u0456\u044f\u043b\u044c\u043d\u043e\u0441\u0442\u0456 \u0433\u043e\u043b\u043e\u0432\u0438 \u043e\u0431\u043b\u0430\u0441\u043d\u043e\u0457 \u0434\u0435\u0440\u0436\u0430\u0432\u043d\u043e\u0457 \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0446\u0456\u0457", "\u041a\u0430\u0431\u0456\u043d\u0435\u0442 \u041c\u0456\u043d\u0456\u0441\u0442\u0440\u0456\u0432 \u0423\u043a\u0440\u0430\u0457\u043d\u0438 \u0432\u043d\u043e\u0441\u0438\u0442\u044c \u043f\u043e\u0434\u0430\u043d\u043d\u044f \u041f\u0440\u0435\u0437\u0438\u0434\u0435\u043d\u0442\u0443 \u0423\u043a\u0440\u0430\u0457\u043d\u0438 \u043f\u0440\u043e \u0443\u0441\u0443\u043d\u0435\u043d\u043d\u044f \u0433\u043e\u043b\u043e\u0432\u0438 \u043e\u0431\u043b\u0430\u0441\u043d\u043e\u0457 \u0434\u0435\u0440\u0436\u0430\u0432\u043d\u043e\u0457 \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0446\u0456\u0457 \u0437 \u043f\u043e\u0441\u0430\u0434\u0438", "\u041f\u0440\u0435\u0437\u0438\u0434\u0435\u043d\u0442 \u0423\u043a\u0440\u0430\u0457\u043d\u0438 \u043f\u0440\u0438\u0439\u043c\u0430\u0454 \u0440\u0456\u0448\u0435\u043d\u043d\u044f \u043f\u0440\u043e \u0432\u0456\u0434\u0441\u0442\u0430\u0432\u043a\u0443 \u0433\u043e\u043b\u043e\u0432\u0438 \u043e\u0431\u043b\u0430\u0441\u043d\u043e\u0457 \u0434\u0435\u0440\u0436\u0430\u0432\u043d\u043e\u0457 \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0446\u0456\u0457"]',	0,	'КОНСТИТУЦІЙНЕ ПРАВО'),
(13,	'Що НЕ є підставою для дострокового припинення повноважень Кабінету Міністрів України?',	'["\u0412\u0456\u0434\u0441\u0442\u0430\u0432\u043a\u0430 \u041f\u0440\u0435\u043c\u2019\u0454\u0440-\u041c\u0456\u043d\u0456\u0441\u0442\u0440\u0430 \u0437\u0430 \u043f\u043e\u0434\u0430\u043d\u043e\u044e \u043d\u0438\u043c \u0437\u0430\u044f\u0432\u043e\u044e.", "\u041e\u0431\u0440\u0430\u043d\u043d\u044f \u043d\u043e\u0432\u043e\u0433\u043e \u043f\u0430\u0440\u043b\u0430\u043c\u0435\u043d\u0442\u0443.", "\u0412\u0456\u0434\u0441\u0442\u0430\u0432\u043a\u0430 \u041a\u0430\u0431\u0456\u043d\u0435\u0442\u0443 \u041c\u0456\u043d\u0456\u0441\u0442\u0440\u0456\u0432 \u0443 \u0437\u0432\u2019\u044f\u0437\u043a\u0443 \u0437 \u043f\u0440\u0438\u0439\u043d\u044f\u0442\u0442\u044f\u043c \u0412\u0435\u0440\u0445\u043e\u0432\u043d\u043e\u044e \u0420\u0430\u0434\u043e\u044e \u0423\u043a\u0440\u0430\u0457\u043d\u0438 \u0440\u0435\u0437\u043e\u043b\u044e\u0446\u0456\u0457 \u043d\u0435\u0434\u043e\u0432\u0456\u0440\u0438.", "\u0412\u0456\u0434\u0441\u0442\u0430\u0432\u043a\u0430 \u0431\u0456\u043b\u044c\u0448\u043e\u0441\u0442\u0456 \u0447\u043b\u0435\u043d\u0456\u0432 \u041a\u0430\u0431\u0456\u043d\u0435\u0442\u0443 \u041c\u0456\u043d\u0456\u0441\u0442\u0440\u0456\u0432 \u0423\u043a\u0440\u0430\u0457\u043d\u0438 \u0437\u0430 \u043f\u043e\u0434\u0430\u043d\u0438\u043c\u0438 \u043d\u0438\u043c\u0438 \u0437\u0430\u044f\u0432\u0430\u043c\u0438."]',	3,	'КОНСТИТУЦІЙНЕ ПРАВО'),
(15,	'З якою діяльністю може поєднувати перебування на своїй посаді сільський голова?',	'["\u0410\u0434\u0432\u043e\u043a\u0430\u0442\u0441\u044c\u043a\u0430 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0430 \u0432 \u0440\u0430\u043c\u043a\u0430\u0445 \u043d\u0430\u0434\u0430\u043d\u043d\u044f \u0431\u0435\u0437\u043e\u043f\u043b\u0430\u0442\u043d\u043e\u0457 \u043f\u0440\u0430\u0432\u043e\u0432\u043e\u0457 \u0434\u043e\u043f\u043e\u043c\u043e\u0433\u0438", "\u041a\u0435\u0440\u0456\u0432\u043d\u0438\u0446\u0442\u0432\u043e \u043f\u0440\u043e\u0444\u0441\u043f\u0456\u043b\u043a\u043e\u0432\u043e\u044e \u043e\u0440\u0433\u0430\u043d\u0456\u0437\u0430\u0446\u0456\u0454\u044e \u043d\u0430 \u0433\u0440\u043e\u043c\u0430\u0434\u0441\u044c\u043a\u0438\u0445 \u0437\u0430\u0441\u0430\u0434\u0430\u0445", "\u0427\u043b\u0435\u043d\u0441\u0442\u0432\u043e \u0443 \u0441\u0456\u043c\u0435\u0439\u043d\u043e\u043c\u0443 \u0444\u0435\u0440\u043c\u0435\u0440\u0441\u044c\u043a\u043e\u043c\u0443 \u0433\u043e\u0441\u043f\u043e\u0434\u0430\u0440\u0441\u0442\u0432\u0456", "\u041e\u043f\u043b\u0430\u0447\u0443\u0432\u0430\u043d\u0430 \u043c\u0435\u0434\u0438\u0447\u043d\u0430 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0430"]',	3,	'КОНСТИТУЦІЙНЕ ПРАВО'),
(16,	'Яке з перерахованих прав людини може бути тимчасово обмежене в умовах воєнного або надзвичайного стану?',	'["\u041f\u0440\u0430\u0432\u043e \u043e\u0441\u043e\u0431\u0438\u0441\u0442\u043e \u0437\u0432\u0435\u0440\u0442\u0430\u0442\u0438\u0441\u044f \u0434\u043e \u043e\u0440\u0433\u0430\u043d\u0456\u0432 \u0434\u0435\u0440\u0436\u0430\u0432\u043d\u043e\u0457 \u0432\u043b\u0430\u0434\u0438, \u043e\u0440\u0433\u0430\u043d\u0456\u0432 \u043c\u0456\u0441\u0446\u0435\u0432\u043e\u0433\u043e \u0441\u0430\u043c\u043e\u0432\u0440\u044f\u0434\u0443\u0432\u0430\u043d\u043d\u044f.", "\u041f\u0440\u0430\u0432\u043e \u0437\u0431\u0438\u0440\u0430\u0442\u0438\u0441\u044f \u043c\u0438\u0440\u043d\u043e, \u0431\u0435\u0437 \u0437\u0431\u0440\u043e\u0457 \u0456 \u043f\u0440\u043e\u0432\u043e\u0434\u0438\u0442\u0438 \u0437\u0431\u043e\u0440\u0438, \u043c\u0456\u0442\u0438\u043d\u0433\u0438, \u043f\u043e\u0445\u043e\u0434\u0438 \u0456 \u0434\u0435\u043c\u043e\u043d\u0441\u0442\u0440\u0430\u0446\u0456\u0457.", "\u041f\u0440\u0430\u0432\u043e \u043d\u0430 \u0441\u0432\u043e\u0431\u043e\u0434\u0443 \u0442\u0430 \u043e\u0441\u043e\u0431\u0438\u0441\u0442\u0443 \u043d\u0435\u0434\u043e\u0442\u043e\u0440\u043a\u0430\u043d\u043d\u0456\u0441\u0442\u044c.", "\u041f\u0440\u0430\u0432\u043e \u043d\u0430 \u043f\u043e\u0432\u0430\u0433\u0443 \u0434\u043e \u0433\u0456\u0434\u043d\u043e\u0441\u0442\u0456."]',	1,	'АДМІНІСТРАТИВНЕ ПРАВО'),
(17,	'У якому випадку Колегія Конституційного Суду України має постановити ухвалу про відмову у відкритті конституційного провадження за конституційною скаргою? До Конституційного Суду України звернувся громадянин Республіки',	'["\u041f\u043e\u043b\u044c\u0449\u0430 \u0437 \u043a\u043e\u043d\u0441\u0442\u0438\u0442\u0443\u0446\u0456\u0439\u043d\u043e\u044e \u0441\u043a\u0430\u0440\u0433\u043e\u044e \u0449\u043e\u0434\u043e \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u043d\u043e\u0441\u0442\u0456 \u041a\u043e\u043d\u0441\u0442\u0438\u0442\u0443\u0446\u0456\u0457 \u0423\u043a\u0440\u0430\u0457\u043d\u0438 \u043f\u043e\u043b\u043e\u0436\u0435\u043d\u044c \u0417\u0430\u043a\u043e\u043d\u0443 \u0423\u043a\u0440\u0430\u0457\u043d\u0438 \u00ab\u041f\u0440\u043e \u0441\u0443\u0434\u043e\u0432\u0438\u0439 \u0437\u0431\u0456\u0440\u00bb, \u0437\u0430\u0441\u0442\u043e\u0441\u043e\u0432\u0430\u043d\u043e\u0433\u043e \u0432 \u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e\u043c\u0443 \u0441\u0443\u0434\u043e\u0432\u043e\u043c\u0443 \u0440\u0456\u0448\u0435\u043d\u043d\u0456 \u0432 \u0439\u043e\u0433\u043e \u0441\u043f\u0440\u0430\u0432\u0456;", "\u0414\u043e \u041a\u043e\u043d\u0441\u0442\u0438\u0442\u0443\u0446\u0456\u0439\u043d\u043e\u0433\u043e \u0421\u0443\u0434\u0443 \u0423\u043a\u0440\u0430\u0457\u043d\u0438 \u0437\u0432\u0435\u0440\u043d\u0443\u043b\u0430\u0441\u044f \u0433\u0440\u043e\u043c\u0430\u0434\u044f\u043d\u043a\u0430 \u0423\u043a\u0440\u0430\u0457\u043d\u0438 \u0437 \u043a\u043e\u043d\u0441\u0442\u0438\u0442\u0443\u0446\u0456\u0439\u043d\u043e\u044e \u0441\u043a\u0430\u0440\u0433\u043e\u044e \u0449\u043e\u0434\u043e \u043e\u0444\u0456\u0446\u0456\u0439\u043d\u043e\u0433\u043e \u0442\u043b\u0443\u043c\u0430\u0447\u0435\u043d\u043d\u044f \u043f\u043e\u043b\u043e\u0436\u0435\u043d\u044c \u0447\u0430\u0441\u0442\u0438\u043d \u043f\u0435\u0440\u0448\u043e\u0457, \u0434\u0440\u0443\u0433\u043e\u0457, \u0434\u0435\u0432\u2019\u044f\u0442\u043e\u0457 \u0441\u0442\u0430\u0442\u0442\u0456 129 \u041a\u043e\u043d\u0441\u0442\u0438\u0442\u0443\u0446\u0456\u0457 \u0423\u043a\u0440\u0430\u0457\u043d\u0438; \u0414\u043e \u041a\u043e\u043d\u0441\u0442\u0438\u0442\u0443\u0446\u0456\u0439\u043d\u043e\u0433\u043e \u0421\u0443\u0434\u0443 \u0423\u043a\u0440\u0430\u0457\u043d\u0438 \u0437\u0432\u0435\u0440\u043d\u0443\u043b\u043e\u0441\u044f \u0422\u043e\u0432\u0430\u0440\u0438\u0441\u0442\u0432\u043e \u0437", "\u043e\u0431\u043c\u0435\u0436\u0435\u043d\u043e\u044e \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u0456\u0441\u0442\u044e \u0437 \u043a\u043e\u043d\u0441\u0442\u0438\u0442\u0443\u0446\u0456\u0439\u043d\u043e\u044e \u0441\u043a\u0430\u0440\u0433\u043e\u044e \u0449\u043e\u0434\u043e \u0432\u0438\u0437\u043d\u0430\u043d\u043d\u044f \u043d\u0435\u043a\u043e\u043d\u0441\u0442\u0438\u0442\u0443\u0446\u0456\u0439\u043d\u0438\u043c\u0438 \u043f\u043e\u043b\u043e\u0436\u0435\u043d\u044c \u0447\u0430\u0441\u0442\u0438\u043d\u0438 \u043f\u0435\u0440\u0448\u043e\u0457 \u0441\u0442\u0430\u0442\u0442\u0456 601 \u0426\u0438\u0432\u0456\u043b\u044c\u043d\u043e\u0433\u043e \u043a\u043e\u0434\u0435\u043a\u0441\u0443 \u0423\u043a\u0440\u0430\u0457\u043d\u0438, \u0437\u0430\u0441\u0442\u043e\u0441\u043e\u0432\u0430\u043d\u0438\u0445 \u0443 \u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e\u043c\u0443 \u0441\u0443\u0434\u043e\u0432\u043e\u043c\u0443 \u0440\u0456\u0448\u0435\u043d\u043d\u0456 \u0443 \u0439\u043e\u0433\u043e \u0441\u043f\u0440\u0430\u0432\u0456; \u0414\u043e \u041a\u043e\u043d\u0441\u0442\u0438\u0442\u0443\u0446\u0456\u0439\u043d\u043e\u0433\u043e \u0421\u0443\u0434\u0443 \u0423\u043a\u0440\u0430\u0457\u043d\u0438 \u0437\u0432\u0435\u0440\u043d\u0443\u043b\u0430\u0441\u044c \u043e\u0441\u043e\u0431\u0430 \u0431\u0435\u0437 \u0433\u0440\u043e\u043c\u0430\u0434\u044f\u043d\u0441\u0442\u0432\u0430", "\u0437 \u043a\u043e\u043d\u0441\u0442\u0438\u0442\u0443\u0446\u0456\u0439\u043d\u043e\u044e \u0441\u043a\u0430\u0440\u0433\u043e\u044e \u0449\u043e\u0434\u043e \u0432\u0438\u0437\u043d\u0430\u043d\u043d\u044f \u043d\u0435\u043a\u043e\u043d\u0441\u0442\u0438\u0442\u0443\u0446\u0456\u0439\u043d\u0438\u043c\u0438 \u043f\u043e\u043b\u043e\u0436\u0435\u043d\u044c \u0417\u0430\u043a\u043e\u043d\u0443 \u0423\u043a\u0440\u0430\u0457\u043d\u0438 \u00ab\u041f\u0440\u043e \u043e\u0440\u0435\u043d\u0434\u0443 \u0434\u0435\u0440\u0436\u0430\u0432\u043d\u043e\u0433\u043e \u0442\u0430 \u043a\u043e\u043c\u0443\u043d\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043c\u0430\u0439\u043d\u0430\u00bb, \u0437\u0430\u0441\u0442\u043e\u0441\u043e\u0432\u0430\u043d\u043e\u0433\u043e \u0432 \u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e\u043c\u0443 \u0441\u0443\u0434\u043e\u0432\u043e\u043c\u0443 \u0440\u0456\u0448\u0435\u043d\u043d\u0456 \u0432 \u0457\u0457 \u0441\u043f\u0440\u0430\u0432\u0456."]',	1,	'АДМІНІСТРАТИВНЕ ПРАВО'),
(18,	'Який принцип адміністративної процедури визначається через визначення обовʼязку адміністративного органу встановлювати, насамперед обставини, що мать значення для вирішення справи?',	'["\u0411\u0435\u0437\u0441\u0442\u043e\u0440\u043e\u043d\u043d\u043e\u0441\u0442\u0456.", "\u041e\u0444\u0456\u0446\u0456\u0439\u043d\u043e\u0441\u0442\u0456.", "\u041f\u0440\u043e\u043f\u043e\u0440\u0446\u0456\u0439\u043d\u043e\u0441\u0442\u044c.", "\u041e\u0431\u0491\u0440\u0443\u043d\u0442\u043e\u0432\u0430\u043d\u043e\u0441\u0442\u0456."]',	1,	'АДМІНІСТРАТИВНЕ ПРАВО'),
(19,	'27.09.2025 року до Приморського районного суду міста Одеси надійшов матеріал про притягнення до адміністративної відповідальності громадянина В. за ч.1 ст. 162 КУпАП (стаття 162. порушення правил про валютні операції). Згідно протоколу ГП 763922 від 11.08.2025 року громадянин В. вчинив адміністративне правопорушення 11.08.2025 року. Справа призначена судом до розгляду на 29.11.2025 року. Які дії повинен вчинити суд?',	'["\u0437\u0432\u0456\u043b\u044c\u043d\u0438\u0442\u0438 \u0433\u0440\u043e\u043c\u0430\u0434\u044f\u043d\u0438\u043d\u0430 \u0412. \u0432\u0456\u0434 \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0442\u0438\u0432\u043d\u043e\u0457 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0456 \u0456 \u043e\u0431\u043c\u0435\u0436\u0438\u0442\u0438\u0441\u044c \u0443\u0441\u043d\u0438\u043c \u0437\u0430\u0443\u0432\u0430\u0436\u0435\u043d\u043d\u044f\u043c \u043d\u0430\u043a\u043b\u0430\u0441\u0442\u0438 \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0442\u0438\u0432\u043d\u0435 \u0441\u0442\u044f\u0433\u043d\u0435\u043d\u043d\u044f, \u043d\u0438\u0436\u0447\u0435 \u0432\u0456\u0434 \u043d\u0430\u0439\u043d\u0438\u0436\u0447\u043e\u0457 \u043c\u0435\u0436\u0456,", "\u0432\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u043e\u0457 \u0432 \u0441\u0430\u043d\u043a\u0446\u0456\u0457 \u0441\u0442. 160 \u041a\u0423\u043f\u0410\u041f, \u0430\u0431\u043e \u043f\u0435\u0440\u0435\u0439\u0442\u0438 \u0434\u043e \u0456\u043d\u0448\u043e\u0433\u043e, \u0431\u0456\u043b\u044c\u0448 \u043c''\u044f\u043a\u043e\u0433\u043e \u0432\u0438\u0434\u0443 \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0442\u0438\u0432\u043d\u043e\u0433\u043e \u0441\u0442\u044f\u0433\u043d\u0435\u043d\u043d\u044f, \u043d\u0435 \u0437\u0430\u0437\u043d\u0430\u0447\u0435\u043d\u043e\u0433\u043e \u0432 \u0441\u0430\u043d\u043a\u0446\u0456\u0457 \u0441\u0442. 160 \u041a\u0423\u043f\u0410\u041f", "\u0432\u0438\u0437\u043d\u0430\u0442\u0438 \u0433\u0440\u043e\u043c\u0430\u0434\u044f\u043d\u0438\u043d\u0430 \u0412. \u0432\u0438\u043d\u043d\u0438\u043c \u0443 \u0432\u0447\u0438\u043d\u0435\u043d\u043d\u0456 \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0442\u0438\u0432\u043d\u043e\u0433\u043e \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u0442\u0430 \u0437\u0432\u0456\u043b\u044c\u043d\u0438\u0442\u0438 \u0439\u043e\u0433\u043e \u0432\u0456\u0434 \u043d\u0430\u043a\u043b\u0430\u0434\u0435\u043d\u043d\u044f \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0442\u0438\u0432\u043d\u043e\u0433\u043e \u0441\u0442\u044f\u0433\u043d\u0435\u043d\u043d\u044f", "\u0437\u0430\u043a\u0440\u0438\u0442\u0438 \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f \u0432 \u0441\u043f\u0440\u0430\u0432\u0456 \u043f\u0440\u043e \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0442\u0438\u0432\u043d\u0435 \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f"]',	3,	'АДМІНІСТРАТИВНЕ ПРАВО'),
(20,	'Що із зазначеного може бути віднесено до адміністративних1 актів?',	'["\u043f\u0440\u043e\u043c\u0456\u0436\u043d\u0456 \u0440\u0456\u0448\u0435\u043d\u043d\u044f \u0441\u0443\u0431''\u0454\u043a\u0442\u0430 \u043f\u0443\u0431\u043b\u0456\u0447\u043d\u043e\u0457 \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0446\u0456\u0457, \u0449\u043e \u043d\u0435 \u043c\u0430\u044e\u0442\u044c \u043a\u0456\u043d\u0446\u0435\u0432\u043e\u0433\u043e \u0440\u0435\u0433\u0443\u043b\u044e\u044e\u0447\u043e\u0433\u043e \u0432\u043f\u043b\u0438\u0432\u0443", "\u043e\u0444\u0456\u0446\u0456\u0439\u043d\u0456 \u0434\u043e\u043a\u0443\u043c\u0435\u043d\u0442\u0438, \u044f\u043a\u0456 \u0437\u0430\u0441\u0432\u0456\u0434\u0447\u0443\u044e\u0442\u044c \u043f\u0435\u0432\u043d\u0456 \u0444\u0430\u043a\u0442\u0438 \u0442\u0430 \u043d\u0435 \u0432\u0438\u043a\u043b\u0438\u043a\u0430\u044e\u0442\u044c \u044e\u0440\u0438\u0434\u0438\u0447\u043d\u0438\u0445 \u043d\u0430\u0441\u043b\u0456\u0434\u043a\u0456\u0432", "\u0430\u043a\u0442\u0438-\u0434\u0456\u0457 \u0441\u0443\u0431''\u0454\u043a\u0442\u0456\u0432 \u043f\u0443\u0431\u043b\u0456\u0447\u043d\u043e\u0457 \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0446\u0456\u0457, \u0449\u043e \u043d\u0435 \u0442\u044f\u0433\u043d\u0443\u0442\u044c \u043d\u0430\u0441\u0442\u0430\u043d\u043d\u044f \u044e\u0440\u0438\u0434\u0438\u0447\u043d\u0438\u0445 \u043d\u0430\u0441\u043b\u0456\u0434\u043a\u0456\u0432, \u043c\u0430\u044e\u0447\u0438 \u043b\u0438\u0448\u0435 \u0444\u0430\u043a\u0442\u0438\u0447\u043d\u0438\u0439 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442", "\u0430\u043a\u0442\u0438 \u0441\u0443\u0431''\u0454\u043a\u0442\u0456\u0432 \u043f\u0443\u0431\u043b\u0456\u0447\u043d\u043e\u0457 \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0446\u0456\u0457, \u0449\u043e \u043d\u0435 \u043c\u0430\u044e\u0442\u044c \u043f\u0438\u0441\u044c\u043c\u043e\u0432\u043e\u0457 \u0444\u043e\u0440\u043c\u0438"]',	3,	'АДМІНІСТРАТИВНЕ ПРАВО'),
(34,	'Яку обставину субʼєкт, що накладає адміністративне стягнення1 за вчинення адміністративного правопорушення, може НЕ визнати обтяжуючою?',	'["\u0412\u0447\u0438\u043d\u0435\u043d\u043d\u044f \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u0432 \u0443\u043c\u043e\u0432\u0430\u0445 \u0441\u0442\u0438\u0445\u0456\u0439\u043d\u043e\u0433\u043e \u043b\u0438\u0445\u0430.", "\u0412\u0442\u044f\u0433\u043d\u0435\u043d\u043d\u044f \u043d\u0435\u043f\u043e\u0432\u043d\u043e\u043b\u0456\u0442\u043d\u044c\u043e\u0433\u043e \u0432 \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f.", "\u0412\u0447\u0438\u043d\u0435\u043d\u043d\u044f \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u0433\u0440\u0443\u043f\u043e\u044e \u043e\u0441\u0456\u0431.", "\u0412\u0447\u0438\u043d\u0435\u043d\u043d\u044f \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u0432 \u0441\u0442\u0430\u043d\u0456 \u0441\u043f\u02bc\u044f\u043d\u0456\u043d\u043d\u044f."]',	3,	'ЦИВІЛЬНЕ ПРАВО'),
(21,	'Громадянин О. звернувся до адміністративного суду із позовом про визнання протиправним рішення суб''єкта владних повноважень та його скасування з порушенням строку звернення. До позовної заяви О. додав заяву про поновлення зазначеного строку та докази поважності причин його пропуску. Яку ухвалу має постановити суд, якщо визнає причини пропуску неповажними?',	'["\u041f\u0440\u043e \u0437\u0430\u043b\u0438\u0448\u0435\u043d\u043d\u044f \u043f\u043e\u0437\u043e\u0432\u043d\u043e\u0457 \u0437\u0430\u044f\u0432\u0438 \u0431\u0435\u0437 \u0440\u0443\u0445\u0443.", "\u041f\u0440\u043e \u043f\u043e\u0432\u0435\u0440\u043d\u0435\u043d\u043d\u044f \u043f\u043e\u0437\u043e\u0432\u043d\u043e\u0457 \u0437\u0430\u044f\u0432\u0438.", "\u041f\u0440\u043e \u0432\u0456\u0434\u043c\u043e\u0432\u0443 \u0443 \u0432\u0456\u0434\u043a\u0440\u0438\u0442\u0442\u0456 \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f \u0443 \u0441\u043f\u0440\u0430\u0432\u0456.", "\u041f\u0440\u043e \u0437\u0430\u043b\u0438\u0448\u0435\u043d\u043d\u044f \u043f\u043e\u0437\u043e\u0432\u043d\u043e\u0457 \u0437\u0430\u044f\u0432\u0438 \u0431\u0435\u0437 \u0440\u043e\u0437\u0433\u043b\u044f\u0434\u0443."]',	0,	'АДМІНІСТРАТИВНЕ ПРАВО'),
(22,	'Який вид джерел адміністративного права становлять акти, що не мають обов’язкової юридичної сили та характеризуються як «м’яке право»?',	'["\u043d\u0430\u0446\u0456\u043e\u043d\u0430\u043b\u044c\u043d\u0456 \u0434\u0436\u0435\u0440\u0435\u043b\u0430, \u0432\u043a\u043b\u044e\u0447\u0430\u044e\u0447\u0438 \u0430\u043a\u0442\u0438 \u0446\u0435\u043d\u0442\u0440\u0430\u043b\u044c\u043d\u0438\u0445 \u043e\u0440\u0433\u0430\u043d\u0456\u0432 \u0432\u0438\u043a\u043e\u043d\u0430\u0432\u0447\u043e\u0457 \u0432\u043b\u0430\u0434\u0438", "\u043c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u0456 \u0434\u0436\u0435\u0440\u0435\u043b\u0430, \u043d\u0430\u043f\u0440\u0438\u043a\u043b\u0430\u0434 \u0430\u043a\u0442\u0438 \u043c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u0438\u0445 \u043e\u0440\u0433\u0430\u043d\u0456\u0437\u0430\u0446\u0456\u0439", "\u0441\u0443\u0434\u043e\u0432\u0456 \u0434\u0436\u0435\u0440\u0435\u043b\u0430, \u0437\u043e\u043a\u0440\u0435\u043c\u0430 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0430 \u0404\u0432\u0440\u043e\u043f\u0435\u0439\u0441\u044c\u043a\u043e\u0433\u043e \u0441\u0443\u0434\u0443 \u0437 \u043f\u0440\u0430\u0432 \u043b\u044e\u0434\u0438\u043d\u0438", "\u043d\u0435\u0444\u043e\u0440\u043c\u0430\u043b\u0456\u0437\u043e\u0432\u0430\u043d\u0456 \u0434\u0436\u0435\u0440\u0435\u043b\u0430 \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0442\u0438\u0432\u043d\u043e\u0433\u043e \u043f\u0440\u0430\u0432\u0430, \u0437\u043e\u043a\u0440\u0435\u043c\u0430 \u043f\u0440\u0430\u0432\u043e\u0432\u0430 \u0434\u043e\u043a\u0442\u0440\u0438\u043d\u0430"]',	1,	'АДМІНІСТРАТИВНЕ ПРАВО'),
(23,	'А., будучи військовослужбовцем Державної прикордонної служби України, створив дослідницьку лабораторію і систематично здійснював наукові дослідження та експериментальні розробки, завдяки чому отримував постійний прибуток. ЧИ ДОПУСТИВ А. ПОРУШЕННЯ встановлених законом обмежень щодо сумісництва та суміщення з іншими видами діяльності?',	'["\u041d\u0456, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u043d\u0430\u0437\u0432\u0430\u043d\u0456 \u043e\u0431\u043c\u0435\u0436\u0435\u043d\u043d\u044f \u043d\u0435 \u043f\u043e\u0448\u0438\u0440\u044e\u044e\u0442\u044c\u0441\u044f \u043d\u0430 \u0432\u0456\u0439\u0441\u044c\u043a\u043e\u0432\u043e\u0441\u043b\u0443\u0436\u0431\u043e\u0432\u0446\u0456\u0432", "\u041d\u0456, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u043d\u0430\u0443\u043a\u043e\u0432\u0430 \u0434\u0456\u044f\u043b\u044c\u043d\u0456\u0441\u0442\u044c \u0454 \u0434\u043e\u0437\u0432\u043e\u043b\u0435\u043d\u0438\u043c \u0432\u0438\u0434\u043e\u043c \u0441\u0443\u043c\u0456\u0449\u0435\u043d\u043d\u044f \u0442\u0430 \u0441\u0443\u043c\u0456\u0441\u043d\u0438\u0446\u0442\u0432\u0430", "\u0422\u0430\u043a, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u043d\u0430\u0443\u043a\u043e\u0432\u0430 \u0434\u0456\u044f\u043b\u044c\u043d\u0456\u0441\u0442\u044c \u043d\u0435 \u0432\u0456\u0434\u043d\u0435\u0441\u0435\u043d\u0430 \u0434\u043e \u0434\u043e\u0437\u0432\u043e\u043b\u0435\u043d\u0438\u0445 \u0432\u0438\u0434\u0456\u0432 \u0441\u0443\u043c\u0456\u0449\u0435\u043d\u043d\u044f \u0442\u0430 \u0441\u0443\u043c\u0456\u0441\u043d\u0438\u0446\u0442\u0432\u0430", "\u0422\u0430\u043a, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0432 \u043e\u043f\u0438\u0441\u0430\u043d\u0456\u0439 \u0441\u0438\u0442\u0443\u0430\u0446\u0456\u0457 \u043d\u0430\u044f\u0432\u043d\u0456 \u043e\u0437\u043d\u0430\u043a\u0438 \u043f\u0456\u0434\u043f\u0440\u0438\u0454\u043c\u043d\u0438\u0446\u044c\u043a\u043e\u0457 \u0434\u0456\u044f\u043b\u044c\u043d\u043e\u0441\u0442\u0456"]',	3,	'АДМІНІСТРАТИВНЕ ПРАВО'),
(24,	'Підприємець подав заяву про виділення земельної ділянки під будівництво відпочинкового закладу до міської ради. Поряд із земельною ділянкою знаходиться земельна ділянка Реабілітаційного центру для диких тварин екологічного громадського обʼєднання. Працівники реабілітаційного центру вирішили не допустити майбутнього будівництва та виступили проти виділення земельної ділянки через побоювання шуму. Яким субʼєктом адміністративної процедури у даній ситуації с працівники реабілітаційного центру?',	'["\u0417\u0430\u044f\u0432\u043d\u0438\u043a\u0438.", "\u0417\u0430\u0446\u0456\u043a\u0430\u0432\u043b\u0435\u043d\u0456 \u043e\u0441\u043e\u0431\u0438.", "\u0410\u0434\u0440\u0435\u0441\u0430\u0442\u0438.", "\u0417\u0430\u0456\u043d\u0442\u0435\u0440\u0435\u0441\u043e\u0432\u0430\u043d\u0456 \u043e\u0441\u043e\u0431\u0438."]',	3,	'АДМІНІСТРАТИВНЕ ПРАВО'),
(25,	'Верховний Суд відкрив касаційне провадження в адміністративній справі за позовом ТОВ «Альфа» до органу публічної влади про визнання протиправним та скасування індивідуального акта; третя особа без самостійних вимог — ТОВ «Бета». Під час касаційного розгляду позивач подав заяву про відмову від позову та просив закрити провадження у справі.',	'["\u0423\u0445\u0432\u0430\u043b\u0443 \u043f\u0440\u043e \u0432\u0456\u0434\u043c\u043e\u0432\u0443 \u0443 \u043f\u0440\u0438\u0439\u043d\u044f\u0442\u0442\u0456 \u0432\u0456\u0434\u043c\u043e\u0432\u0438 \u0432\u0456\u0434 \u043f\u043e\u0437\u043e\u0432\u0443, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0432\u0456\u0434\u043c\u043e\u0432\u0430 \u0432\u0456\u0434 \u043f\u043e\u0437\u043e\u0432\u0443 \u043c\u043e\u0436\u043b\u0438\u0432\u0430 \u043b\u0438\u0448\u0435 \u0443 \u0441\u0443\u0434\u0456 \u043f\u0435\u0440\u0448\u043e\u0457 \u0456\u043d\u0441\u0442\u0430\u043d\u0446\u0456\u0457.", "\u0423\u0445\u0432\u0430\u043b\u0443 \u043f\u0440\u043e \u0432\u0456\u0434\u043c\u043e\u0432\u0443 \u0443 \u043f\u0440\u0438\u0439\u043d\u044f\u0442\u0442\u0456 \u0432\u0456\u0434\u043c\u043e\u0432\u0438 \u0432\u0456\u0434 \u043f\u043e\u0437\u043e\u0432\u0443, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0432\u0456\u0434\u043c\u043e\u0432\u0430 \u0432\u0456\u0434 \u043f\u043e\u0437\u043e\u0432\u0443 \u043d\u0435\u043c\u043e\u0436\u043b\u0438\u0432\u0430 \u0443 \u0441\u043f\u0440\u0430\u0432\u0430\u0445, \u0432 \u044f\u043a\u0438\u0445 \u0431\u0435\u0440\u0443\u0442\u044c \u0443\u0447\u0430\u0441\u0442\u044c \u0442\u0440\u0435\u0442\u0456 \u043e\u0441\u043e\u0431\u0438.", "\u0423\u0445\u0432\u0430\u043b\u0443 \u043f\u0440\u043e \u043f\u0440\u0438\u0439\u043d\u044f\u0442\u0442\u044f \u0432\u0456\u0434\u043c\u043e\u0432\u0438 \u0432\u0456\u0434 \u043f\u043e\u0437\u043e\u0432\u0443, \u0437\u0430\u043a\u0440\u0438\u0442\u0442\u044f \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f \u0443 \u0441\u043f\u0440\u0430\u0432\u0456 \u0442\u0430 \u0437\u0430\u043b\u0438\u0448\u0435\u043d\u043d\u044f \u0432 \u0441\u0438\u043b\u0456 \u0440\u0456\u0448\u0435\u043d\u044c \u0441\u0443\u0434\u0456\u0432 \u043f\u0435\u0440\u0448\u043e\u0457 \u0442\u0430 \u0434\u0440\u0443\u0433\u043e\u0457 \u0456\u043d\u0441\u0442\u0430\u043d\u0446\u0456\u0457.", "\u0423\u0445\u0432\u0430\u043b\u0443 \u043f\u0440\u043e \u043f\u0440\u0438\u0439\u043d\u044f\u0442\u0442\u044f \u0432\u0456\u0434\u043c\u043e\u0432\u0438 \u0432\u0456\u0434 \u043f\u043e\u0437\u043e\u0432\u0443, \u0432\u0438\u0437\u043d\u0430\u043d\u043d\u044f \u043d\u0435\u0447\u0438\u043d\u043d\u0438\u043c\u0438 \u0440\u0456\u0448\u0435\u043d\u044c \u0441\u0443\u0434\u0456\u0432 \u043f\u0435\u0440\u0448\u043e\u0457 \u0442\u0430 \u0434\u0440\u0443\u0433\u043e\u0457 \u0456\u043d\u0441\u0442\u0430\u043d\u0446\u0456\u0457, \u0437\u0430\u043a\u0440\u0438\u0442\u0442\u044f \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f \u0443 \u0441\u043f\u0440\u0430\u0432\u0456."]',	3,	'АДМІНІСТРАТИВНЕ ПРАВО'),
(26,	'На яких посадах і за яких умов можуть бути залишені посадові особи місцевого самоврядування після досягнення ними граничного віку перебування на службі в органах місцевого самоврядування?',	'["\u041d\u0430 \u043f\u043e\u0441\u0430\u0434\u0430\u0445 \u0440\u0430\u0434\u043d\u0438\u043a\u0456\u0432 \u0447\u0438 \u043a\u043e\u043d\u0441\u0443\u043b\u044c\u0442\u0430\u043d\u0442\u0456\u0432 (\u043f\u0430\u0442\u0440\u043e\u043d\u0430\u0442\u043d\u0430 \u0441\u043b\u0443\u0436\u0431\u0430), \u0437\u0430 \u0443\u043c\u043e\u0432\u0438, \u044f\u043a\u0449\u043e \u0442\u0430\u043a\u0456 \u043f\u043e\u0441\u0430\u0434\u0438 \u043f\u0435\u0440\u0435\u0434\u0431\u0430\u0447\u0435\u043d\u0456 \u0448\u0442\u0430\u0442\u043d\u0438\u043c \u0440\u043e\u0437\u043f\u0438\u0441\u043e\u043c, \u0430\u043b\u0435 \u043d\u0435 \u0431\u0456\u043b\u044c\u0448\u0435 \u043f\u02bc\u044f\u0442\u0438 \u0440\u043e\u043a\u0456\u0432.", "\u041d\u0430 \u043f\u043e\u0441\u0430\u0434\u0430\u0445 \u0440\u0430\u0434\u043d\u0438\u043a\u0456\u0432 \u0447\u0438 \u043a\u043e\u043d\u0441\u0443\u043b\u044c\u0442\u0430\u043d\u0442\u0456\u0432 (\u043f\u0430\u0442\u0440\u043e\u043d\u0430\u0442\u043d\u0430 \u0441\u043b\u0443\u0436\u0431\u0430) \u0437\u0430 \u0440\u0456\u0448\u0435\u043d\u043d\u044f\u043c \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u043d\u043e\u0433\u043e \u0433\u043e\u043b\u043e\u0432\u0438, \u0437\u0430 \u0443\u043c\u043e\u0432\u0438 \u0440\u043e\u0431\u043e\u0442\u0438 \u0432\u0438\u043a\u043b\u044e\u0447\u043d\u043e \u044f\u043a \u043f\u043e\u0437\u0430\u0448\u0442\u0430\u0442\u043d\u0456 \u043f\u0440\u0430\u0446\u0456\u0432\u043d\u0438\u043a\u0438.", "\u041d\u0430 \u0431\u0443\u0434\u044c-\u044f\u043a\u0438\u0445 \u043f\u043e\u0441\u0430\u0434\u0430\u0445, \u0437\u0430 \u0440\u0456\u0448\u0435\u043d\u043d\u044f\u043c \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u043d\u043e\u0433\u043e \u0433\u043e\u043b\u043e\u0432\u0438, \u0437\u0430 \u0443\u043c\u043e\u0432\u0438, \u044f\u043a\u0449\u043e \u0442\u0430\u043a \u043f\u043e\u0441\u0430\u0434\u0438 \u043f\u0435\u0440\u0435\u0434\u0431\u0430\u0447\u0435\u043d\u0456 \u0448\u0442\u0430\u0442\u043d\u0438\u043c \u0440\u043e\u0437\u043f\u0438\u0441\u043e\u043c.", "\u041d\u0430 \u043f\u043e\u0441\u0430\u0434\u0430\u0445 \u0440\u0430\u0434\u043d\u0438\u043a\u0456\u0432 \u0447\u0438 \u043a\u043e\u043d\u0441\u0443\u043b\u044c\u0442\u0430\u043d\u0442\u0456\u0432 (\u043f\u0430\u0442\u0440\u043e\u043d\u0430\u0442\u043d\u0430 \u0441\u043b\u0443\u0436\u0431\u0430), \u044f\u043a\u0449\u043e \u0442\u0430\u043a\u0456 \u043f\u043e\u0441\u0430\u0434\u0438 \u043f\u0435\u0440\u0435\u0434\u0431\u0430\u0447\u0435\u043d\u0456 \u0448\u0442\u0430\u0442\u043d\u0438\u043c \u0440\u043e\u0437\u043f\u0438\u0441\u043e\u043c, \u043d\u0430 \u0443\u043c\u043e\u0432\u0430\u0445 \u0441\u0442\u0440\u043e\u043a\u043e\u0432\u043e\u0433\u043e \u0442\u0440\u0443\u0434\u043e\u0432\u043e\u0433\u043e \u0434\u043e\u0433\u043e\u0432\u043e\u0440\u0443. \u041f\u0440\u043e \u0441\u043b\u0443\u0436\u0431\u0443 \u0432 \u043e\u0440\u0433\u0430\u043d\u0430\u0445 \u043c/c"]',	3,	'АДМІНІСТРАТИВНЕ ПРАВО'),
(27,	'Коли здійснюється обовʼязкова антикорупційна експертиза нормативно-правових актів, які підлягають державній реєстрації?',	'["\u041f\u0456\u0441\u043b\u044f \u043e\u0442\u0440\u0438\u043c\u0430\u043d\u043d\u044f \u0434\u043e\u0437\u0432\u043e\u043b\u0443 \u043d\u0430 \u043f\u0440\u043e\u0432\u0435\u0434\u0435\u043d\u043d\u044f \u0440\u0435\u0454\u0441\u0442\u0440\u0430\u0446\u0456\u0457 \u0430\u043a\u0442\u0456\u0432.", "\u041f\u0456\u0434 \u0447\u0430\u0441 \u0437\u0434\u0456\u0439\u0441\u043d\u0435\u043d\u043d\u044f \u0434\u0435\u0440\u0436\u0430\u0432\u043d\u043e\u0457 \u0440\u0435\u0454\u0441\u0442\u0440\u0430\u0446\u0456\u0457.", "\u0414\u043e \u043f\u0440\u043e\u0432\u0435\u0434\u0435\u043d\u043d\u044f \u0434\u0435\u0440\u0436\u0430\u0432\u043d\u043e\u0457 \u0440\u0435\u0454\u0441\u0442\u0440\u0430\u0446\u0456\u0457 \u0430\u043a\u0442\u0456\u0432.", "\u041f\u0456\u0441\u043b\u044f \u043f\u0440\u043e\u0432\u0435\u0434\u0435\u043d\u043d\u044f \u0434\u0435\u0440\u0436\u0430\u0432\u043d\u043e\u0457 \u0440\u0435\u0454\u0441\u0442\u0440\u0430\u0446\u0456 \u0430\u043a\u0442\u0456\u0432."]',	1,	'АДМІНІСТРАТИВНЕ ПРАВО'),
(28,	'Що із наведеного є основним завданням державної інспекції?',	'["\u0423\u043f\u0440\u0430\u0432\u043b\u0456\u043d\u043d\u044f \u043e\u0431\u2019\u0454\u043a\u0442\u0430\u043c\u0438 \u0434\u0435\u0440\u0436\u0430\u0432\u043d\u043e\u0457 \u0432\u043b\u0430\u0441\u043d\u043e\u0441\u0442\u0456.", "\u041d\u0430\u0434\u0430\u043d\u043d\u044f \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0442\u0438\u0432\u043d\u0438\u0445 \u043f\u043e\u0441\u043b\u0443\u0433.", "\u0417\u0434\u0456\u0439\u0441\u043d\u0435\u043d\u043d\u044f \u0434\u0435\u0440\u0436\u0430\u0432\u043d\u043e\u0433\u043e \u043d\u0430\u0433\u043b\u044f\u0434\u0443 (\u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044e).", "\u0424\u043e\u0440\u043c\u0443\u0432\u0430\u043d\u043d\u044f \u0442\u0430 \u0440\u0435\u0430\u043b\u0456\u0437\u0430\u0446\u0456\u044f \u0434\u0435\u0440\u0436\u0430\u0432\u043d\u043e\u0457 \u043f\u043e\u043b\u0456\u0442\u0438\u043a\u0438 \u0432 \u043f\u0435\u0432\u043d\u0456\u0439 \u0433\u0430\u043b\u0443\u0437\u0456."]',	2,	'АДМІНІСТРАТИВНЕ ПРАВО'),
(29,	'Правила якої підсудності було порушено позивачем, який в інтересах неповнолітньої доньки звернувся до районного суду як адміністративного суду з позовом, у якому просив визнати протиправною відмову відповідача у видачі доньці паспорта громадянина України у вигляді книжечки, зобовʼязати відповідача оформити та видати паспорт громадянина України у формі книжечки?',	'["\u0406\u043d\u0441\u0442\u0430\u043d\u0446\u0456\u0439\u043d\u043e\u0457", "\u0412\u0438\u043a\u043b\u044e\u0447\u043d\u043e\u0457.", "\u0422\u0435\u0440\u0438\u0442\u043e\u0440\u0456\u0430\u043b\u044c\u043d\u043e\u0457.", "\u041f\u0440\u0435\u0434\u043c\u0435\u0442\u043d\u043e\u0457."]',	3,	'АДМІНІСТРАТИВНЕ ПРАВО'),
(30,	'До ознак якого інструменту публічного адміністрування належить неодноразовість застосування?',	'["\u0406\u043d\u0434\u0438\u0432\u0456\u0434\u0443\u0430\u043b\u044c\u043d\u0438\u0439 \u0430\u043a\u0442.", "\u0410\u043a\u0442\u0438-\u0434\u0456\u0457.", "\u041d\u043e\u0440\u043c\u0430\u0442\u0438\u0432\u043d\u043e-\u043f\u0440\u0430\u0432\u043e\u0432\u0438\u0439 \u0430\u043a\u0442 (\u043d\u043e\u0440\u043c\u0430\u0442\u0438\u0432\u043d\u0438\u0439 \u0430\u043a\u0442).", "\u0410\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0442\u0438\u0432\u043d\u0438\u0439 \u0430\u043a\u0442."]',	2,	'АДМІНІСТРАТИВНЕ ПРАВО'),
(31,	'До предметної підсудності якого суду належить позов Приватного підприємства до інспектора з паркування міської ради про скасування постанови про накладення адміністративного стягнення за правопорушення у сфері забезпечення безпеки дорожнього руху?',	'["\u041e\u043a\u0440\u0443\u0436\u043d\u043e\u0433\u043e \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0442\u0438\u0432\u043d\u043e\u0433\u043e \u0441\u0443\u0434\u0443.", "\u0410\u043f\u0435\u043b\u044f\u0446\u0456\u0439\u043d\u043e\u0433\u043e \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0442\u0438\u0432\u043d\u043e\u0433\u043e \u0441\u0443\u0434\u0443.", "\u041c\u0456\u0441\u0446\u0435\u0432\u043e\u0433\u043e \u0437\u0430\u0433\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0441\u0443\u0434\u0443 \u044f\u043a \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0442\u0438\u0432\u043d\u043e\u0433\u043e.", "\u0410\u043f\u0435\u043b\u044f\u0446\u0456\u0439\u043d\u043e\u0433\u043e \u0437\u0430\u0433\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0441\u0443\u0434\u0443."]',	2,	'АДМІНІСТРАТИВНЕ ПРАВО'),
(32,	'З дотриманням якого принципу здійснюється державна служба відповідно до Закону України «Про державну службу»?',	'["\u0414\u0435\u043c\u043e\u043a\u0440\u0430\u0442\u0438\u0437\u043c\u0443.", "\u0413\u043b\u0430\u0441\u043d\u043e\u0441\u0442\u0456.", "\u0421\u0442\u0430\u0431\u0456\u043b\u044c\u043d\u043e\u0441\u0442\u0456.", "\u041f\u0443\u0431\u043b\u0456\u0447\u043d\u043e\u0441\u0442\u0456."]',	2,	'АДМІНІСТРАТИВНЕ ПРАВО'),
(33,	'Як відповідно до Закону України «Про звернення громадян» називається письмове звернення громадянина, у якому міститься повідомлення про порушення чинного законодавства, якщо воно було надіслане за допомогою електронної пошти?',	'["\u0415\u043b\u0435\u043a\u0442\u0440\u043e\u043d\u043d\u0430 \u043f\u0435\u0442\u0438\u0446\u0456\u044f.", "\u0421\u043a\u0430\u0440\u0433\u0430.", "\u0417\u0430\u043f\u0438\u0442 \u043d\u0430 \u0456\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0456\u044e.", "\u0417\u0430\u044f\u0432\u0430."]',	3,	'АДМІНІСТРАТИВНЕ ПРАВО'),
(35,	'Як називається застосування до договору про нерозголошення конфіденційної інформації, через відсутність спеціальних норм, що його регулюють, положень статей та 627 Цивільного кодексу України про свободу договору?',	'["\u0410\u043d\u0430\u043b\u043e\u0433\u0456\u044f \u0437\u0430\u043a\u043e\u043d\u0443.", "\u0410\u043d\u0430\u043b\u043e\u0433\u0456\u044f \u043f\u0440\u0430\u0432\u0430.", "\u041f\u0440\u0430\u0432\u043e\u0432\u0430 \u043a\u043e\u043b\u0456\u0437\u0456\u044f.", "\u042e\u0440\u0438\u0434\u0438\u0447\u043d\u0430 \u0444\u0456\u043a\u0446\u0456\u044f."]',	1,	'ЦИВІЛЬНЕ ПРАВО'),
(36,	'Хто належить до первинних субʼєктів суміжних прав?',	'["\u0421\u043f\u0430\u0434\u043a\u043e\u0454\u043c\u0435\u0446\u044c \u0432\u0438\u043a\u043e\u043d\u0430\u0432\u0446\u044f.", "\u041e\u0440\u0433\u0430\u043d\u0456\u0437\u0430\u0446\u0456\u044f \u043c\u043e\u0432\u043b\u0435\u043d\u043d\u044f.", "\u0420\u0435\u0434\u0430\u043a\u0446\u0456\u044f \u0434\u0440\u0443\u043a\u043e\u0432\u0430\u043d\u043e\u0433\u043e \u043c\u0435\u0434\u0456\u0430.", "\u041f\u0440\u043e\u0434\u044e\u0441\u0435\u0440 \u0430\u0443\u0434\u0456\u043e\u0432\u0456\u0437\u0443\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0442\u0432\u043e\u0440\u0443."]',	1,	'ЦИВІЛЬНЕ ПРАВО'),
(37,	'В якому випадку використання імені фізичної особи без її згоди є правомірним відповідно до Цивільного кодексу України?',	'["\u0406\u043c\u02bc\u044f\u043c \u0444\u0456\u0437\u0438\u0447\u043d\u043e\u0457 \u043e\u0441\u043e\u0431\u0438 \u043d\u0430\u0437\u0432\u0430\u043d\u043e \u043e\u0434\u043d\u043e\u0433\u043e \u0437 \u043f\u0435\u0440\u0441\u043e\u043d\u0430\u0436\u0456\u0432 \u0445\u0443\u0434\u043e\u0436\u043d\u044c\u043e\u0433\u043e \u0444\u0456\u043b\u044c\u043c\u0443, \u0441\u0446\u0435\u043d\u0430\u0440\u0456\u0439 \u044f\u043a\u043e\u0433\u043e \u0437\u0430\u0441\u043d\u043e\u0432\u0430\u043d\u043e \u043d\u0430 \u0440\u0435\u0430\u043b\u044c\u043d\u0438\u0445 \u043f\u043e\u0434\u0456\u044f\u0445", "\u0406\u043c\u02bc\u044f \u043d\u0430\u0443\u043a\u043e\u0432\u0446\u044f \u0437\u0430\u0437\u043d\u0430\u0447\u0435\u043d\u043e \u0443 \u043f\u0440\u043e\u0442\u043e\u043a\u043e\u043b\u0456 \u0442\u0430 \u043d\u0430 \u0432\u0456\u0434\u0435\u043e\u0437\u0430\u043f\u0438\u0441\u0456 \u0437\u0430\u0441\u0456\u0434\u0430\u043d\u043d\u044f \u0432\u0447\u0435\u043d\u043e\u0457 \u0440\u0430\u0434\u0438 \u0443\u043d\u0456\u0432\u0435\u0440\u0441\u0438\u0442\u0435\u0442\u0443, \u0432 \u044f\u043a\u043e\u043c\u0443 \u0432\u0456\u043d \u043f\u0440\u0430\u0446\u044e\u0454", "\u0406\u043c\u02bc\u044f \u0444\u0456\u0437\u0438\u0447\u043d\u043e\u0457 \u043e\u0441\u043e\u0431\u0438 \u043f\u043e\u0442\u0435\u0440\u043f\u0456\u043b\u043e\u0433\u043e \u0437\u0430\u0437\u043d\u0430\u0447\u0435\u043d\u043e \u0443 \u0440\u0435\u043f\u043e\u0440\u0442\u0430\u0436\u0456 \u0437 \u043c\u0456\u0441\u0446\u044f \u0437\u043b\u043e\u0447\u0438\u043d\u0443", "\u0406\u043c\u02bc\u044f \u0443\u0447\u0430\u0441\u043d\u0438\u043a\u0430 \u0446\u0438\u0432\u0456\u043b\u044c\u043d\u043e\u0433\u043e \u0441\u043f\u043e\u0440\u0443, \u044f\u043a\u0438\u0439 \u0441\u0442\u043e\u0441\u0443\u0454\u0442\u044c\u0441\u044f \u043e\u0441\u043e\u0431\u0438\u0441\u0442\u043e\u0433\u043e \u0436\u0438\u0442\u0442\u044f \u0441\u0442\u043e\u0440\u0456\u043d, \u0432\u0438\u0441\u0432\u0456\u0442\u043b\u0435\u043d\u043e \u0443 \u0434\u043e\u043f\u0438\u0441\u0456 \u0432 \u0441\u043e\u0446\u0456\u0430\u043b\u044c\u043d\u0456\u0439 \u043c\u0435\u0440\u0435\u0436\u0456"]',	1,	'ЦИВІЛЬНЕ ПРАВО'),
(38,	'За якої умови позовна давність НЕ поширюється на вимоги відшкодування шкоди?',	'["\u042f\u043a\u0449\u043e \u043f\u0440\u0435\u0434\u02bc\u044f\u0432\u043b\u0435\u043d\u043d\u044e \u043f\u043e\u0437\u043e\u0432\u0443 \u043f\u0435\u0440\u0435\u0448\u043a\u043e\u0434\u0436\u0430\u043b\u0430 \u043d\u0430\u0434\u0437\u0432\u0438\u0447\u0430\u0439\u043d\u0430 \u0430\u0431\u043e \u043d\u0435\u0432\u0456\u0434\u0432\u043e\u0440\u043e\u0442\u043d\u0430 \u0437\u0430 \u0434\u0430\u043d\u0438\u0445 \u0443\u043c\u043e\u0432 \u043f\u043e\u0434\u0456\u044f (\u043d\u0435\u043f\u0435\u0440\u0435\u0431\u043e\u0440\u043d\u0430 \u0441\u0438\u043b\u0430).", "\u042f\u043a\u0449\u043e \u0448\u043a\u043e\u0434\u0438 \u0437\u0430\u0432\u0434\u0430\u043d\u043e \u0441\u043c\u0435\u0440\u0442\u044e \u0444\u0456\u0437\u0438\u0447\u043d\u043e\u0457 \u043e\u0441\u043e\u0431\u0438 \u0432\u043d\u0430\u0441\u043b\u0456\u0434\u043e\u043a \u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u043f\u0440\u0430\u0432\u0438\u043b \u0434\u043e\u0440\u043e\u0436\u043d\u044c\u043e\u0433\u043e \u0440\u0443\u0445\u0443.", "\u042f\u043a\u0449\u043e \u0437\u043e\u0431\u043e\u0432\u02bc\u044f\u0437\u0430\u043d\u0430 \u043e\u0441\u043e\u0431\u0430 \u0432\u0447\u0438\u043d\u0438\u043b\u0430 \u0434\u0456\u0457, \u0449\u043e \u0441\u0432\u0456\u0434\u0447\u0430\u0442\u044c \u043f\u0440\u043e \u0432\u0438\u0437\u043d\u0430\u043d\u043d\u044f \u043d\u0435\u044e \u0441\u0432\u043e\u0433\u043e \u043e\u0431\u043e\u0432\u02bc\u044f\u0437\u043a\u0443.", "\u042f\u043a\u0449\u043e \u0441\u0443\u0434 \u0437\u0430\u043b\u0438\u0448\u0438\u0432 \u0431\u0435\u0437 \u0440\u043e\u0437\u0433\u043b\u044f\u0434\u0443 \u043f\u043e\u0437\u043e\u0432 \u043f\u0440\u043e \u0432\u0456\u0434\u0448\u043a\u043e\u0434\u0443\u0432\u0430\u043d\u043d\u044f \u0448\u043a\u043e\u0434\u0438, \u043f\u0440\u0435\u0434\u02bc\u044f\u0432\u043b\u0435\u043d\u0438\u0439 \u0443 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u043c\u0443 \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u0456."]',	1,	'ЦИВІЛЬНЕ ПРАВО'),
(39,	'У якому порядку відшкодовується шкода, завдана фізичній особі внаслідок її незаконного засудження?',	'["\u0432\u0456\u0434\u0448\u043a\u043e\u0434\u043e\u0432\u0443\u0454\u0442\u044c\u0441\u044f \u0434\u0435\u0440\u0436\u0430\u0432\u043e\u044e \u0443 \u043f\u043e\u0432\u043d\u043e\u043c\u0443 \u043e\u0431\u0441\u044f\u0437\u0456 \u043d\u0435\u0437\u0430\u043b\u0435\u0436\u043d\u043e \u0432\u0456\u0434 \u0432\u0438\u043d\u0438 \u043f\u043e\u0441\u0430\u0434\u043e\u0432\u0438\u0445 \u0456 \u0441\u043b\u0443\u0436\u0431\u043e\u0432\u0438\u0445 \u043e\u0441\u0456\u0431 \u043e\u0440\u0433\u0430\u043d\u0443 \u0434\u0456\u0437\u043d\u0430\u043d\u043d\u044f, \u043f\u043e\u043f\u0435\u0440\u0435\u0434\u043d\u044c\u043e\u0433\u043e (\u0434\u043e\u0441\u0443\u0434\u043e\u0432\u043e\u0433\u043e) \u0441\u043b\u0456\u0434\u0441\u0442\u0432\u0430, \u043f\u0440\u043e\u043a\u0443\u0440\u0430\u0442\u0443\u0440\u0438 \u0430\u0431\u043e \u0441\u0443\u0434\u0443; \u0432\u0456\u0434\u0448\u043a\u043e\u0434\u043e\u0432\u0443\u0454\u0442\u044c\u0441\u044f \u0434\u0435\u0440\u0436\u0430\u0432\u043e\u044e \u0443 \u0444\u0456\u043a\u0441\u043e\u0432\u0430\u043d\u043e\u043c\u0443 \u0440\u043e\u0437\u043c\u0456\u0440\u0456 (100 \u043c\u0456\u043d\u0456\u043c\u0430\u043b\u044c\u043d\u0438\u0445", "\u0437\u0430\u0440\u043e\u0431\u0456\u0442\u043d\u0438\u0445 \u043f\u043b\u0430\u0442) \u0437\u0430 \u0432\u0456\u0434\u0441\u0443\u0442\u043d\u043e\u0441\u0442\u0456 \u0432\u0438\u043d\u0438 \u043f\u043e\u0441\u0430\u0434\u043e\u0432\u0438\u0445 \u0456 \u0441\u043b\u0443\u0436\u0431\u043e\u0432\u0438\u0445 \u043e\u0441\u0456\u0431 \u043e\u0440\u0433\u0430\u043d\u0443 \u0434\u0456\u0437\u043d\u0430\u043d\u043d\u044f, \u043f\u043e\u043f\u0435\u0440\u0435\u0434\u043d\u044c\u043e\u0433\u043e (\u0434\u043e\u0441\u0443\u0434\u043e\u0432\u043e\u0433\u043e) \u0441\u043b\u0456\u0434\u0441\u0442\u0432\u0430, \u043f\u0440\u043e\u043a\u0443\u0440\u0430\u0442\u0443\u0440\u0438 \u0430\u0431\u043e \u0441\u0443\u0434\u0443;", "\u0432\u0456\u0434\u0448\u043a\u043e\u0434\u043e\u0432\u0443\u0454\u0442\u044c\u0441\u044f \u0434\u0435\u0440\u0436\u0430\u0432\u043e\u044e \u043f\u0440\u0438 \u043d\u0430\u044f\u0432\u043d\u043e\u0441\u0442\u0456 \u0432\u0438\u043d\u0438 \u043f\u043e\u0441\u0430\u0434\u043e\u0432\u0438\u0445 \u0456 \u0441\u043b\u0443\u0436\u0431\u043e\u0432\u0438\u0445 \u043e\u0441\u0456\u0431 \u043e\u0440\u0433\u0430\u043d\u0443 \u0434\u0456\u0437\u043d\u0430\u043d\u043d\u044f, \u043f\u043e\u043f\u0435\u0440\u0435\u0434\u043d\u044c\u043e\u0433\u043e (\u0434\u043e\u0441\u0443\u0434\u043e\u0432\u043e\u0433\u043e) \u0441\u043b\u0456\u0434\u0441\u0442\u0432\u0430, \u043f\u0440\u043e\u043a\u0443\u0440\u0430\u0442\u0443\u0440\u0438 \u0430\u0431\u043e \u0441\u0443\u0434\u0443.", "\u043d\u0435 \u0432\u0456\u0434\u0448\u043a\u043e\u0434\u043e\u0432\u0443\u0454\u0442\u044c\u0441\u044f;"]',	0,	'ЦИВІЛЬНЕ ПРАВО'),
(40,	'В якому випадку власник житлового будинку та земельної ділянки НЕ набуває права на компенсацію у зв’язку із зниженням цінності цих об’єктів?',	'["\u0437\u043d\u0438\u0436\u0435\u043d\u043d\u044f \u0440\u0456\u0432\u043d\u044f \u0448\u0443\u043c\u043e\u0432\u043e\u0457 \u0437\u0430\u0445\u0438\u0449\u0435\u043d\u043e\u0441\u0442\u0456 \u0442\u0435\u0440\u0438\u0442\u043e\u0440\u0456\u0457;", "\u043f\u043e\u0433\u0456\u0440\u0448\u0435\u043d\u043d\u044f \u043f\u0440\u0438\u0440\u043e\u0434\u043d\u0438\u0445 \u0432\u043b\u0430\u0441\u0442\u0438\u0432\u043e\u0441\u0442\u0435\u0439 \u0437\u0435\u043c\u043b\u0456;", "\u0437\u043d\u0438\u0436\u0435\u043d\u043d\u044f \u0440\u0456\u0432\u043d\u044f \u0435\u043a\u043e\u043b\u043e\u0433\u0456\u0447\u043d\u043e\u0457 \u0437\u0430\u0445\u0438\u0449\u0435\u043d\u043e\u0441\u0442\u0456 \u0442\u0435\u0440\u0438\u0442\u043e\u0440\u0456\u0457;", "\u0432\u0438\u0434\u0430\u043d\u043d\u044f \u043f\u0440\u0430\u0432\u043e\u0432\u043e\u0433\u043e \u0430\u043a\u0442\u0430 \u043e\u0440\u0433\u0430\u043d\u043e\u043c \u0434\u0435\u0440\u0436\u0430\u0432\u043d\u043e\u0457 \u0432\u043b\u0430\u0434\u0438."]',	3,	'ЦИВІЛЬНЕ ПРАВО'),
(41,	'А. і Б. є співвласниками в рівних частках чотирикімнатної квартири. А. зі своєю сім''єю займає три кімнати в цій квартирі. Б., керуючись тим, що його частка становить одну другу, звернувся до А. з вимогою звільнити одну з кімнат. А. відмовився задовольнити цю вимогу. Яким буде належний спосіб захисту прав А., НЕ пов''язаний із припиненням права спільної власності?',	'["\u0423\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u043d\u044f \u043f\u043e\u0440\u044f\u0434\u043a\u0443 \u0432\u043e\u043b\u043e\u0434\u0456\u043d\u043d\u044f \u0439 \u043a\u043e\u0440\u0438\u0441\u0442\u0443\u0432\u0430\u043d\u043d\u044f \u043a\u0432\u0430\u0440\u0442\u0438\u0440\u043e\u044e.", "\u0412\u0438\u0434\u0456\u043b \u0447\u0430\u0441\u0442\u043a\u0438 \u0432 \u043d\u0430\u0442\u0443\u0440\u0456.", "\u041f\u043e\u0434\u0456\u043b \u043a\u0432\u0430\u0440\u0442\u0438\u0440\u0438 \u0432 \u043d\u0430\u0442\u0443\u0440\u0456.", "\u0423\u0441\u0443\u043d\u0435\u043d\u043d\u044f \u043f\u0435\u0440\u0435\u0448\u043a\u043e\u0434 \u0443 \u0432\u043e\u043b\u043e\u0434\u0456\u043d\u043d\u0456 \u0439 \u043a\u043e\u0440\u0438\u0441\u0442\u0443\u0432\u0430\u043d\u043d\u0456 \u043a\u0432\u0430\u0440\u0442\u0438\u0440\u043e\u044e."]',	0,	'ЦИВІЛЬНЕ ПРАВО'),
(42,	'У день виселення із готелю А. виявив відсутність фотоапарату. Через те, що поспішав до аеропорту, А. вирішив повідомити про це адміністрацію готелю після повернення додому. Повернувшись додому, А. звернувся до готелю «Б» із проханням повернути йому фотоапарат, будучи упевненим, що останній раз користувався ним у готелі, однак адміністрацією готелю йому було відмовлено. Чи правомірні дії адміністрації готелю?',	'["\u0422\u0430\u043a, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438, \u0437\u0431\u0435\u0440\u0456\u0433\u0430\u043d\u043d\u044f \u0440\u0435\u0447\u0456 (\u0444\u043e\u0442\u043e\u0430\u043f\u0430\u0440\u0430\u0442\u0443) \u043d\u0435 \u0431\u0443\u043b\u043e \u043f\u0440\u043e\u043f\u0438\u0441\u0430\u043d\u043e \u0432 \u0443\u043c\u043e\u0432\u0430\u0445 \u0434\u043e\u0433\u043e\u0432\u043e\u0440\u0443 \u0437\u0431\u0435\u0440\u0456\u0433\u0430\u043d\u043d\u044f \u0440\u0435\u0447\u0435\u0439 \u0432 \u0433\u043e\u0442\u0435\u043b\u0456.", "\u041d\u0456, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0433\u043e\u0442\u0435\u043b\u044c \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u0454 \u0437\u0430 \u0441\u0445\u043e\u0440\u043e\u043d\u043d\u0456\u0441\u0442\u044c \u0440\u0435\u0447\u0435\u0439, \u043d\u0435 \u0437\u0430\u043b\u0435\u0436\u043d\u043e \u0432\u0456\u0434 \u0442\u043e\u0433\u043e, \u043f\u0440\u043e\u0442\u044f\u0433\u043e\u043c \u044f\u043a\u043e\u0433\u043e \u0441\u0442\u0440\u043e\u043a\u0443 \u043f\u0456\u0441\u043b\u044f \u0432\u0438\u0441\u0435\u043b\u0435\u043d\u043d\u044f \u0437 \u0433\u043e\u0442\u0435\u043b\u044e, \u043e\u0441\u043e\u0431\u0430 \u043f\u0440\u0435\u0434\u02bc\u044f\u0432\u0438\u043b\u0430 \u0441\u0432\u043e\u0457 \u0432\u0438\u043c\u043e\u0433\u0438 \u043f\u0440\u043e \u0432\u0442\u0440\u0430\u0447\u0435\u043d\u0443 \u0440\u0456\u0447.", "\u0422\u0430\u043a, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0434\u043e \u0437\u0430\u043a\u0456\u043d\u0447\u0435\u043d\u043d\u044f \u0441\u0442\u0440\u043e\u043a\u0443 \u043f\u0440\u043e\u0436\u0438\u0432\u0430\u043d\u043d\u044f \u043e\u0441\u043e\u0431\u0430 \u043d\u0435 \u043f\u0440\u0435\u0434\u02bc\u044f\u0432\u0438\u043b\u0430 \u0441\u0432\u043e\u0457 \u0432\u0438\u043c\u043e\u0433\u0438 \u0434\u043e \u0433\u043e\u0442\u0435\u043b\u044e, \u0442\u043e\u043c\u0443 \u0432\u0432\u0430\u0436\u0430\u0454\u0442\u044c\u0441\u044f, \u0449\u043e \u0440\u0456\u0447 \u043d\u0435 \u0431\u0443\u043b\u0430 \u0432\u0442\u0440\u0430\u0447\u0435\u043d\u0430.", "\u041d\u0456, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0433\u043e\u0442\u0435\u043b\u044c \u0443 \u0431\u0443\u0434\u044c-\u044f\u043a\u043e\u043c\u0443 \u0432\u0438\u043f\u0430\u0434\u043a\u0443 \u043d\u0435\u0441\u0435 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u0456\u0441\u0442\u044c \u0437\u0430 \u0432\u0442\u0440\u0430\u0442\u0443 \u0447\u0438 \u043f\u043e\u0448\u043a\u043e\u0434\u0436\u0435\u043d\u043d\u044f \u0440\u0435\u0447\u0456, \u044f\u043a\u0430 \u0437\u043d\u0430\u0445\u043e\u0434\u0438\u043b\u0430\u0441\u044f \u0432 \u0433\u043e\u0442\u0435\u043b\u0456."]',	2,	'ЦИВІЛЬНЕ ПРАВО'),
(80,	'Які з названих нижче заходів кримінально-правового характеру можуть застосовуватись щодо юридичних осіб лише як основні?',	'["\u0448\u0442\u0440\u0430\u0444 \u0442\u0430 \u043b\u0456\u043a\u0432\u0456\u0434\u0430\u0446\u0456\u044f", "\u0448\u0442\u0440\u0430\u0444 \u0442\u0430 \u043a\u043e\u043d\u0444\u0456\u0441\u043a\u0430\u0446\u0456\u044f", "\u043b\u0438\u0448\u0435 \u0448\u0442\u0440\u0430\u0444", "\u043b\u0438\u0448\u0435 \u043b\u0456\u043a\u0432\u0456\u0434\u0430\u0446\u0456\u044f"]',	0,	'КРИМІНАЛЬНЕ ПРАВО'),
(43,	'Громадянин Д. працює в Університеті на посаді доцента кафедри психології. У зв''язку з виконанням трудових обов''язків Д. підготував конспект лекцій із курсу «Основи психології» і передав його примірник керівництву Університету. Жодних договорів щодо прав на створювані у зв''язку з виконанням трудових обов''язків об''єкти між Д. і Університетом НЕ укладено. Кому належать права інтелектуальної власності на конспект лекцій?',	'["\u041e\u0441\u043e\u0431\u0438\u0441\u0442\u0456 \u043d\u0435\u043c\u0430\u0439\u043d\u043e\u0432\u0456 \u043f\u0440\u0430\u0432\u0430 \u043d\u0430\u043b\u0435\u0436\u0430\u0442\u044c \u0414., \u0430 \u043c\u0430\u0439\u043d\u043e\u0432\u0456 \u0414. \u0456 \u0423\u043d\u0456\u0432\u0435\u0440\u0441\u0438\u0442\u0435\u0442\u0443 \u0441\u043f\u0456\u043b\u044c\u043d\u043e.", "\u041e\u0441\u043e\u0431\u0438\u0441\u0442\u0456 \u043d\u0435\u043c\u0430\u0439\u043d\u043e\u0432\u0456 \u043f\u0440\u0430\u0432\u0430 \u043d\u0430\u043b\u0435\u0436\u0430\u0442\u044c \u0414., \u0430 \u043c\u0430\u0439\u043d\u043e\u0432\u0456 \u0423\u043d\u0456\u0432\u0435\u0440\u0441\u0438\u0442\u0435\u0442\u0443.", "\u041e\u0441\u043e\u0431\u0438\u0441\u0442\u0456 \u043d\u0435\u043c\u0430\u0439\u043d\u043e\u0432\u0456 \u0456 \u043c\u0430\u0439\u043d\u043e\u0432\u0456 \u043f\u0440\u0430\u0432\u0430 \u043d\u0430\u043b\u0435\u0436\u0430\u0442\u044c \u0414. \u044f\u043a \u0430\u0432\u0442\u043e\u0440\u0443.", "\u041e\u0441\u043e\u0431\u0438\u0441\u0442\u0456 \u043d\u0435\u043c\u0430\u0439\u043d\u043e\u0432\u0456 \u0456 \u043c\u0430\u0439\u043d\u043e\u0432\u0456 \u043f\u0440\u0430\u0432\u0430 \u043d\u0430\u043b\u0435\u0436\u0430\u0442\u044c \u0423\u043d\u0456\u0432\u0435\u0440\u0441\u0438\u0442\u0435\u0442\u0443 \u044f\u043a \u0440\u043e\u0431\u043e\u0442\u043e\u0434\u0430\u0432\u0446\u044e. \u041f\u0440\u043e \u041f\u0440\u043e \u0430\u0432\u0442\u043e\u0440\u0441\u044c\u043a\u0435 \u043f\u0440\u0430\u0432\u043e \u0456 \u0441\u0443\u043c\u0456\u0436\u043d\u0456 \u043f\u0440\u0430\u0432\u0430"]',	1,	'ЦИВІЛЬНЕ ПРАВО'),
(44,	'ОСОБА 1 уклала спадковий договір з ОСОБОЮ 2 щодо всього належного їй майна. Через пів року ОСОБА 1 склала заповіт на користь ОСОБИ 3, відповідно до якого після смерті ОСОБИ усе майно має перейти ОСОБІ 3.',	'["\u041e\u0421\u041e\u0411\u0410 2, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0437\u0430\u043f\u043e\u0432\u0456\u0442 \u0454 \u043d\u0456\u043a\u0447\u0435\u043c\u043d\u0438\u043c", "\u041e\u0421\u041e\u0411\u0410 3, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0437\u0430\u043f\u043e\u0432\u0456\u0442 \u0441\u043a\u0430\u0441\u043e\u0432\u0443\u0454 \u0441\u043f\u0430\u0434\u043a\u043e\u0432\u0438\u0439 \u0434\u043e\u0433\u043e\u0432\u0456\u0440", "\u041e\u0421\u041e\u0411\u0410 2, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0437\u0430\u043f\u043e\u0432\u0456\u0442 \u0454 \u0444\u0456\u043a\u0442\u0438\u0432\u043d\u0438\u043c", "\u041e\u0421\u041e\u0411\u0410 3, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0441\u043f\u0430\u0434\u043a\u043e\u0432\u0438\u0439 \u0434\u043e\u0433\u043e\u0432\u0456\u0440 \u0454 \u043d\u0435\u0434\u0456\u0439\u0441\u043d\u0438\u043c"]',	0,	'ЦИВІЛЬНЕ ПРАВО'),
(45,	'Наречені уклали письмовий договір дарування, за яким наречений взяв на себе обов’язок подарувати кольє з діамантами нареченій в день реєстрації шлюбу, однак до цього моменту підприємство нареченого збанкрутувало і понесені вже витрати на весілля не залишили в нього матеріальної можливості виконати обов’язок. Яке право виникає в дарувальника?',	'["\u0412\u0456\u0434\u0441\u0442\u0440\u043e\u0447\u0438\u0442\u0438 \u0432\u0438\u043a\u043e\u043d\u0430\u043d\u043d\u044f \u043e\u0431\u043e\u0432\u2019\u044f\u0437\u043a\u0443 \u0437\u0430 \u0434\u043e\u0433\u043e\u0432\u043e\u0440\u043e\u043c.", "\u0412\u0438\u043c\u0430\u0433\u0430\u0442\u0438 \u0432\u0438\u0437\u043d\u0430\u043d\u043d\u044f \u0434\u043e\u0433\u043e\u0432\u043e\u0440\u0443 \u043d\u0435\u0434\u0456\u0439\u0441\u043d\u0438\u043c \u0432 \u0441\u0443\u0434\u043e\u0432\u043e\u043c\u0443 \u043f\u043e\u0440\u044f\u0434\u043a\u0443.", "\u0412\u0456\u0434\u043c\u043e\u0432\u0438\u0442\u0438\u0441\u044c \u0432\u0456\u0434 \u0434\u043e\u0433\u043e\u0432\u043e\u0440\u0443.", "\u0412\u0438\u043c\u0430\u0433\u0430\u0442\u0438 \u0440\u043e\u0437\u0456\u0440\u0432\u0430\u043d\u043d\u044f \u0434\u043e\u0433\u043e\u0432\u043e\u0440\u0443 \u0432 \u0441\u0443\u0434\u043e\u0432\u043e\u043c\u0443 \u043f\u043e\u0440\u044f\u0434\u043a\u0443."]',	2,	'ЦИВІЛЬНЕ ПРАВО'),
(46,	'Що є предметом віндикаційного позову?',	'["\u0432\u0438\u043c\u043e\u0433\u0430 \u043f\u043e\u0437\u0438\u0432\u0430\u0447\u0430 \u0434\u043e \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u0447\u0430 \u043f\u0440\u043e \u043f\u043e\u0432\u0435\u0440\u043d\u0435\u043d\u043d\u044f \u043c\u0430\u0439\u043d\u0430 \u0437 \u0447\u0443\u0436\u043e\u0433\u043e \u043d\u0435\u0437\u0430\u043a\u043e\u043d\u043d\u043e\u0433\u043e \u0432\u043e\u043b\u043e\u0434\u0456\u043d\u043d\u044f", "\u0440\u0435\u0447\u0456, \u0432\u0438\u0437\u043d\u0430\u0447\u0435\u043d\u0456 \u0456\u043d\u0434\u0438\u0432\u0456\u0434\u0443\u0430\u043b\u044c\u043d\u0438\u043c\u0438 \u043e\u0437\u043d\u0430\u043a\u0430\u043c\u0438, \u044f\u043a\u0456 \u0456\u0441\u043d\u0443\u044e\u0442\u044c \u0432 \u043d\u0430\u0442\u0443\u0440\u0456 \u043d\u0430 \u043c\u043e\u043c\u0435\u043d\u0442 \u043f\u043e\u0434\u0430\u043d\u043d\u044f \u043f\u043e\u0437\u043e\u0432\u0443;", "\u0432\u0438\u043c\u043e\u0433\u0430 \u043f\u043e\u0437\u0438\u0432\u0430\u0447\u0430 \u043f\u0440\u043e \u0443\u0441\u0443\u043d\u0435\u043d\u043d\u044f \u0437 \u0431\u043e\u043a\u0443 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u0447\u0430 \u0431\u0443\u0434\u044c-\u044f\u043a\u0438\u0445 \u043f\u0435\u0440\u0435\u0448\u043a\u043e\u0434 \u0443 \u0437\u0434\u0456\u0439\u0441\u043d\u0435\u043d\u043d\u0456 \u043d\u0438\u043c \u043f\u0440\u0430\u0432\u0430 \u043a\u043e\u0440\u0438\u0441\u0442\u0443\u0432\u0430\u043d\u043d\u044f \u0442\u0430 \u0440\u043e\u0437\u043f\u043e\u0440\u044f\u0434\u0436\u0430\u043d\u043d\u044f \u0441\u0432\u043e\u0457\u043c \u043c\u0430\u0439\u043d\u043e\u043c;", "\u0443\u0441\u0443\u043d\u0435\u043d\u043d\u044f \u0442\u0440\u0438\u0432\u0430\u044e\u0447\u043e\u0433\u043e \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f."]',	0,	'ЦИВІЛЬНЕ ПРАВО'),
(47,	'Які правові наслідки недодержання вимоги закону про нотаріальне посвідчення одностороннього правочину, якщо буде встановлено його відповідність справжній волі особи?',	'["\u041f\u0440\u0430\u0432\u043e\u0447\u0438\u043d \u043c\u043e\u0436\u0435 \u0431\u0443\u0442\u0438 \u0432\u0438\u0437\u043d\u0430\u043d\u0438\u0439 \u0434\u0456\u0439\u0441\u043d\u0438\u043c \u0432 \u0441\u0443\u0434\u043e\u0432\u043e\u043c\u0443 \u043f\u043e\u0440\u044f\u0434\u043a\u0443, \u044f\u043a\u0449\u043e \u0449\u043e\u0434\u043e \u0446\u044c\u043e\u0433\u043e \u0432\u0456\u0434\u0441\u0443\u0442\u043d\u0435 \u0437\u0430\u043f\u0435\u0440\u0435\u0447\u0435\u043d\u043d\u044f \u0456\u043d\u0448\u043e\u0457 \u0441\u0442\u043e\u0440\u043e\u043d\u0438 \u043f\u0440\u0430\u0432\u043e\u0447\u0438\u043d\u0443.", "\u041f\u0440\u0430\u0432\u043e\u0447\u0438\u043d \u043c\u043e\u0436\u0435 \u0431\u0443\u0442\u0438 \u0432\u0438\u0437\u043d\u0430\u043d\u0438\u0439 \u0434\u0456\u0439\u0441\u043d\u0438\u043c \u0432 \u0441\u0443\u0434\u043e\u0432\u043e\u043c\u0443 \u043f\u043e\u0440\u044f\u0434\u043a\u0443, \u044f\u043a\u0449\u043e \u0431\u0443\u0434\u0435 \u0432\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u043e, \u0449\u043e \u043d\u043e\u0442\u0430\u0440\u0456\u0430\u043b\u044c\u043d\u043e\u043c\u0443 \u043f\u043e\u0441\u0432\u0456\u0434\u0447\u0435\u043d\u043d\u044e \u043f\u0435\u0440\u0435\u0448\u043a\u043e\u0434\u0436\u0430\u043b\u0430 \u043e\u0431\u0441\u0442\u0430\u0432\u0438\u043d\u0430, \u044f\u043a\u0430 \u043d\u0435 \u0437\u0430\u043b\u0435\u0436\u0430\u043b\u0430 \u0432\u0456\u0434 \u0432\u043e\u043b\u0456 \u043e\u0441\u043e\u0431\u0438.", "\u041f\u0440\u0430\u0432\u043e\u0447\u0438\u043d \u043c\u043e\u0436\u0435 \u0431\u0443\u0442\u0438 \u0432\u0438\u0437\u043d\u0430\u043d\u0438\u0439 \u0434\u0456\u0439\u0441\u043d\u0438\u043c \u0432 \u0441\u0443\u0434\u043e\u0432\u043e\u043c\u0443 \u043f\u043e\u0440\u044f\u0434\u043a\u0443, \u044f\u043a\u0449\u043e \u0431\u0443\u0434\u0435 \u0432\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u043e, \u0449\u043e \u043f\u0440\u0430\u0432\u043e\u0447\u0438\u043d \u043f\u043e\u0432\u043d\u0456\u0441\u0442\u044e \u0432\u0438\u043a\u043e\u043d\u0430\u043d\u0438\u0439 \u0441\u0442\u043e\u0440\u043e\u043d\u0430\u043c\u0438 \u043d\u0430 \u043c\u043e\u043c\u0435\u043d\u0442 \u0437\u0432\u0435\u0440\u043d\u0435\u043d\u043d\u044f \u0434\u043e \u0441\u0443\u0434\u0443.", "\u041f\u0440\u0430\u0432\u043e\u0447\u0438\u043d \u043c\u043e\u0436\u0435 \u0431\u0443\u0442\u0438 \u0432\u0438\u0437\u043d\u0430\u043d\u0438\u0439 \u0434\u0456\u0439\u0441\u043d\u0438\u043c \u0432 \u0441\u0443\u0434\u043e\u0432\u043e\u043c\u0443 \u043f\u043e\u0440\u044f\u0434\u043a\u0443, \u044f\u043a\u0449\u043e \u0431\u0443\u0434\u0435 \u0432\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u043e, \u0449\u043e \u043d\u043e\u0442\u0430\u0440\u0456\u0430\u043b\u044c\u043d\u043e\u043c\u0443 \u043f\u043e\u0441\u0432\u0456\u0434\u0447\u0435\u043d\u043d\u044e \u043d\u0456\u0447\u043e\u0433\u043e \u043d\u0435 \u043f\u0435\u0440\u0435\u0448\u043a\u043e\u0434\u0436\u0430\u0454."]',	1,	'ЦИВІЛЬНЕ ПРАВО'),
(54,	'Н. звернувся до суду із заявою про встановлення факту родинних відносин між ним та спадкодавцем з метою реалізації права на спадщину. Під час розгляду справи суд встановив виникнення спору про право на спадщину між заявником та заінтересованими особами. Якими мають бути дії суду?',	'["\u0421\u0443\u0434 \u043f\u0440\u043e\u0434\u043e\u0432\u0436\u0443\u0454 \u0440\u043e\u0437\u0433\u043b\u044f\u0434 \u0441\u043f\u0440\u0430\u0432\u0438 \u043f\u043e \u0441\u0443\u0442\u0456 \u0432 \u043c\u0435\u0436\u0430\u0445 \u0432\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u043d\u044f \u0444\u0430\u043a\u0442\u0443 \u0440\u043e\u0434\u0438\u043d\u043d\u0438\u0445 \u0432\u0456\u0434\u043d\u043e\u0441\u0438\u043d", "\u0421\u0443\u0434 \u0437\u0430\u043a\u0440\u0438\u0432\u0430\u0454 \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f \u0443 \u0441\u043f\u0440\u0430\u0432\u0456 \u0456 \u0440\u043e\u0437\u2019\u044f\u0441\u043d\u044e\u0454 \u0437\u0430\u0456\u043d\u0442\u0435\u0440\u0435\u0441\u043e\u0432\u0430\u043d\u0438\u043c \u043e\u0441\u043e\u0431\u0430\u043c, \u0449\u043e \u0432\u043e\u043d\u0438 \u043c\u0430\u044e\u0442\u044c \u043f\u0440\u0430\u0432\u043e \u043f\u043e\u0434\u0430\u0442\u0438 \u043f\u043e\u0437\u043e\u0432 \u043d\u0430 \u0437\u0430\u0433\u0430\u043b\u044c\u043d\u0438\u0445 \u043f\u0456\u0434\u0441\u0442\u0430\u0432\u0430\u0445", "\u0421\u0443\u0434 \u0437\u0430\u043b\u0438\u0448\u0430\u0454 \u043f\u0440\u0430\u0432\u043e \u043f\u043e\u0434\u0430\u0442\u0438 \u043f\u043e\u0437\u043e\u0432 \u043d\u0430 \u0437\u0430\u0433\u0430\u043b\u044c\u043d\u0438\u0445 \u043f\u0456\u0434\u0441\u0442\u0430\u0432\u0430\u0445", "\u0421\u0443\u0434 \u0437\u0430\u043b\u0438\u0448\u0430\u0454 \u0437\u0430\u044f\u0432\u0443 \u0431\u0435\u0437 \u0440\u043e\u0437\u0433\u043b\u044f\u0434\u0443 \u0456 \u0440\u043e\u0437\u2019\u044f\u0441\u043d\u044e\u0454 \u0437\u0430\u0456\u043d\u0442\u0435\u0440\u0435\u0441\u043e\u0432\u0430\u043d\u0438\u043c \u043e\u0441\u043e\u0431\u0430\u043c, \u0449\u043e \u0432\u043e\u043d\u0438 \u043c\u0430\u044e\u0442\u044c \u043f\u0440\u0430\u0432\u043e \u043f\u043e\u0434\u0430\u0442\u0438 \u043f\u043e\u0437\u043e\u0432 \u043d\u0430 \u0437\u0430\u0433\u0430\u043b\u044c\u043d\u0438\u0445 \u043f\u0456\u0434\u0441\u0442\u0430\u0432\u0430\u0445"]',	3,	'ЦИВІЛЬНЕ ПРОЦЕСУАЛЬНЕ ПРАВО'),
(48,	'Громадянин О. дізнався про відкриття спадщини через десять місяців після смерті свого батька. Вся спадщина перейшла до його брата, громадянина Д. З якою заявою може звернутися громадянин О. до суду для того, щоб здійснити своє право на спадкування?',	'["\u041f\u0440\u043e \u0432\u0438\u0437\u043d\u0430\u043d\u043d\u044f \u043f\u0440\u0430\u0432\u0430 \u043d\u0430 \u0441\u043f\u0430\u0434\u0449\u0438\u043d\u0443 \u0433\u0440\u043e\u043c\u0430\u0434\u044f\u043d\u0438\u043d\u0430 \u041e.", "\u041f\u0440\u043e \u0440\u043e\u0437\u043f\u043e\u0434\u0456\u043b \u0441\u043f\u0430\u0434\u0449\u0438\u043d\u0438 \u043c\u0456\u0436 \u0433\u0440\u043e\u043c\u0430\u0434\u044f\u043d\u0438\u043d\u043e\u043c \u041e. \u0442\u0430 \u0433\u0440\u043e\u043c\u0430\u0434\u044f\u043d\u0438\u043d\u043e\u043c \u0414.", "\u041f\u0440\u043e \u043f\u0440\u043e\u0434\u043e\u0432\u0436\u0435\u043d\u043d\u044f \u0441\u0442\u0440\u043e\u043a\u0443 \u0434\u043b\u044f \u043f\u0440\u0438\u0439\u043d\u044f\u0442\u0442\u044f \u0441\u043f\u0430\u0434\u0449\u0438\u043d\u0438 \u0433\u0440\u043e\u043c\u0430\u0434\u044f\u043d\u0438\u043d\u0443 \u041e.", "\u041f\u0440\u043e \u043d\u0430\u0434\u0430\u043d\u043d\u044f \u043f\u0440\u0430\u0432\u0430 \u043d\u0430 \u0441\u043f\u0430\u0434\u043a\u0443\u0432\u0430\u043d\u043d\u044f \u0433\u0440\u043e\u043c\u0430\u0434\u044f\u043d\u0438\u043d\u0443 \u041e."]',	2,	'ЦИВІЛЬНЕ ПРАВО'),
(49,	'Який із наведених спадкоємців вважається таким, що прийняв спадщину автоматично, без подання заяви про прийняття спадщини?',	'["\u041f\u043b\u0435\u043c\u0456\u043d\u043d\u0438\u043a \u0441\u043f\u0430\u0434\u043a\u043e\u0434\u0430\u0432\u0446\u044f, \u044f\u043a\u0438\u0439 \u043e\u0441\u0442\u0430\u043d\u043d\u0456\u043c \u0447\u0430\u0441\u043e\u043c \u043f\u043e\u0441\u0442\u0456\u0439\u043d\u043e \u0434\u043e\u0433\u043b\u044f\u0434\u0430\u0432 \u0437\u0430 \u0441\u043f\u0430\u0434\u043a\u043e\u0434\u0430\u0432\u0446\u0435\u043c, \u0444\u0430\u043a\u0442\u0438\u0447\u043d\u043e \u043f\u0440\u043e\u0436\u0438\u0432\u0430\u0432 \u0440\u0430\u0437\u043e\u043c \u0437 \u043d\u0438\u043c \u043d\u0430 \u0447\u0430\u0441 \u0432\u0456\u0434\u043a\u0440\u0438\u0442\u0442\u044f \u0441\u043f\u0430\u0434\u0449\u0438\u043d\u0438, \u0430\u043b\u0435 \u0431\u0443\u0432 \u0437\u0430\u0440\u0435\u0454\u0441\u0442\u0440\u043e\u0432\u0430\u043d\u0438\u0439 \u0432 \u0456\u043d\u0448\u043e\u043c\u0443 \u043c\u0456\u0441\u0446\u0456.", "\u0411\u0430\u0442\u044c\u043a\u043e \u0441\u043f\u0430\u0434\u043a\u043e\u0434\u0430\u0432\u0446\u044f, 85 \u0440\u043e\u043a\u0456\u0432, \u043e\u0441\u043e\u0431\u0430 \u0437 \u0456\u043d\u0432\u0430\u043b\u0456\u0434\u043d\u0456\u0441\u0442\u044e III \u0433\u0440\u0443\u043f\u0438.", "\u0414\u043e\u043d\u044c\u043a\u0430 \u0441\u043f\u0430\u0434\u043a\u043e\u0434\u0430\u0432\u0446\u044f, 16 \u0440\u043e\u043a\u0456\u0432, \u043d\u0435 \u043f\u0440\u043e\u0436\u0438\u0432\u0430\u043b\u0430 \u0437\u0456 \u0441\u043f\u0430\u0434\u043a\u043e\u0434\u0430\u0432\u0446\u0435\u043c \u043d\u0430 \u0447\u0430\u0441 \u0432\u0456\u0434\u043a\u0440\u0438\u0442\u0442\u044f \u0441\u043f\u0430\u0434\u0449\u0438\u043d\u0438 \u0442\u0430 \u0437\u0430\u0440\u0435\u0454\u0441\u0442\u0440\u043e\u0432\u0430\u043d\u0430 \u0432 \u0456\u043d\u0448\u043e\u043c\u0443 \u043c\u0456\u0441\u0446\u0456.", "\u0414\u0440\u0443\u0436\u0438\u043d\u0430 \u0441\u043f\u0430\u0434\u043a\u043e\u0434\u0430\u0432\u0446\u044f, \u043e\u0441\u043e\u0431\u0430 \u0437 \u0456\u043d\u0432\u0430\u043b\u0456\u0434\u043d\u0456\u0441\u0442\u044e \u0406 \u0433\u0440\u0443\u043f\u0438, \u043d\u0435 \u043f\u0440\u043e\u0436\u0438\u0432\u0430\u043b\u0430 \u0441\u043f\u0430\u0434\u043a\u043e\u0434\u0430\u0432\u0446\u0435\u043c \u0442\u0430 \u0431\u0443\u043b\u0430 \u0437\u0430\u0440\u0435\u0454\u0441\u0442\u0440\u043e\u0432\u0430\u043d\u0430 \u0432 \u0456\u043d\u0448\u043e\u043c\u0443 \u043c\u0456\u0441\u0446\u0456."]',	2,	'ЦИВІЛЬНЕ ПРАВО'),
(50,	'Дідусь 14-річного Олександра уклав договір банківського вкладу та вніс на його імʼя гроші. Вклад у повному розмірі було знято Олександрою через рік, а договір автоматично був припинений. Яке положення правильно характеризує наведену ситуацію, зважаючи на приписи норм Цивільного Кодексу України щодо обсягу дієздатності?',	'["\u0412\u0447\u0438\u043d\u0435\u043d\u043d\u044f \u0442\u0430\u043a\u0438\u0445 \u0434\u0456\u0439 \u043f\u043e\u0432\u043d\u0456\u0441\u0442\u044e \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u0454 \u043e\u0431\u0441\u044f\u0433\u0443 \u0446\u0438\u0432\u0456\u043b\u044c\u043d\u043e\u0457 \u0434\u0456\u0454\u0437\u0434\u0430\u0442\u043d\u043e\u0441\u0442\u0456 \u041e\u043b\u0435\u043a\u0441\u0430\u043d\u0434\u0440\u0430.", "\u0417\u043d\u044f\u0442\u0442\u044f \u0433\u0440\u043e\u0448\u043e\u0432\u0438\u0445 \u043a\u043e\u0448\u0442\u0456\u0432 \u0441\u0442\u0430\u043b\u043e \u043c\u043e\u0436\u043b\u0438\u0432\u0438\u043c \u043b\u0438\u0448\u0435 \u0442\u043e\u043c\u0443, \u0449\u043e \u043d\u0430 \u0446\u0435 \u0431\u0443\u0432 \u0434\u043e\u0437\u0432\u0456\u043b \u0434\u0456\u0434\u0443\u0441\u044f.", "\u0417\u043d\u044f\u0442\u0442\u044f \u0433\u0440\u043e\u0448\u0435\u0439 \u0441\u0442\u0430\u043b\u043e \u043c\u043e\u0436\u043b\u0438\u0432\u0438\u043c \u043b\u0438\u0448\u0435 \u0442\u043e\u043c\u0443, \u0449\u043e \u043d\u0430 \u0446\u0435 \u0431\u0443\u043b\u0430 \u0437\u0433\u043e\u0434\u0430 \u0431\u0430\u0442\u044c\u043a\u0456\u0432 \u041e\u043b\u0435\u043a\u0441\u0430\u043d\u0434\u0440\u0430.", "\u0417\u043d\u044f\u0442\u0442\u044f \u0433\u0440\u043e\u0448\u0435\u0439 \u0441\u0442\u0430\u043b\u043e \u043c\u043e\u0436\u043b\u0438\u0432\u0438\u043c \u0442\u043e\u043c\u0443, \u0449\u043e \u0431\u0443\u043b\u0430 \u0437\u0433\u043e\u0434\u0430 \u043e\u0440\u0433\u0430\u043d\u0443 \u043e\u043f\u0456\u043a\u0438 \u0442\u0430 \u043f\u0456\u043a\u043b\u0443\u0432\u0430\u043d\u043d\u044f \u0442\u0430 \u0431\u0430\u0442\u044c\u043a\u0456\u0432 \u041e\u043b\u0435\u043a\u0441\u0430\u043d\u0434\u0440\u0430."]',	3,	'ЦИВІЛЬНЕ ПРАВО'),
(51,	'Між магазином та постачальником було укладено договір купівлі-продажу з відстроченням платежу. Сторони домовилися про заміну договору купівлі-продажу на позикове зобов’язання. Чи допустимий варіант обрали сторони для припинення зобов’язання за таких обставин та чому?',	'["\u041d\u0456, \u0446\u0435 \u0437\u0430\u0441\u0442\u043e\u0441\u0443\u0432\u0430\u043d\u043d\u044f \u0446\u0435\u0441\u0456\u0457", "\u0422\u0430\u043a, \u0446\u0435 \u0432\u0438\u043a\u043e\u0440\u0438\u0441\u0442\u0430\u043d\u043d\u044f \u043d\u043e\u0432\u0430\u0446\u0456\u0457", "\u0422\u0430\u043a, \u043c\u0430\u0454 \u043c\u0456\u0441\u0446\u0435 \u043f\u0440\u043e\u0446\u0435\u0434\u0443\u0440\u0430 \u0441\u0430\u043d\u0430\u0446\u0456\u0457", "\u041d\u0456, \u043c\u0430\u0454 \u043c\u0456\u0441\u0446\u0435 \u0440\u0435\u0441\u0442\u0440\u0443\u043a\u0442\u0443\u0440\u0438\u0437\u0430\u0446\u0456\u044f \u0431\u043e\u0440\u0433\u0443"]',	1,	'ЦИВІЛЬНЕ ПРАВО'),
(52,	'Для цього різновиду юридичної особи нормами Цивільного кодексу України дозволяється перетворення лише у три організаційно-правові форми: акціонерне товариство, товариство з обмеженою відповідальністю, товариство з додатковою відповідальністю. Що це за юридична особа?',	'["\u0414\u0435\u0440\u0436\u0430\u0432\u043d\u0435 \u043f\u0456\u0434\u043f\u0440\u0438\u0454\u043c\u0441\u0442\u0432\u043e", "\u0414\u0435\u0440\u0436\u0430\u0432\u043d\u0430 \u0443\u0441\u0442\u0430\u043d\u043e\u0432\u0430", "\u041a\u043e\u043c\u0443\u043d\u0430\u043b\u044c\u043d\u0435 \u043f\u0456\u0434\u043f\u0440\u0438\u0454\u043c\u0441\u0442\u0432\u043e", "\u041a\u043e\u043c\u0443\u043d\u0430\u043b\u044c\u043d\u0430 \u0443\u0441\u0442\u0430\u043d\u043e\u0432\u0430 \u0417\u0430 2 \u0434\u043d\u0456 \u0434\u043e \u0441\u0443\u0434\u043e\u0432\u043e\u0433\u043e \u0437\u0430\u0441\u0456\u0434\u0430\u043d\u043d\u044f \u043f\u043e\u0437\u0438\u0432\u0430\u0447 \u043f\u043e\u0434\u0430\u0432 \u0434\u043e \u043c\u0456\u0441\u0446\u0435\u0432\u043e\u0433\u043e \u0441\u0443\u0434\u0443 \u0437\u0430\u044f\u0432\u0443 \u043f\u0440\u043e \u0432\u0456\u0434\u0432\u0456\u0434 \u0441\u0443\u0434\u0434\u0456. \u042f\u043a\u0438\u0439 \u0441\u043a\u043b\u0430\u0434 \u0441\u0443\u0434\u0443 \u043c\u0430\u0454 \u0440\u043e\u0437\u0433\u043b\u044f\u043d\u0443\u0442\u0438"]',	1,	'ЦИВІЛЬНЕ ПРОЦЕСУАЛЬНЕ ПРАВО'),
(53,	'За 2 дні до судового засідання позивач подав до місцевого суду заяву про відвід судді. Який склад суду має розглянути цю заяву?',	'["\u0421\u0443\u0434\u0434\u044f, \u044f\u043a\u0438\u0439 \u0440\u043e\u0437\u0433\u043b\u044f\u0434\u0430\u0454 \u0441\u043f\u0440\u0430\u0432\u0443", "\u0421\u0443\u0434\u0434\u044f, \u044f\u043a\u0438\u0439 \u043d\u0435 \u0432\u0445\u043e\u0434\u0438\u0442\u044c \u0434\u043e \u0441\u043a\u043b\u0430\u0434\u0443 \u0441\u0443\u0434\u0443, \u0449\u043e \u0440\u043e\u0437\u0433\u043b\u044f\u0434\u0430\u0454 \u0441\u043f\u0440\u0430\u0432\u0443", "\u0421\u0443\u0434 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u043d\u043e\u0457 \u0456\u043d\u0441\u0442\u0430\u043d\u0446\u0456\u0457, \u043d\u0430\u0439\u0431\u0456\u043b\u044c\u0448 \u0442\u0435\u0440\u0438\u0442\u043e\u0440\u0456\u0430\u043b\u044c\u043d\u043e \u043d\u0430\u0431\u043b\u0438\u0436\u0435\u043d\u0438\u0439 \u0434\u043e \u0446\u044c\u043e\u0433\u043e \u0441\u0443\u0434\u0443", "\u0421\u0443\u0434 \u0430\u043f\u0435\u043b\u044f\u0446\u0456\u0439\u043d\u043e\u0457 \u0456\u043d\u0441\u0442\u0430\u043d\u0446\u0456\u0457"]',	0,	'ЦИВІЛЬНЕ ПРОЦЕСУАЛЬНЕ ПРАВО'),
(55,	'В якому випадку у разі видачі судового наказу боржник може1 звернутися до суду першої інстанції?',	'["\u041f\u0440\u043e \u043f\u0435\u0440\u0435\u0440\u0430\u0445\u0443\u043d\u043e\u043a \u043d\u0430\u0440\u0430\u0445\u043e\u0432\u0430\u043d\u043e\u0457, \u0430\u043b\u0435 \u043d\u0435 \u0432\u0438\u043f\u043b\u0430\u0447\u0435\u043d\u043e\u0457 \u043f\u0440\u0430\u0446\u0456\u0432\u043d\u0438\u043a\u043e\u0432\u0456 \u0441\u0443\u043c\u0438 \u0437\u0430\u0440\u043e\u0431\u0456\u0442\u043d\u043e\u0457 \u043f\u043b\u0430\u0442\u0438", "\u041f\u0440\u043e \u0437\u043c\u0435\u043d\u0448\u0435\u043d\u043d\u044f \u0441\u0443\u043c\u0438 \u0437\u0430\u0431\u043e\u0440\u0433\u043e\u0432\u0430\u043d\u043e\u0441\u0442\u0456 \u0437\u0430 \u043e\u043f\u043b\u0430\u0442\u0443 \u0435\u043b\u0435\u043a\u0442\u0440\u043e\u043d\u043d\u0438\u0445 \u043a\u043e\u043c\u0443\u043d\u0456\u043a\u0430\u0446\u0456\u0439\u043d\u0438\u0445 \u043f\u043e\u0441\u043b\u0443\u0433", "\u041f\u0440\u043e \u0437\u043c\u0435\u043d\u0448\u0435\u043d\u043d\u044f \u0441\u0443\u043c\u0438 \u0440\u043e\u0437\u043c\u0456\u0440\u0443 \u0430\u043b\u0456\u043c\u0435\u043d\u0442\u0456\u0432", "\u041f\u0440\u043e \u0437\u0431\u0456\u043b\u044c\u0448\u0435\u043d\u043d\u044f \u0441\u0443\u043c\u0438 \u0432\u0430\u0440\u0442\u043e\u0441\u0442\u0456 \u0442\u043e\u0432\u0430\u0440\u0443 \u043d\u0435\u043d\u0430\u043b\u0435\u0436\u043d\u043e\u0457 \u044f\u043a\u043e\u0441\u0442\u0456, \u0449\u043e \u043f\u0456\u0434\u043b\u044f\u0433\u0430\u0454 \u043f\u043e\u0432\u0435\u0440\u043d\u0435\u043d\u043d\u044e"]',	2,	'ЦИВІЛЬНЕ ПРОЦЕСУАЛЬНЕ ПРАВО'),
(56,	'Які процесуально-правові наслідки може мати НЕвнесення позивачем у визначений судом строк коштів для забезпечення судових витрат відповідача?',	'["\u0437\u0430\u043a\u0440\u0438\u0442\u0442\u044f \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f \u0443 \u0441\u043f\u0440\u0430\u0432\u0456;", "\u0437\u0430\u043b\u0438\u0448\u0435\u043d\u043d\u044f \u043f\u043e\u0437\u043e\u0432\u0443 \u0431\u0435\u0437 \u0440\u043e\u0437\u0433\u043b\u044f\u0434\u0443;", "\u0432\u0456\u0434\u043c\u043e\u0432\u0443 \u0443 \u0432\u0456\u0434\u0448\u043a\u043e\u0434\u0443\u0432\u0430\u043d\u043d\u0456 \u0441\u0443\u0434\u043e\u0432\u0438\u0445 \u0432\u0438\u0442\u0440\u0430\u0442 \u043f\u043e\u0437\u0438\u0432\u0430\u0447\u0430 \u043f\u043e\u0432\u043d\u0456\u0441\u0442\u044e;", "\u0432\u0456\u0434\u043c\u043e\u0432\u0443 \u0432 \u0437\u0430\u0434\u043e\u0432\u043e\u043b\u0435\u043d\u043d\u0456 \u043f\u043e\u0437\u043e\u0432\u043d\u0438\u0445 \u0432\u0438\u043c\u043e\u0433."]',	1,	'ЦИВІЛЬНЕ ПРОЦЕСУАЛЬНЕ ПРАВО'),
(57,	'Яка процесуальна дія спричиняє неможливість повторного звернення до суду з тотожним позовом?',	'["\u0437\u0430\u043a\u0440\u0438\u0442\u0442\u044f \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f \u0443 \u0441\u043f\u0440\u0430\u0432\u0456;", "\u0437\u0430\u043b\u0438\u0448\u0435\u043d\u043d\u044f \u043f\u043e\u0437\u043e\u0432\u0443 \u0431\u0435\u0437 \u0440\u043e\u0437\u0433\u043b\u044f\u0434\u0443;", "\u043f\u043e\u0432\u0435\u0440\u043d\u0435\u043d\u043d\u044f \u043f\u043e\u0437\u043e\u0432\u043d\u043e\u0457 \u0437\u0430\u044f\u0432\u0438;", "\u0436\u043e\u0434\u043d\u0430 \u043f\u0440\u043e\u0446\u0435\u0441\u0443\u0430\u043b\u044c\u043d\u0430 \u0434\u0456\u044f \u043d\u0435 \u043c\u043e\u0436\u0435 \u0431\u0443\u0442\u0438 \u043f\u0435\u0440\u0435\u0448\u043a\u043e\u0434\u043e\u044e \u0434\u043b\u044f \u043f\u043e\u0432\u0442\u043e\u0440\u043d\u043e\u0433\u043e \u0437\u0432\u0435\u0440\u043d\u0435\u043d\u043d\u044f \u0434\u043e \u0441\u0443\u0434\u0443 \u0437 \u0442\u043e\u0442\u043e\u0436\u043d\u0438\u043c \u043f\u043e\u0437\u043e\u0432\u043e\u043c."]',	0,	'ЦИВІЛЬНЕ ПРОЦЕСУАЛЬНЕ ПРАВО'),
(58,	'У справі про відшкодування майнової та моральної шкоди за наслідками розгляду справи у загальному позовному провадженні суд ухвалив рішення про часткове задоволення позовних вимог. В судовому засіданні було проголошено лише вступну та резолютивну частину, відповідно до якої суд задовольнив позовну вимогу про відшкодування майнової шкоди, а вимогу про відшкодування моральної шкоди залишив без розгляду. Суддя повідомив, що з повним текстом рішення сторони можуть ознайомитись через десять днів. Чи припустився суд помилки?',	'["\u0442\u0430\u043a, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u043f\u043e\u0432\u043d\u0438\u0439 \u0442\u0435\u043a\u0441\u0442 \u0440\u0456\u0448\u0435\u043d\u043d\u044f \u043c\u0430\u0454 \u0431\u0443\u0442\u0438 \u0441\u043a\u043b\u0430\u0434\u0435\u043d\u0438\u0439 \u043d\u0435 \u043f\u0456\u0437\u043d\u0456\u0448\u0435 \u043d\u0456\u0436 \u0437\u0430 \u043f\u2019\u044f\u0442\u044c \u0434\u043d\u0456\u0432;", "\u0442\u0430\u043a, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0440\u0456\u0448\u0435\u043d\u043d\u044f \u043f\u0440\u0438\u0437\u043d\u0430\u0447\u0435\u043d\u0435 \u0434\u043b\u044f \u0432\u0438\u0440\u0456\u0448\u0435\u043d\u043d\u044f \u0441\u043f\u0440\u0430\u0432\u0438 \u043f\u043e \u0441\u0443\u0442\u0456 \u0442\u0430 \u043d\u0438\u043c \u043d\u0435 \u043c\u043e\u0436\u0435 \u0431\u0443\u0442\u0438 \u0432\u0438\u0440\u0456\u0448\u0435\u043d\u0435 \u043f\u0438\u0442\u0430\u043d\u043d\u044f \u043f\u0440\u043e \u0437\u0430\u043b\u0438\u0448\u0435\u043d\u043d\u044f \u043f\u043e\u0437\u043e\u0432\u043d\u043e\u0457 \u0432\u0438\u043c\u043e\u0433\u0438 \u0431\u0435\u0437 \u0440\u043e\u0437\u0433\u043b\u044f\u0434\u0443;", "\u0442\u0430\u043a, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0440\u0456\u0448\u0435\u043d\u043d\u044f \u043f\u0440\u043e \u0432\u0456\u0434\u0448\u043a\u043e\u0434\u0443\u0432\u0430\u043d\u043d\u044f \u043c\u0430\u0439\u043d\u043e\u0432\u043e\u0457 \u0442\u0430 \u043c\u043e\u0440\u0430\u043b\u044c\u043d\u043e\u0457 \u0448\u043a\u043e\u0434\u0438 \u043f\u0456\u0434\u043b\u044f\u0433\u0430\u044e\u0442\u044c \u043d\u0435\u0433\u0430\u0439\u043d\u043e\u043c\u0443 \u0432\u0438\u043a\u043e\u043d\u0430\u043d\u043d\u044e, \u0430 \u0442\u043e\u043c\u0443 \u0441\u0443\u0434 \u043e\u0434\u0440\u0430\u0437\u0443 \u0437\u043e\u0431\u043e\u0432\u2019\u044f\u0437\u0430\u043d\u0438\u0439 \u0431\u0443\u0432 \u043f\u0440\u043e\u0433\u043e\u043b\u043e\u0441\u0438\u0442\u0438 \u043f\u043e\u0432\u043d\u0438\u0439 \u0442\u0435\u043a\u0441\u0442 \u0440\u0456\u0448\u0435\u043d\u043d\u044f;", "\u043d\u0456, \u0441\u0443\u0434 \u043d\u0435 \u043f\u0440\u0438\u043f\u0443\u0441\u0442\u0438\u0432\u0441\u044f \u0436\u043e\u0434\u043d\u043e\u0457 \u043f\u043e\u043c\u0438\u043b\u043a\u0438."]',	1,	'ЦИВІЛЬНЕ ПРОЦЕСУАЛЬНЕ ПРАВО'),
(59,	'У якому з наведених випадків суддя відмовляє у видачі судового наказу?',	'["\u0423 \u0437\u0430\u044f\u0432\u0456 \u043f\u0440\u043e \u0432\u0438\u0434\u0430\u0447\u0443 \u0441\u0443\u0434\u043e\u0432\u043e\u0433\u043e \u043d\u0430\u043a\u0430\u0437\u0443 \u043c\u0456\u0441\u0442\u044f\u0442\u044c\u0441\u044f \u0432\u0438\u043c\u043e\u0433\u0438, \u0447\u0430\u0441\u0442\u0438\u043d\u0430 \u0437 \u044f\u043a\u0438\u0445 \u043d\u0435 \u043f\u0456\u0434\u043b\u044f\u0433\u0430\u0454 \u0440\u043e\u0437\u0433\u043b\u044f\u0434\u0443 \u0432 \u043f\u043e\u0440\u044f\u0434\u043a\u0443 \u043d\u0430\u043a\u0430\u0437\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f, \u0456 \u0446\u0456 \u0432\u0438\u043c\u043e\u0433\u0438 \u043d\u0435 \u0454 \u0432\u0437\u0430\u0454\u043c\u043e\u043f\u043e\u0432''\u044f\u0437\u0430\u043d\u0456.", "\u0417 \u043c\u043e\u043c\u0435\u043d\u0442\u0443 \u0432\u0438\u043d\u0438\u043a\u043d\u0435\u043d\u043d\u044f \u043f\u0440\u0430\u0432\u0430 \u0432\u0438\u043c\u043e\u0433\u0438 \u043f\u0440\u043e\u0439\u0448\u043e\u0432 \u0441\u0442\u0440\u043e\u043a, \u044f\u043a\u0438\u0439 \u043f\u0435\u0440\u0435\u0432\u0438\u0449\u0443\u0454 \u043f\u043e\u0437\u043e\u0432\u043d\u0443 \u0434\u0430\u0432\u043d\u0456\u0441\u0442\u044c, \u0443\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u0443 \u0437\u0430\u043a\u043e\u043d\u043e\u043c \u0434\u043b\u044f \u0442\u0430\u043a\u043e\u0457 \u0432\u0438\u043c\u043e\u0433\u0438.", "\u0417\u0430\u044f\u0432\u043d\u0438\u043a \u0432\u0456\u0434\u043a\u043b\u0438\u043a\u0430\u0432 \u0437\u0430\u044f\u0432\u0443 \u043f\u0440\u043e \u0432\u0438\u0434\u0430\u0447\u0443 \u0441\u0443\u0434\u043e\u0432\u043e\u0433\u043e \u043d\u0430\u043a\u0430\u0437\u0443 \u0434\u043e \u0457\u0457 \u0440\u043e\u0437\u0433\u043b\u044f\u0434\u0443 \u0441\u0443\u0434\u043e\u043c.", "\u0421\u0443\u0434\u043e\u043c \u0440\u0430\u043d\u0456\u0448\u0435 \u0432\u0456\u0434\u043c\u043e\u0432\u043b\u0435\u043d\u043e \u0443 \u0432\u0438\u0434\u0430\u0447\u0456 \u0441\u0443\u0434\u043e\u0432\u043e\u0433\u043e \u043d\u0430\u043a\u0430\u0437\u0443 \u0437 \u043f\u0456\u0434\u0441\u0442\u0430\u0432\u0438 \u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u0432\u0438\u043c\u043e\u0433 \u0449\u043e\u0434\u043e \u0444\u043e\u0440\u043c\u0438 \u0439 \u0437\u043c\u0456\u0441\u0442\u0443 \u0437\u0430\u044f\u0432\u0438 \u043f\u0440\u043e \u0432\u0438\u0434\u0430\u0447\u0443 \u0441\u0443\u0434\u043e\u0432\u043e\u0433\u043e \u043d\u0430\u043a\u0430\u0437\u0443."]',	1,	'ЦИВІЛЬНЕ ПРОЦЕСУАЛЬНЕ ПРАВО'),
(60,	'Яка з наведених категорій справ НЕ може бути розглянута в порядку спрощеного позовного провадження?',	'["\u0441\u043f\u0440\u0430\u0432\u0438, \u0449\u043e \u0432\u0438\u043d\u0438\u043a\u0430\u044e\u0442\u044c \u0437 \u0442\u0440\u0443\u0434\u043e\u0432\u0438\u0445 \u0432\u0456\u0434\u043d\u043e\u0441\u0438\u043d", "\u0441\u043f\u0440\u0430\u0432\u0438 \u0449\u043e\u0434\u043e \u0441\u043f\u0430\u0434\u043a\u0443\u0432\u0430\u043d\u043d\u044f", "\u0441\u043f\u0440\u0430\u0432\u0438 \u0449\u043e\u0434\u043e \u0432\u0438\u0437\u043d\u0430\u043d\u043d\u044f \u043f\u0440\u0430\u0432\u0430 \u0432\u043b\u0430\u0441\u043d\u043e\u0441\u0442\u0456 \u043d\u0430 \u0437\u0435\u043c\u0435\u043b\u044c\u043d\u0443 \u0434\u0456\u043b\u044f\u043d\u043a\u0443", "\u0441\u043f\u0440\u0430\u0432\u0438 \u043f\u0440\u043e \u0441\u0442\u044f\u0433\u043d\u0435\u043d\u043d\u044f \u0430\u043b\u0456\u043c\u0435\u043d\u0442\u0456\u0432"]',	1,	'ЦИВІЛЬНЕ ПРОЦЕСУАЛЬНЕ ПРАВО'),
(61,	'Який процесуальний документ постановляє суд у випадку подання зустрічного позову у справі, яка розглядається за правилами спрощеного позовного провадження?',	'["\u0443\u0445\u0432\u0430\u043b\u0443 \u043f\u0440\u043e \u0437\u0430\u043b\u0438\u0448\u0435\u043d\u043d\u044f \u043f\u043e\u0437\u043e\u0432\u043d\u043e\u0457 \u0437\u0430\u044f\u0432\u0438 \u0431\u0435\u0437 \u0440\u043e\u0437\u0433\u043b\u044f\u0434\u0443", "\u0443\u0445\u0432\u0430\u043b\u0443 \u043f\u0440\u043e \u043f\u0435\u0440\u0435\u0445\u0456\u0434 \u0434\u043e \u0440\u043e\u0437\u0433\u043b\u044f\u0434\u0443 \u0441\u043f\u0440\u0430\u0432\u0438 \u0437\u0430 \u043f\u0440\u0430\u0432\u0438\u043b\u0430\u043c\u0438 \u0437\u0430\u0433\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u043e\u0437\u043e\u0432\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f", "\u0443\u0445\u0432\u0430\u043b\u0443 \u043f\u0440\u043e \u0437\u0430\u043a\u0440\u0438\u0442\u0442\u044f \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f \u0443 \u0441\u043f\u0440\u0430\u0432\u0456", "\u0443\u0445\u0432\u0430\u043b\u0443 \u043f\u0440\u043e \u0437\u0430\u043a\u0440\u0438\u0442\u0442\u044f \u043f\u0456\u0434\u0433\u043e\u0442\u043e\u0432\u0447\u043e\u0433\u043e \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f \u0442\u0430 \u043f\u0440\u0438\u0437\u043d\u0430\u0447\u0435\u043d\u043d\u044f \u0441\u043f\u0440\u0430\u0432\u0438 \u0434\u043e \u0441\u0443\u0434\u043e\u0432\u043e\u0433\u043e \u0440\u043e\u0437\u0433\u043b\u044f\u0434\u0443 \u043f\u043e \u0441\u0443\u0442\u0456"]',	1,	'ЦИВІЛЬНЕ ПРОЦЕСУАЛЬНЕ ПРАВО'),
(62,	'У провадженні Київського районного суду м. Одеси знаходиться справа про розірвання договору ренти. Після задоволення клопотання про відвід судді зʼясувалось, що новий склад суду для розгляду цієї справи утворити неможливо. Яким чином слід вирішити цю ситуацію?',	'["\u0420\u043e\u0437\u043f\u043e\u0440\u044f\u0434\u0436\u0435\u043d\u043d\u044f\u043c \u0433\u043e\u043b\u043e\u0432\u0438 \u0441\u0443\u0434\u0443 \u0432\u0438\u0440\u0456\u0448\u0438\u0442\u0438 \u043f\u0438\u0442\u0430\u043d\u043d\u044f \u043f\u0440\u043e \u043f\u0435\u0440\u0435\u0434\u0430\u0447\u0443 \u0441\u043f\u0440\u0430\u0432\u0438 \u043d\u0430 \u0440\u043e\u0437\u0433\u043b\u044f\u0434 \u0456\u043d\u0448\u043e\u0433\u043e \u0441\u0443\u0434\u0443, \u043d\u0430\u0439\u0431\u0456\u043b\u044c\u0448 \u0442\u0435\u0440\u0438\u0442\u043e\u0440\u0456\u0430\u043b\u044c\u043d\u043e \u043d\u0430\u0431\u043b\u0438\u0436\u0435\u043d\u043e\u0433\u043e \u0434\u043e \u0446\u044c\u043e\u0433\u043e \u0441\u0443\u0434\u0443.", "\u041f\u0435\u0440\u0435\u0434\u0430\u0442\u0438 \u0441\u043f\u0440\u0430\u0432\u0443 \u0434\u043e \u0441\u0443\u0434\u0443 \u0432\u0438\u0449\u043e\u0457 \u0456\u043d\u0441\u0442\u0430\u043d\u0446\u0456\u0457 \u0434\u043b\u044f \u0432\u0438\u0437\u043d\u0430\u0447\u0435\u043d\u043d\u044f \u0441\u0443\u0434\u0443, \u044f\u043a\u0438\u0439 \u0440\u043e\u0437\u0433\u043b\u044f\u0434\u0430\u0442\u0438\u043c\u0435 \u0441\u043f\u0440\u0430\u0432\u0443.", "\u041f\u043e\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0438 \u0443\u0445\u0432\u0430\u043b\u0443 \u043f\u0440\u043e \u0437\u0430\u043a\u0440\u0438\u0442\u0442\u044f \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f \u0443 \u0441\u043f\u0440\u0430\u0432\u0456 \u0442\u0430 \u0437\u0430\u043f\u0440\u043e\u043f\u043e\u043d\u0443\u0432\u0430\u0442\u0438 \u0443\u0447\u0430\u0441\u043d\u0438\u043a\u0430\u043c \u0437\u0432\u0435\u0440\u043d\u0443\u0442\u0438\u0441\u044f \u0437 \u0446\u0438\u043c \u043f\u043e\u0437\u043e\u0432\u043e\u043c \u0434\u043e \u0441\u0443\u0434\u0443, \u043d\u0430\u0439\u0431\u0456\u043b\u044c\u0448 \u0442\u0435\u0440\u0438\u0442\u043e\u0440\u0456\u0430\u043b\u044c\u043d\u043e \u043d\u0430\u0431\u043b\u0438\u0436\u0435\u043d\u043e\u0433\u043e \u0434\u043e \u0446\u044c\u043e\u0433\u043e \u0441\u0443\u0434\u0443.", "\u041f\u043e\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0438 \u0443\u0445\u0432\u0430\u043b\u0443 \u043f\u0440\u043e \u043f\u0435\u0440\u0435\u0434\u0430\u0447\u0443 \u0441\u043f\u0440\u0430\u0432\u0438 \u043d\u0430 \u0440\u043e\u0437\u0433\u043b\u044f\u0434 \u0456\u043d\u0448\u043e\u0433\u043e \u0441\u0443\u0434\u0443, \u043d\u0430\u0439\u0431\u0456\u043b\u044c\u0448 \u0442\u0435\u0440\u0438\u0442\u043e\u0440\u0456\u0430\u043b\u044c\u043d\u043e \u043d\u0430\u0431\u043b\u0438\u0436\u0435\u043d\u043e\u0433\u043e \u0434\u043e \u0446\u044c\u043e\u0433\u043e \u0441\u0443\u0434\u0443."]',	0,	'ЦИВІЛЬНЕ ПРОЦЕСУАЛЬНЕ ПРАВО'),
(63,	'За позовом К. до І. щодо зняття з реєстрації місця проживання та виселення Дарницьким районним судом міста Києва відкрито провадження в справі. До закінчення підготовчого провадження до суду надійшло клопотання відповідача І. про залучення до участі в справі як співвідповідача Д. Своє клопотання відповідач обґрунтував тим, що предметом спору є спільні права І. та Д. Яким має бути судове рішення?',	'["\u041f\u043e\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0438 \u0443\u0445\u0432\u0430\u043b\u0443 \u043f\u0440\u043e \u0437\u0430\u0434\u043e\u0432\u043e\u043b\u0435\u043d\u043d\u044f \u043a\u043b\u043e\u043f\u043e\u0442\u0430\u043d\u043d\u044f \u043f\u0440\u043e \u0437\u0430\u043b\u0443\u0447\u0435\u043d\u043d\u044f \u0434\u043e \u0443\u0447\u0430\u0441\u0442\u0456 \u0432 \u0441\u043f\u0440\u0430\u0432\u0456 \u0441\u043f\u0456\u0432\u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u0447\u0430 \u0414.", "\u041f\u043e\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0438 \u0443\u0445\u0432\u0430\u043b\u0443 \u043f\u0440\u043e \u0437\u0430\u043b\u0438\u0448\u0435\u043d\u043d\u044f \u0431\u0435\u0437 \u0440\u0443\u0445\u0443 \u043a\u043b\u043e\u043f\u043e\u0442\u0430\u043d\u043d\u044f \u043f\u0440\u043e \u0437\u0430\u043b\u0443\u0447\u0435\u043d\u043d\u044f \u0434\u043e \u0443\u0447\u0430\u0441\u0442\u0456 \u0432 \u0441\u043f\u0440\u0430\u0432\u0456 \u0441\u043f\u0456\u0432\u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u0447\u0430 \u0414.", "\u041f\u043e\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0438 \u0443\u0445\u0432\u0430\u043b\u0443 \u043f\u0440\u043e \u0437\u0430\u043b\u0443\u0447\u0435\u043d\u043d\u044f \u0434\u043e \u0443\u0447\u0430\u0441\u0442\u0456 \u0432 \u0441\u043f\u0440\u0430\u0432\u0456 \u0414. \u044f\u043a \u0442\u0440\u0435\u0442\u044c\u043e\u0457 \u043e\u0441\u043e\u0431\u0438, \u044f\u043a\u0430 \u0437\u0430\u044f\u0432\u043b\u044f\u0454 \u0441\u0430\u043c\u043e\u0441\u0442\u0456\u0439\u043d\u0456 \u0432\u0438\u043c\u043e\u0433\u0438 \u0449\u043e\u0434\u043e \u043f\u0440\u0435\u0434\u043c\u0435\u0442\u0430 \u0441\u043f\u043e\u0440\u0443.", "\u041f\u043e\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0438 \u0443\u0445\u0432\u0430\u043b\u0443 \u043f\u0440\u043e \u0432\u0456\u0434\u043c\u043e\u0432\u0443 \u0432 \u0437\u0430\u0434\u043e\u0432\u043e\u043b\u0435\u043d\u043d\u0456 \u043a\u043b\u043e\u043f\u043e\u0442\u0430\u043d\u043d\u044f \u043f\u0440\u043e \u0437\u0430\u043b\u0443\u0447\u0435\u043d\u043d\u044f \u0434\u043e \u0443\u0447\u0430\u0441\u0442\u0456 \u0432 \u0441\u043f\u0440\u0430\u0432\u0456 \u0441\u043f\u0456\u0432\u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u0447\u0430 \u0414."]',	3,	'ЦИВІЛЬНЕ ПРОЦЕСУАЛЬНЕ ПРАВО'),
(64,	'Відповідач, подаючи заперечення щодо наведених позивачем1 у відповіді на відзив пояснень, посилався на додаткові обставини, що не наводились у відзиві, та підтвердив їх доказами, які ним раніше не подавалися. Як повинен вчинити суд при розгляді справи?',	'["\u0411\u0435\u0440\u0435 \u0434\u043e \u0443\u0432\u0430\u0433\u0438 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u043d\u0456 \u0434\u043e\u043a\u0430\u0437\u0438 \u0432 \u043e\u0431\u043e\u0432''\u044f\u0437\u043a\u043e\u0432\u043e\u043c\u0443 \u043f\u043e\u0440\u044f\u0434\u043a\u0443.", "\u041d\u0435 \u0431\u0435\u0440\u0435 \u0434\u043e \u0443\u0432\u0430\u0433\u0438, \u0442\u043e\u043c\u0443 \u0449\u043e \u0434\u043e\u043a\u0430\u0437\u0438 \u043f\u043e\u0434\u0430\u044e\u0442\u044c\u0441\u044f \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u0447\u0435\u043c \u0440\u0430\u0437\u043e\u043c \u0437 \u0432\u0456\u0434\u0437\u0438\u0432\u043e\u043c.", "\u0411\u0435\u0440\u0435 \u0434\u043e \u0443\u0432\u0430\u0433\u0438, \u044f\u043a\u0449\u043e \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u0447 \u043e\u0431\u0491\u0440\u0443\u043d\u0442\u0443\u0454 \u043d\u0435\u043c\u043e\u0436\u043b\u0438\u0432\u0456\u0441\u0442\u044c \u043f\u043e\u0434\u0430\u043d\u043d\u044f \u0457\u0445 \u0440\u0430\u0437\u043e\u043c \u0437 \u0432\u0456\u0434\u0437\u0438\u0432\u043e\u043c.", "\u041d\u0435 \u0431\u0435\u0440\u0435 \u0434\u043e \u0443\u0432\u0430\u0433\u0438, \u0442\u043e\u043c\u0443 \u0449\u043e \u0434\u043e\u043a\u0430\u0437\u0438 \u043f\u043e\u0434\u0430\u044e\u0442\u044c\u0441\u044f \u043d\u0430 \u0441\u0442\u0430\u0434\u0456\u0457 \u0440\u043e\u0437\u0433\u043b\u044f\u0434\u0443 \u0441\u043f\u0440\u0430\u0432\u0438 \u043f\u043e \u0441\u0443\u0442\u0456."]',	0,	'ЦИВІЛЬНЕ ПРОЦЕСУАЛЬНЕ ПРАВО'),
(65,	'Хто є суб’єктом звернення до суду із заявою про скасування заочного рішення?',	'["\u043f\u043e\u0437\u0438\u0432\u0430\u0447;", "\u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u0447;", "\u043e\u0441\u043e\u0431\u0438, \u044f\u043a\u0456 \u043d\u0435 \u0431\u0440\u0430\u043b\u0438 \u0443\u0447\u0430\u0441\u0442\u0456 \u0443 \u0441\u043f\u0440\u0430\u0432\u0456;", "\u0442\u0440\u0435\u0442\u0456 \u043e\u0441\u043e\u0431\u0438."]',	1,	'ЦИВІЛЬНЕ ПРОЦЕСУАЛЬНЕ ПРАВО'),
(66,	'До якого суду подається заява про скасування рішення міжнародного комерційного арбітражу?',	'["\u0434\u043e \u043c\u0456\u0441\u0446\u0435\u0432\u043e\u0433\u043e \u0437\u0430\u0433\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0441\u0443\u0434\u0443 \u0437\u0430 \u043c\u0456\u0441\u0446\u0435\u0437\u043d\u0430\u0445\u043e\u0434\u0436\u0435\u043d\u043d\u044f\u043c \u0430\u0440\u0431\u0456\u0442\u0440\u0430\u0436\u0443", "\u0434\u043e \u043c\u0456\u0441\u0446\u0435\u0432\u043e\u0433\u043e \u0437\u0430\u0433\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0441\u0443\u0434\u0443 \u0437\u0430 \u043c\u0456\u0441\u0446\u0435\u0437\u043d\u0430\u0445\u043e\u0434\u0436\u0435\u043d\u043d\u044f\u043c \u0431\u043e\u0440\u0436\u043d\u0438\u043a\u0430", "\u0434\u043e \u0430\u043f\u0435\u043b\u044f\u0446\u0456\u0439\u043d\u043e\u0433\u043e \u0437\u0430\u0433\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0441\u0443\u0434\u0443 \u0437\u0430 \u043c\u0456\u0441\u0446\u0435\u0437\u043d\u0430\u0445\u043e\u0434\u0436\u0435\u043d\u043d\u044f\u043c \u0430\u0440\u0431\u0456\u0442\u0440\u0430\u0436\u0443", "\u0434\u043e \u0430\u043f\u0435\u043b\u044f\u0446\u0456\u0439\u043d\u0438\u0439 \u0437\u0430\u0433\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0441\u0443\u0434\u0443 \u0437\u0430 \u043c\u0456\u0441\u0446\u0435\u0437\u043d\u0430\u0445\u043e\u0434\u0436\u0435\u043d\u043d\u044f\u043c \u0431\u043e\u0440\u0436\u043d\u0438\u043a\u0430"]',	2,	'ЦИВІЛЬНЕ ПРОЦЕСУАЛЬНЕ ПРАВО'),
(67,	'За наявності якої умови суд апеляційної інстанції повинен відмовити у відкритті апеляційного провадження якщо апеляційна скарга подана після спливу одного року з дня складення повного тексту судового рішення?',	'["\u0423 \u0440\u0430\u0437\u0456 \u043f\u0440\u043e\u043f\u0443\u0441\u043a\u0443 \u0441\u0442\u0440\u043e\u043a\u0443 \u043d\u0430 \u0430\u043f\u0435\u043b\u044f\u0446\u0456\u0439\u043d\u0435 \u043e\u0441\u043a\u0430\u0440\u0436\u0435\u043d\u043d\u044f \u0432\u043d\u0430\u0441\u043b\u0456\u0434\u043e\u043a \u0432\u0438\u043d\u0438\u043a\u043d\u0435\u043d\u043d\u044f \u0441\u043a\u043b\u0430\u0434\u043d\u0438\u0445 \u0436\u0438\u0442\u0442\u0454\u0432\u0438\u0445 \u043e\u0431\u0441\u0442\u0430\u0432\u0438\u043d.", "\u0423 \u0440\u0430\u0437\u0456 \u043f\u043e\u0434\u0430\u043d\u043d\u044f \u0430\u043f\u0435\u043b\u044f\u0446\u0456\u0439\u043d\u043e\u0457 \u0441\u043a\u0430\u0440\u0433\u0438 \u043e\u0441\u043e\u0431\u043e\u044e, \u043d\u0435 \u043f\u043e\u0432\u0456\u0434\u043e\u043c\u043b\u0435\u043d\u043e\u044e \u043f\u0440\u043e \u0440\u043e\u0437\u0433\u043b\u044f\u0434 \u0441\u043f\u0440\u0430\u0432\u0438.", "\u0423 \u0440\u0430\u0437\u0456 \u043f\u0440\u043e\u043f\u0443\u0441\u043a\u0443 \u0441\u0442\u0440\u043e\u043a\u0443 \u043d\u0430 \u0430\u043f\u0435\u043b\u044f\u0446\u0456\u0439\u043d\u0435 \u043e\u0441\u043a\u0430\u0440\u0436\u0435\u043d\u043d\u044f \u0432\u043d\u0430\u0441\u043b\u0456\u0434\u043e\u043a \u0432\u0438\u043d\u0438\u043a\u043d\u0435\u043d\u043d\u044f \u043e\u0431\u0441\u0442\u0430\u0432\u0438\u043d \u043d\u0435\u043f\u0435\u0440\u0435\u0431\u043e\u0440\u043d\u043e\u0457 \u0441\u0438\u043b\u0438.", "\u0423 \u0440\u0430\u0437\u0456 \u043f\u043e\u0434\u0430\u043d\u043d\u044f \u0430\u043f\u0435\u043b\u044f\u0446\u0456\u0439\u043d\u043e\u0457 \u0441\u043a\u0430\u0440\u0433\u0438 \u043e\u0441\u043e\u0431\u043e\u044e, \u043d\u0435 \u0437\u0430\u043b\u0443\u0447\u0435\u043d\u043e\u044e \u0434\u043e \u0443\u0447\u0430\u0441\u0442\u0456 \u0441\u043f\u0440\u0430\u0432\u0456, \u044f\u043a\u0449\u043e \u0441\u0443\u0434 \u0443\u0445\u0432\u0430\u043b\u0438\u0432 \u0440\u0456\u0448\u0435\u043d\u043d\u044f \u043f\u0440\u043e \u0457\u0457 \u043f\u0440\u0430\u0432\u0430, \u0441\u0432\u043e\u0431\u043e\u0434\u0438, \u0456\u043d\u0442\u0435\u0440\u0435\u0441\u0438 \u0442\u0430 (\u0430\u0431\u043e) \u043e\u0431\u043e\u0432\u02bc\u044f\u0437\u043a\u0438."]',	0,	'ЦИВІЛЬНЕ ПРОЦЕСУАЛЬНЕ ПРАВО'),
(68,	'У якому з варіантів відповіді НЕ правильно вказано категорії цивільних справ, у яких суд допускає негайне виконання рішень?',	'["\u041f\u0440\u0438\u0441\u0443\u0434\u0436\u0435\u043d\u043d\u044f \u043f\u0440\u0430\u0446\u0456\u0432\u043d\u0438\u043a\u043e\u0432\u0456 \u0432\u0438\u043f\u043b\u0430\u0442\u0438 \u0437\u0430\u0440\u043e\u0431\u0456\u0442\u043d\u043e\u0457 \u043f\u043b\u0430\u0442\u0438, \u0430\u043b\u0435 \u043d\u0435 \u0431\u0456\u043b\u044c\u0448\u0435 \u043d\u0456\u0436 \u0437\u0430 \u043e\u0434\u0438\u043d \u043c\u0456\u0441\u044f\u0446\u044c: \u0441\u0442\u044f\u0433\u043d\u0435\u043d\u043d\u044f \u0430\u043b\u0456\u043c\u0435\u043d\u0442\u0456\u0432 \u0443 \u043c\u0435\u0436\u0430\u0445 \u0441\u0443\u043c\u0438 \u043f\u043b\u0430\u0442\u0435\u0436\u0443 \u0437\u0430 \u043e\u0434\u0438\u043d \u043c\u0456\u0441\u044f\u0446\u044c. \u0412\u0456\u0434\u0448\u043a\u043e\u0434\u0443\u0432\u0430\u043d\u043d\u044f \u0448\u043a\u043e\u0434\u0438, \u0437\u0430\u0432\u0434\u0430\u043d\u043e\u0457 \u043a\u0430\u043b\u0456\u0446\u0442\u0432\u043e\u043c, \u0456\u043d\u0448\u0438\u043c \u0443\u0448\u043a\u043e\u0434\u0436\u0435\u043d\u043d\u044f\u043c", "\u0437\u0434\u043e\u0440\u043e\u0432\u02bc\u044f \u0430\u0431\u043e \u0441\u043c\u0435\u0440\u0442\u044e \u0444\u0456\u0437\u0438\u0447\u043d\u043e\u0457 \u043e\u0441\u043e\u0431\u0438, \u0443 \u043c\u0435\u0436\u0430\u0445 \u0441\u0443\u043c\u0438 \u0441\u0442\u044f\u0433\u043d\u0435\u043d\u043d\u044f \u0437\u0430 \u043e\u0434\u0438\u043d \u043c\u0456\u0441\u044f\u0446\u044c; \u0440\u043e\u0437\u043a\u0440\u0438\u0442\u0442\u044f \u0431\u0430\u043d\u043a\u043e\u043c \u0456\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0456\u0457, \u044f\u043a\u0430 \u043c\u0456\u0441\u0442\u0438\u0442\u044c \u0431\u0430\u043d\u043a\u0456\u0432\u0441\u044c\u043a\u0443 \u0442\u0430\u0454\u043c\u043d\u0438\u0446\u044e \u0449\u043e\u0434\u043e \u0444\u0456\u0437\u0438\u0447\u043d\u0438\u0445 \u0442\u0430 \u044e\u0440\u0438\u0434\u0438\u0447\u043d\u0438\u0445 \u043e\u0441\u0456\u0431.", "\u0421\u043f\u043b\u0430\u0442\u0443 \u043f\u043e\u0434\u0430\u0442\u043a\u0456\u0432, \u043f\u0440\u0438\u0441\u0443\u0434\u0436\u0435\u043d\u043d\u044f \u043f\u0440\u0430\u0446\u0456\u0432\u043d\u0438\u043a\u043e\u0432\u0456 \u0432\u0438\u043f\u043b\u0430\u0442\u0438 \u0437\u0430\u0440\u043e\u0431\u0456\u0442\u043d\u043e\u0457 \u043f\u043b\u0430\u0442\u0438, \u0430\u043b\u0435 \u043d\u0435 \u0431\u0456\u043b\u044c\u0448\u0435 \u043d\u0456\u0436 \u0437\u0430 \u043e\u0434\u0438\u043d \u043c\u0456\u0441\u044f\u0446\u044c.", "\u041f\u043e\u043d\u043e\u0432\u043b\u0435\u043d\u043d\u044f \u043d\u0430 \u0440\u043e\u0431\u043e\u0442\u0456 \u043d\u0435\u0437\u0430\u043a\u043e\u043d\u043d\u043e \u0437\u0432\u0456\u043b\u044c\u043d\u0435\u043d\u043e\u0433\u043e \u0430\u0431\u043e \u043f\u0435\u0440\u0435\u0432\u0435\u0434\u0435\u043d\u043e\u0433\u043e \u043d\u0430 \u0456\u043d\u0448\u0443 \u0440\u043e\u0431\u043e\u0442\u0443 \u043f\u0440\u0430\u0446\u0456\u0432\u043d\u0438\u043a\u0430: \u0432\u0456\u0434\u0456\u0431\u0440\u0430\u043d\u043d\u044f \u0434\u0438\u0442\u0438\u043d\u0438 \u0456 \u043f\u043e\u0432\u0435\u0440\u043d\u0435\u043d\u043d\u044f \u0439 \u0442\u043e\u043c\u0443, \u0437 \u043a\u0438\u043c \u0432\u043e\u043d\u0430 \u043f\u0440\u043e\u0436\u0438\u0432\u0430\u043b\u0430."]',	2,	'ЦИВІЛЬНЕ ПРОЦЕСУАЛЬНЕ ПРАВО'),
(69,	'Під час судового засідання сторони подали до суду спільну письмову заяву про укладення мирової угоди. Який процесуальний документ повинен постановити суд в такій ситуації?',	'["\u0423\u0445\u0432\u0430\u043b\u0443 \u043f\u0440\u043e \u0432\u0438\u0437\u043d\u0430\u043d\u043d\u044f \u043c\u0438\u0440\u043e\u0432\u043e\u0457 \u0443\u0433\u043e\u0434\u0438.", "\u0423\u0445\u0432\u0430\u043b\u0443 \u043f\u0440\u043e \u0437\u0430\u0442\u0432\u0435\u0440\u0434\u0436\u0435\u043d\u043d\u044f \u043c\u0438\u0440\u043e\u0432\u043e\u0457 \u0443\u0433\u043e\u0434\u0438.", "\u0423\u0445\u0432\u0430\u043b\u0443 \u043f\u0440\u043e \u0437\u0430\u0442\u0432\u0435\u0440\u0434\u0436\u0435\u043d\u043d\u044f \u043c\u0438\u0440\u043e\u0432\u043e\u0457 \u0443\u0433\u043e\u0434\u0438 \u0432 \u0440\u0435\u0437\u043e\u043b\u044e\u0442\u0438\u0432\u043d\u0456\u0439 \u0447\u0430\u0441\u0442\u0438\u043d\u0456 \u044f\u043a\u043e\u0457 \u0437\u0430\u0437\u043d\u0430\u0447\u0430\u044e\u0442\u044c\u0441\u044f \u0443\u043c\u043e\u0432\u0438 \u0442\u0430\u043a\u043e\u0457 \u0443\u0433\u043e\u0434\u0438 \u0442\u0430 \u043f\u0440\u043e \u0437\u0430\u043a\u0440\u0438\u0442\u0442\u044f \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f \u0443 \u0441\u043f\u0440\u0430\u0432\u0456.", "\u0420\u0456\u0448\u0435\u043d\u043d\u044f, \u0432 \u0440\u0435\u0437\u043e\u043b\u044e\u0442\u0438\u0432\u043d\u0456\u0439 \u0447\u0430\u0441\u0442\u0438\u043d\u0456 \u044f\u043a\u043e\u0433\u043e \u0437\u0430\u0437\u043d\u0430\u0447\u0430\u044e\u0442\u044c\u0441\u044f \u0443\u043c\u043e\u0432\u0438 \u043c\u0438\u0440\u043e\u0432\u043e\u0457 \u0443\u0433\u043e\u0434\u0438."]',	2,	'КРИМІНАЛЬНЕ ПРАВО'),
(70,	'Який принцип чинності кримінального закону слід застосувати для притягнення до кримінальної відповідальності за КК України громадянина іноземної держави, що вчинив особливо тяжкий злочин на території Білорусі проти інтересів України за відсутності відповідних міжнародно-правових зобов’язань?',	'["\u0420\u0435\u0430\u043b\u044c\u043d\u0438\u0439", "\u0422\u0435\u0440\u0438\u0442\u043e\u0440\u0456\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0456", "\u0413\u0440\u043e\u043c\u0430\u0434\u044f\u043d\u0441\u0442\u0432\u0430", "\u0423\u043d\u0456\u0432\u0435\u0440\u0441\u0430\u043b\u044c\u043d\u0438\u0439"]',	0,	'КРИМІНАЛЬНЕ ПРАВО'),
(71,	'А. вчинив діяння, передбачене ч. 1 ст. 262 КК України, а саме: «Викрадення, привласнення, вимагання вогнепальної зброї (крім гладкоствольної мисливської), бойових припасів, вибухових речовин, вибухових пристроїв чи радіоактивних матеріалів або заволодіння ними шляхом шахрайства». Через тиждень А. вчинив діяння, передбачене ч. 3 ст. 185 КК України, а саме: «Крадіжка, поєднана з проникненням у житло, інше приміщення чи сховище або що завдала значної шкоди потерпілому». Визначте вид множинності кримінальних правопорушень.',	'["\u041f\u043e\u0432\u0442\u043e\u0440\u043d\u0456\u0441\u0442\u044c \u043e\u0434\u043d\u043e\u0440\u0456\u0434\u043d\u0438\u0445 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u0438\u0445 \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u044c", "\u041f\u043e\u0432\u0442\u043e\u0440\u043d\u0456\u0441\u0442\u044c \u0440\u0456\u0437\u043d\u043e\u0440\u0456\u0434\u043d\u0438\u0445 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u0438\u0445 \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u044c", "\u0420\u0435\u0430\u043b\u044c\u043d\u0430 \u0441\u0443\u043a\u0443\u043f\u043d\u0456\u0441\u0442\u044c \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u0438\u0445 \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u044c", "\u0420\u0435\u0446\u0438\u0434\u0438\u0432 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u0438\u0445 \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u044c 185 \u041a\u041a\u0423 \u041f\u0440\u0438\u043c\u0456\u0442\u043a\u0430."]',	0,	'КРИМІНАЛЬНЕ ПРАВО'),
(72,	'Громадянин А. 18 листопада 2023 року таємно викрав нарізну мисливську зброю. Через місяць він вчинив таємне викрадення грошових коштів на суму 10 тис. грн. Щодо громадянина А. було порушено кримінальне провадження. Визначте, яка форма (вид) множинності має місце у поведінці громадянина A.?',	'["\u041f\u043e\u0432\u0442\u043e\u0440\u043d\u0456\u0441\u0442\u044c \u0442\u043e\u0442\u043e\u0436\u043d\u0438\u0445 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u0438\u0445 \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u044c", "\u041f\u043e\u0432\u0442\u043e\u0440\u043d\u0456\u0441\u0442\u044c \u043e\u0434\u043d\u043e\u0440\u0456\u0434\u043d\u0438\u0445 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u0438\u0445 \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u044c", "\u0420\u0435\u0430\u043b\u044c\u043d\u0430 \u0441\u0443\u043a\u0443\u043f\u043d\u0456\u0441\u0442\u044c \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u0438\u0445 \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u044c", "\u0421\u043f\u0435\u0446\u0456\u0430\u043b\u044c\u043d\u0438\u0439 \u0440\u0435\u0446\u0438\u0434\u0438\u0432 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u0438\u0445 \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u044c"]',	1,	'КРИМІНАЛЬНЕ ПРАВО'),
(73,	'Ш. знайшов посвідчення учасника бойових дій, яке було видано на ім''я іншої особи. Потім, перебуваючи за місцем свого проживання, вклеїв власну фотокартку в знайдене посвідчення, маючи умисел на його подальше використання метою отримання матеріальної вигоди при користуванні пільгами, встановленими Законом України «Про статус ветеранів війни, гарантії їх соціального захисту». Указаний намір Ш. реалізував, пред''явивши чуже посвідчення з власним фото квитковому контролеру для безкоштовного проїзду в громадському транспорті. Кваліфікуйте дії Ш.',	'["\u041f\u0456\u0434\u0440\u043e\u0431\u043b\u0435\u043d\u043d\u044f \u0434\u043e\u043a\u0443\u043c\u0435\u043d\u0442\u0456\u0432 (\u0447. 1 \u0441\u0442. 358 \u041a\u041a \u0423\u043a\u0440\u0430\u0457\u043d\u0438).", "\u041f\u0440\u0438\u0432\u043b\u0430\u0441\u043d\u0435\u043d\u043d\u044f \u043e\u0444\u0456\u0446\u0456\u0439\u043d\u043e\u0433\u043e \u0434\u043e\u043a\u0443\u043c\u0435\u043d\u0442\u0430 (\u0447. 1 \u0441\u0442. 357 \u0423\u043a\u0440\u0430\u0457\u043d\u0438).", "\u041f\u0456\u0434\u0440\u043e\u0431\u043b\u0435\u043d\u043d\u044f \u0434\u043e\u043a\u0443\u043c\u0435\u043d\u0442\u0456\u0432 (\u0447. 1 \u0441\u0442. 358 \u041a\u041a \u0423\u043a\u0440\u0430\u0457\u043d\u0438) \u0442\u0430 \u0432\u0438\u043a\u043e\u0440\u0438\u0441\u0442\u0430\u043d\u043d\u044f \u0437\u0430\u0432\u0456\u0434\u043e\u043c\u043e \u043f\u0456\u0434\u0440\u043e\u0431\u043b\u0435\u043d\u043e\u0433\u043e \u0434\u043e\u043a\u0443\u043c\u0435\u043d\u0442\u0430 (\u0447. 4 \u0441\u0442. 358 \u041a\u041a \u0423\u043a\u0440\u0430\u0457\u043d\u0438).", "\u041f\u0456\u0434\u0440\u043e\u0431\u043b\u0435\u043d\u043d\u044f \u0434\u043e\u043a\u0443\u043c\u0435\u043d\u0442\u0456\u0432 (\u0447. 1 \u0441\u0442. 358 \u041a\u041a \u0423\u043a\u0440\u0430\u0457\u043d\u0438) \u0442\u0430 \u0441\u0430\u043c\u043e\u0432\u0456\u043b\u044c\u043d\u0435 \u043f\u0440\u0438\u0441\u0432\u043e\u0454\u043d\u043d\u044f \u0432\u043b\u0430\u0434\u0438 \u0430\u0431\u043e \u0437\u0432\u0430\u043d\u043d\u044f \u0441\u043b\u0443\u0436\u0431\u043e\u0432\u043e\u0457 \u043e\u0441\u043e\u0431\u0438 (\u0447. 1 \u0441\u0442. 353 \u041a\u041a \u0423\u043a\u0440\u0430\u0457\u043d\u0438)."]',	2,	'КРИМІНАЛЬНЕ ПРАВО'),
(74,	'У невстановленої слідством особи наркоман С. придбав медичний шприц з однією дозою речовини, яку вважав героїном. Того ж дня його було зупинено співробітниками поліції та під час особистого огляду видав цей медичний шприц об''ємом 10 мл з рідиною об''ємом 0,2 мл. За висновком судової експертизи наркотичних засобів у вилученому шприці був фізіологічний розчин. Як кваліфікувати дії С.?',	'["\u0417\u0430\u043a\u0456\u043d\u0447\u0435\u043d\u0438\u0439 \u0437\u0430\u043c\u0430\u0445 \u043d\u0430 \u043d\u0435\u0437\u0430\u043a\u043e\u043d\u043d\u0435 \u043f\u0440\u0438\u0434\u0431\u0430\u043d\u043d\u044f \u0456 \u0437\u0431\u0435\u0440\u0456\u0433\u0430\u043d\u043d\u044f \u043d\u0430\u0440\u043a\u043e\u0442\u0438\u0447\u043d\u0438\u0445 \u0437\u0430\u0441\u043e\u0431\u0456\u0432 \u0431\u0435\u0437 \u043c\u0435\u0442\u0438 \u0437\u0431\u0443\u0442\u0443 (\u0447. 2 \u0441\u0442. 15, \u0447. 1 \u0441\u0442. 309 \u041a\u041a \u0423\u043a\u0440\u0430\u0457\u043d\u0438).", "\u041d\u0435\u0437\u0430\u043a\u043e\u043d\u043d\u0435 \u043f\u0440\u0438\u0434\u0431\u0430\u043d\u043d\u044f \u0456 \u0437\u0431\u0435\u0440\u0456\u0433\u0430\u043d\u043d\u044f \u043d\u0430\u0440\u043a\u043e\u0442\u0438\u0447\u043d\u0438\u0445 \u0437\u0430\u0441\u043e\u0431\u0456\u0432 \u0431\u0435\u0437 \u043c\u0435\u0442\u0438 \u0437\u0431\u0443\u0442\u0443 (\u0447. 1 \u0441\u0442. 309 \u041a\u041a \u0423\u043a\u0440\u0430\u0457\u043d\u0438).", "\u041d\u0435\u0437\u0430\u043a\u043e\u043d\u043d\u0435 \u043f\u0440\u0438\u0434\u0431\u0430\u043d\u043d\u044f \u0456 \u0437\u0431\u0435\u0440\u0456\u0433\u0430\u043d\u043d\u044f \u043e\u0441\u043e\u0431\u043b\u0438\u0432\u043e \u043d\u0435\u0431\u0435\u0437\u043f\u0435\u0447\u043d\u0438\u0445 \u043d\u0430\u0440\u043a\u043e\u0442\u0438\u0447\u043d\u0438\u0445 \u0437\u0430\u0441\u043e\u0431\u0456\u0432 \u0456\u0437 \u043c\u0435\u0442\u043e\u044e \u0437\u0431\u0443\u0442\u0443 (\u0447. 2 \u0441\u0442. 307 \u041a\u041a \u0423\u043a\u0440\u0430\u0457\u043d\u0438).", "\u0423 \u0434\u0456\u044f\u0445 \u0421. \u0441\u043a\u043b\u0430\u0434\u0443 \u0437\u043b\u043e\u0447\u0438\u043d\u0443 \u043d\u0435\u043c\u0430\u0454."]',	0,	'КРИМІНАЛЬНЕ ПРАВО'),
(75,	'Яке з перелічених діянь охоплюється об''єктивною стороною складу злочину «Випуск в експлуатацію технічно несправних транспортних засобів або інше порушення їх експлуатації» (ст. 287 КК)?',	'["\u0414\u043e\u043f\u0443\u0441\u043a \u0434\u043e \u043a\u0435\u0440\u0443\u0432\u0430\u043d\u043d\u044f \u0442\u0440\u0430\u043d\u0441\u043f\u043e\u0440\u0442\u043d\u0438\u043c \u0437\u0430\u0441\u043e\u0431\u043e\u043c \u043e\u0441\u043e\u0431\u0438, \u044f\u043a\u0430 \u043d\u0435 \u043c\u0430\u0454 \u043f\u0440\u0430\u0432\u0430 \u043d\u0430 \u043a\u0435\u0440\u0443\u0432\u0430\u043d\u043d\u044f \u0442\u0440\u0430\u043d\u0441\u043f\u043e\u0440\u0442\u043d\u0438\u043c \u0437\u0430\u0441\u043e\u0431\u043e\u043c.", "\u041a\u0435\u0440\u0443\u0432\u0430\u043d\u043d\u044f \u0442\u0440\u0430\u043d\u0441\u043f\u043e\u0440\u0442\u043d\u0438\u043c \u0437\u0430\u0441\u043e\u0431\u043e\u043c \u0443 \u0441\u0442\u0430\u043d\u0456 \u0430\u043b\u043a\u043e\u0433\u043e\u043b\u044c\u043d\u043e\u0433\u043e, \u043d\u0430\u0440\u043a\u043e\u0442\u0438\u0447\u043d\u043e\u0433\u043e \u0447\u0438 \u0456\u043d\u0448\u043e\u0433\u043e \u0441\u043f''\u044f\u043d\u0456\u043d\u043d\u044f.", "\u041f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u043f\u0440\u0430\u0432\u0438\u043b \u0431\u0435\u0437\u043f\u0435\u043a\u0438 \u0435\u043a\u0441\u043f\u043b\u0443\u0430\u0442\u0430\u0446\u0456\u0457 \u0442\u0440\u0430\u043d\u0441\u043f\u043e\u0440\u0442\u0443 \u043e\u0441\u043e\u0431\u043e\u044e, \u044f\u043a\u0430 \u043a\u0435\u0440\u0443\u0454 \u0442\u0440\u0430\u043d\u0441\u043f\u043e\u0440\u0442\u043d\u0438\u043c \u0437\u0430\u0441\u043e\u0431\u043e\u043c.", "\u0417\u0430\u043c\u0456\u043d\u0430 \u0431\u0435\u0437 \u0434\u043e\u0437\u0432\u043e\u043b\u0443 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u043d\u0438\u0445 \u043e\u0440\u0433\u0430\u043d\u0456\u0432 \u043d\u043e\u043c\u0435\u0440\u043d\u043e\u0457 \u043f\u0430\u043d\u0435\u043b\u0456 \u0437 \u0456\u0434\u0435\u043d\u0442\u0438\u0444\u0456\u043a\u0430\u0446\u0456\u0439\u043d\u0438\u043c \u043d\u043e\u043c\u0435\u0440\u043e\u043c \u0442\u0440\u0430\u043d\u0441\u043f\u043e\u0440\u0442\u043d\u043e\u0433\u043e \u0437\u0430\u0441\u043e\u0431\u0443."]',	0,	'КРИМІНАЛЬНЕ ПРАВО'),
(76,	'До кого може бути застосоване кримінальне покарання у вигляді арешту?',	'["\u0434\u043e \u0431\u0443\u0434\u044c-\u044f\u043a\u043e\u0457 \u043e\u0441\u043e\u0431\u0438, \u044f\u043a\u0430 \u0434\u043e\u0441\u044f\u0433\u043b\u0430 \u0432\u0456\u043a\u0443 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0457 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0456", "\u0434\u043e \u0431\u0443\u0434\u044c-\u044f\u043a\u043e\u0457 \u043e\u0441\u043e\u0431\u0438, \u044f\u043a\u0430 \u0434\u043e\u0441\u044f\u0433\u043b\u0430 16-\u0440\u0456\u0447\u043d\u043e\u0433\u043e \u0432\u0456\u043a\u0443", "\u0434\u043e \u0431\u0443\u0434\u044c-\u044f\u043a\u043e\u0457 \u043e\u0441\u043e\u0431\u0438, \u044f\u043a\u0430 \u0434\u043e\u0441\u044f\u0433\u043b\u0430 18-\u0440\u0456\u0447\u043d\u043e\u0433\u043e \u0432\u0456\u043a\u0443", "\u0434\u043e \u0432\u0456\u0439\u0441\u044c\u043a\u043e\u0432\u043e\u0441\u043b\u0443\u0436\u0431\u043e\u0432\u0446\u044f"]',	3,	'КРИМІНАЛЬНЕ ПРАВО'),
(77,	'Особа без громадянства, яка постійно проживає на території України, вчинила умисне вбивство на території Молдови. Застосування якого принципу чинності закону України про кримінальну відповідальність має місце в такому випадку за загальним правилом відповідно до кримінального законодавства України?',	'["\u0433\u0440\u043e\u043c\u0430\u0434\u044f\u043d\u0441\u0442\u0432\u0430", "\u0442\u0435\u0440\u0438\u0442\u043e\u0440\u0456\u0430\u043b\u044c\u043d\u043e\u0433\u043e", "\u0443\u043d\u0456\u0432\u0435\u0440\u0441\u0430\u043b\u044c\u043d\u043e\u0433\u043e", "\u0440\u0435\u0430\u043b\u044c\u043d\u043e\u0433\u043e"]',	0,	'КРИМІНАЛЬНЕ ПРАВО'),
(78,	'Максимальним ступенем шкоди здоровʼю, властивим насильницькому грабежу, є:',	'["\u0432\u0438\u0440\u0438\u0432\u0430\u043d\u043d\u044f \u043c\u0430\u0439\u043d\u0430 \u0437 \u0440\u0443\u043a \u043f\u043e\u0442\u0435\u0440\u043f\u0456\u043b\u043e\u0433\u043e", "\u0437\u0430\u043f\u043e\u0434\u0456\u044f\u043d\u043d\u044f \u043b\u0435\u0433\u043a\u043e\u0433\u043e \u0442\u0456\u043b\u0435\u0441\u043d\u043e\u0433\u043e \u0443\u0448\u043a\u043e\u0434\u0436\u0435\u043d\u043d\u044f, \u0449\u043e \u043d\u0435 \u0441\u043f\u0440\u0438\u0447\u0438\u043d\u0438\u043b\u043e \u0440\u043e\u0437\u043b\u0430\u0434\u0443 \u0437\u0434\u043e\u0440\u043e\u0432\u02bc\u044f \u0442\u0430 \u0432\u0442\u0440\u0430\u0442\u0438 \u043f\u0440\u0430\u0446\u0435\u0437\u0434\u0430\u0442\u043d\u043e\u0441\u0442\u0456", "\u0437\u0430\u043f\u043e\u0434\u0456\u044f\u043d\u043d\u044f \u043b\u0435\u0433\u043a\u043e\u0433\u043e \u0442\u0456\u043b\u0435\u0441\u043d\u043e\u0433\u043e \u0443\u0448\u043a\u043e\u0434\u0436\u0435\u043d\u043d\u044f, \u0449\u043e \u0441\u043f\u0440\u0438\u0447\u0438\u043d\u0438\u043b\u043e \u043a\u043e\u0440\u043e\u0442\u043a\u043e\u0447\u0430\u0441\u043d\u0438\u0439 \u0440\u043e\u0437\u043b\u0430\u0434 \u0437\u0434\u043e\u0440\u043e\u0432\u02bc\u044f \u0430\u0431\u043e \u043f\u0440\u0430\u0446\u0435\u0437\u0434\u0430\u0442\u043d\u043e\u0441\u0442\u0456", "\u0437\u0430\u043f\u043e\u0434\u0456\u044f\u043d\u043d\u044f \u0442\u0456\u043b\u0435\u0441\u043d\u0438\u0445 \u0443\u0448\u043a\u043e\u0434\u0436\u0435\u043d\u044c \u0441\u0435\u0440\u0435\u0434\u043d\u044c\u043e\u0433\u043e \u0441\u0442\u0443\u043f\u0435\u043d\u044f \u0442\u044f\u0436\u043a\u043e\u0441\u0442\u0456"]',	1,	'КРИМІНАЛЬНЕ ПРАВО'),
(79,	'Укажіть відповідь, в якій названо передбачений Кримінальним кодексом України вид звільнення особи від кримінальної відповідальності?',	'["\u0437\u0432\u0456\u043b\u044c\u043d\u0435\u043d\u043d\u044f \u0432\u0456\u0434 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0457 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0456 \u0443 \u0437\u0432\u02bc\u044f\u0437\u043a\u0443 \u0437 \u044f\u0432\u043a\u043e\u044e \u0437 \u043f\u043e\u0432\u0438\u043d\u043d\u043e\u044e", "\u0437\u0432\u0456\u043b\u044c\u043d\u0435\u043d\u043d\u044f \u0432\u0456\u0434 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0457 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0456 \u0443 \u0437\u0432\u02bc\u044f\u0437\u043a\u0443 \u0437 \u0449\u0438\u0440\u0438\u043c \u043a\u0430\u044f\u0442\u0442\u044f\u043c", "\u0437\u0432\u0456\u043b\u044c\u043d\u0435\u043d\u043d\u044f \u0432\u0456\u0434 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0457 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0456 \u043f\u0440\u0438 \u0433\u043e\u0442\u0443\u0432\u0430\u043d\u043d\u0456 \u0434\u043e \u0437\u043b\u043e\u0447\u0438\u043d\u0443 \u043d\u0435\u0432\u0435\u043b\u0438\u043a\u043e\u0457 \u0442\u044f\u0436\u043a\u043e\u0441\u0442\u0456", "\u0437\u0432\u0456\u043b\u044c\u043d\u0435\u043d\u043d\u044f \u0432\u0456\u0434 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0457 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0456 \u0443 \u0437\u0432\u02bc\u044f\u0437\u043a\u0443 \u0437 \u0437\u043c\u0456\u043d\u043e\u044e \u043e\u0431\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0438"]',	3,	'КРИМІНАЛЬНЕ ПРАВО'),
(81,	'З якого моменту особа вважається такою, що досягла певного віку?',	'["\u0417 00 \u0433\u043e\u0434\u0438\u043d 00 \u0445\u0432\u0438\u043b\u0438\u043d \u043d\u0430\u0441\u0442\u0443\u043f\u043d\u043e\u0457 \u0434\u043e\u0431\u0438 \u043f\u0456\u0441\u043b\u044f \u0434\u043d\u044f \u0441\u0432\u043e\u0433\u043e \u043d\u0430\u0440\u043e\u0434\u0436\u0435\u043d\u043d\u044f.", "\u0417 00 \u0433\u043e\u0434\u0438\u043d 01 \u0445\u0432\u0438\u043b\u0438\u043d\u0438 \u043d\u0430\u0441\u0442\u0443\u043f\u043d\u043e\u0457 \u0434\u043e\u0431\u0438 \u043f\u0456\u0441\u043b\u044f \u0434\u043d\u044f \u0441\u0432\u043e\u0433\u043e \u043d\u0430\u0440\u043e\u0434\u0436\u0435\u043d\u043d\u044f.", "\u0417 00 \u0433\u043e\u0434\u0438\u043d\u0438 01 \u0445\u0432\u0438\u043b\u0438\u043d\u0438 \u0434\u043d\u044f \u0441\u0432\u043e\u0433\u043e \u043d\u0430\u0440\u043e\u0434\u0436\u0435\u043d\u043d\u044f.", "\u0417 00 \u0433\u043e\u0434\u0438\u043d 00 \u0445\u0432\u0438\u043b\u0438\u043d \u0434\u043d\u044f \u0441\u0432\u043e\u0433\u043e \u043d\u0430\u0440\u043e\u0434\u0436\u0435\u043d\u043d\u044f."]',	0,	'КРИМІНАЛЬНЕ ПРАВО'),
(82,	'Особа вчинила кримінальне правопорушення у стані осудності, але до винесення вироку захворіла на психічну хворобу. Щодо неї було застосовано примусовий захід медичного характеру. Невдовзі особа видужала. Чи підлягає вона покаранню?',	'["\u041d\u0435 \u043f\u0456\u0434\u043b\u044f\u0433\u0430\u0454 \u043f\u043e\u043a\u0430\u0440\u0430\u043d\u043d\u044e.", "\u041f\u0456\u0434\u043b\u044f\u0433\u0430\u0454 \u043f\u043e\u0434\u0430\u043b\u044c\u0448\u043e\u043c\u0443 \u0432\u0456\u0434\u0431\u0443\u0432\u0430\u043d\u043d\u044e \u043f\u043e\u043a\u0430\u0440\u0430\u043d\u043d\u044f \u0437 \u0432\u0440\u0430\u0445\u0443\u0432\u0430\u043d\u043d\u044f\u043c \u0441\u0442\u0440\u043e\u043a\u0443 \u043b\u0456\u043a\u0443\u0432\u0430\u043d\u043d\u044f.", "\u041c\u043e\u0436\u0435 \u043f\u0456\u0434\u043b\u044f\u0433\u0430\u0442\u0438 \u043f\u043e\u043a\u0430\u0440\u0430\u043d\u043d\u044e \u043d\u0430 \u0437\u0430\u0433\u0430\u043b\u044c\u043d\u0438\u0445 \u043f\u0456\u0434\u0441\u0442\u0430\u0432\u0430\u0445", "\u041f\u0456\u0434\u043b\u044f\u0433\u0430\u0454 \u043f\u043e\u043a\u0430\u0440\u0430\u043d\u043d\u044e \u043b\u0438\u0448\u0435 \u0443 \u0440\u0430\u0437\u0456 \u0432\u0447\u0438\u043d\u0435\u043d\u043d\u044f \u0442\u044f\u0436\u043a\u043e\u0433\u043e \u0447\u0438 \u043e\u0441\u043e\u0431\u043b\u0438\u0432\u043e \u0442\u044f\u0436\u043a\u043e\u0433\u043e \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f."]',	2,	'КРИМІНАЛЬНЕ ПРАВО'),
(83,	'У якому із варіантів відповідей зазначені види звільнення від кримінальної відповідальності що є безумовними?',	'["\u0437\u0432\u0456\u043b\u044c\u043d\u0435\u043d\u043d\u044f \u0432\u0456\u0434 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0457 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0456 \u0443 \u0437\u0432\u2019\u044f\u0437\u043a\u0443 \u0437 \u043f\u0435\u0440\u0435\u0434\u0430\u0447\u0435\u044e \u043e\u0441\u043e\u0431\u0438 \u043d\u0430 \u043f\u043e\u0440\u0443\u043a\u0438 \u0442\u0430 \u0437\u0432\u0456\u043b\u044c\u043d\u0435\u043d\u043d\u044f \u0432\u0456\u0434 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0457 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0456 \u0443 \u0437\u0432\u2019\u044f\u0437\u043a\u0443 \u0437 \u043f\u0440\u0438\u043c\u0438\u0440\u0435\u043d\u043d\u044f\u043c \u0432\u0438\u043d\u043d\u043e\u0433\u043e \u0437 \u043f\u043e\u0442\u0435\u0440\u043f\u0456\u043b\u0438\u043c;", "\u0437\u0432\u0456\u043b\u044c\u043d\u0435\u043d\u043d\u044f \u0432\u0456\u0434 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0457 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0456 \u0443 \u0437\u0432\u2019\u044f\u0437\u043a\u0443 \u0437\u0456 \u0437\u043c\u0456\u043d\u043e\u044e \u043e\u0431\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0438 \u0442\u0430 \u0437\u0432\u0456\u043b\u044c\u043d\u0435\u043d\u043d\u044f \u0432\u0456\u0434 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0457 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0456 \u0443 \u0437\u0432\u2019\u044f\u0437\u043a\u0443 \u0437 \u0434\u0456\u0439\u043e\u0432\u0438\u043c \u043a\u0430\u044f\u0442\u0442\u044f\u043c \u0437\u0432\u0456\u043b\u044c\u043d\u0435\u043d\u043d\u044f \u0432\u0456\u0434 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0457 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0456 \u0443 \u0437\u0432\u2019\u044f\u0437\u043a\u0443 \u0437 \u043f\u0435\u0440\u0435\u0434\u0430\u0447\u0435\u044e", "\u043e\u0441\u043e\u0431\u0438 \u043d\u0430 \u043f\u043e\u0440\u0443\u043a\u0438 \u0442\u0430 \u0437\u0432\u0456\u043b\u044c\u043d\u0435\u043d\u043d\u044f \u0432\u0456\u0434 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0457 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0456 \u043d\u0435\u043f\u043e\u0432\u043d\u043e\u043b\u0456\u0442\u043d\u044c\u043e\u0433\u043e \u0456\u0437 \u0437\u0430\u0441\u0442\u043e\u0441\u0443\u0432\u0430\u043d\u043d\u044f\u043c \u043f\u0440\u0438\u043c\u0443\u0441\u043e\u0432\u0438\u0445 \u0437\u0430\u0445\u043e\u0434\u0456\u0432 \u0432\u0438\u0445\u043e\u0432\u043d\u043e\u0433\u043e \u0445\u0430\u0440\u0430\u043a\u0442\u0435\u0440\u0443; \u0437\u0432\u0456\u043b\u044c\u043d\u0435\u043d\u043d\u044f \u0432\u0456\u0434 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0457 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0456 \u043d\u0435\u043f\u043e\u0432\u043d\u043e\u043b\u0456\u0442\u043d\u044c\u043e\u0433\u043e \u0456\u0437", "\u0437\u0430\u0441\u0442\u043e\u0441\u0443\u0432\u0430\u043d\u043d\u044f\u043c \u043f\u0440\u0438\u043c\u0443\u0441\u043e\u0432\u0438\u0445 \u0437\u0430\u0445\u043e\u0434\u0456\u0432 \u0432\u0438\u0445\u043e\u0432\u043d\u043e\u0433\u043e \u0445\u0430\u0440\u0430\u043a\u0442\u0435\u0440\u0443 \u0442\u0430 \u0437\u0432\u0456\u043b\u044c\u043d\u0435\u043d\u043d\u044f \u0432\u0456\u0434 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0457 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0456 \u0443 \u0437\u0432\u2019\u044f\u0437\u043a\u0443 \u0437\u0456 \u0437\u043c\u0456\u043d\u043e\u044e \u043e\u0431\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0438;"]',	1,	'КРИМІНАЛЬНЕ ПРАВО'),
(84,	'Хто з нижче перелічених осіб НЕ може бути потерпілим від кримінального правопорушення, передбаченого ст. 112 Кримінального кодексу України (Посягання на життя державного чи громадського діяча)?',	'["\u0413\u0435\u043d\u0435\u0440\u0430\u043b\u044c\u043d\u0438\u0439 \u043f\u0440\u043e\u043a\u0443\u0440\u043e\u0440 \u0423\u043a\u0440\u0430\u0457\u043d\u0438.", "\u0413\u043e\u043b\u043e\u0432\u0430 \u041a\u043e\u043d\u0441\u0442\u0438\u0442\u0443\u0446\u0456\u0439\u043d\u043e\u0433\u043e \u0421\u0443\u0434\u0443 \u0423\u043a\u0440\u0430\u0457\u043d\u0438.", "\u0413\u043e\u043b\u043e\u0432\u0430 \u0412\u0435\u0440\u0445\u043e\u0432\u043d\u043e\u0457 \u0420\u0430\u0434\u0438 \u0423\u043a\u0440\u0430\u0457\u043d\u0438.", "\u0414\u0435\u0440\u0436\u0430\u0432\u043d\u0438\u0439 \u0441\u0435\u043a\u0440\u0435\u0442\u0430\u0440 \u041a\u0430\u0431\u0456\u043d\u0435\u0442\u0443 \u041c\u0456\u043d\u0456\u0441\u0442\u0440\u0456\u0432 \u0423\u043a\u0440\u0430\u0457\u043d\u0438"]',	3,	'КРИМІНАЛЬНЕ ПРАВО'),
(85,	'Вкажіть особливість, яку має втрата працездатності як ознака1 тілесного ушкодження?',	'["\u0412\u043e\u043d\u0430 \u043c\u043e\u0436\u0435 \u0431\u0443\u0442\u0438 \u043e\u0437\u043d\u0430\u043a\u043e\u044e \u043b\u0438\u0448\u0435 \u0442\u044f\u0436\u043a\u043e\u0433\u043e \u0442\u0456\u043b\u0435\u0441\u043d\u043e\u0433\u043e \u0443\u0448\u043a\u043e\u0434\u0436\u0435\u043d\u043d\u044f.", "\u0412\u043e\u043d\u0430 \u043f\u043e\u0432\u0438\u043d\u043d\u0430 \u0431\u0443\u0442\u0438 \u0441\u0442\u0456\u0439\u043a\u043e\u044e (\u043d\u0435\u043e\u0431\u043e\u0440\u043e\u0442\u043d\u043e\u044e), \u0442\u043e\u0431\u0442\u043e \u0442\u0430\u043a\u043e\u044e, \u044f\u043a\u0430 \u043f\u043e\u0432\u043d\u0456\u0441\u0442\u044e \u043d\u0435 \u0432\u0456\u0434\u043d\u043e\u0432\u043b\u044e\u0454\u0442\u044c\u0441\u044f.", "\u0412\u043e\u043d\u0430 \u0432\u0438\u043c\u0456\u0440\u044e\u0454\u0442\u044c\u0441\u044f \u0432 \u0434\u043d\u044f\u0445, \u043f\u0440\u043e\u0442\u044f\u0433\u043e\u043c \u044f\u043a\u0438\u0445 \u043e\u0441\u043e\u0431\u0430 \u043f\u0435\u0440\u0435\u0431\u0443\u0432\u0430\u043b\u0430 \u043d\u0430 \u0441\u0442\u0430\u0446\u0456\u043e\u043d\u0430\u0440\u043d\u043e\u043c\u0443 \u0447\u0438 \u0430\u043c\u0431\u0443\u043b\u0430\u0442\u043e\u0440\u043d\u043e\u043c\u0443 \u043b\u0456\u043a\u0443\u0432\u0430\u043d\u043d\u0456.", "\u0412\u043e\u043d\u0430 \u0441\u0442\u043e\u0441\u0443\u0454\u0442\u044c\u0441\u044f \u043b\u0438\u0448\u0435 \u043f\u0440\u043e\u0444\u0435\u0441\u0456\u0439\u043d\u043e\u0457 \u043f\u0440\u0430\u0446\u0435\u0437\u0434\u0430\u0442\u043d\u043e\u0441\u0442\u0456, \u0430 \u0432\u0442\u0440\u0430\u0442\u0430 \u0437\u0430\u0433\u0430\u043b\u044c\u043d\u043e\u0457 \u043f\u0440\u0430\u0446\u0435\u0437\u0434\u0430\u0442\u043d\u043e\u0441\u0442\u0456 \u0434\u043e \u0443\u0432\u0430\u0433\u0438 \u0431\u0440\u0430\u0442\u0438\u0441\u044f \u043d\u0435 \u043c\u043e\u0436\u0435."]',	1,	'КРИМІНАЛЬНЕ ПРАВО'),
(86,	'Водій А., втомлений після нічного переїзду, під час спільного приятелем Б. розпиття горілки, раптово безпричинно розпочав бійку, під час якої заподіяв Б. тяжке тілесне ушкодження. Судово-психіатрична експертиза дійшла висновку, що А. під час вчинення вказаних дій перебував у стані патологічного сп’яніння і не міг усвідомлювати свої дії. Чи буде А. притягнуто до кримінальної відповідальності?',	'["\u0422\u0430\u043a, \u043d\u0430 \u0437\u0430\u0433\u0430\u043b\u044c\u043d\u0438\u0445 \u043f\u0456\u0434\u0441\u0442\u0430\u0432\u0430\u0445.", "\u0422\u0430\u043a, \u0430 \u0441\u0442\u0430\u043d \u0441\u043f\u2019\u044f\u043d\u0456\u043d\u043d\u044f \u0431\u0443\u0434\u0435 \u043e\u0431\u0441\u0442\u0430\u0432\u0438\u043d\u043e\u044e, \u0449\u043e \u043e\u0431\u0442\u044f\u0436\u0438\u0442\u044c \u043f\u043e\u043a\u0430\u0440\u0430\u043d\u043d\u044f.", "\u041d\u0456, \u0443 \u0437\u0432\u2019\u044f\u0437\u043a\u0443 \u0437 \u0432\u0438\u0437\u043d\u0430\u043d\u043d\u044f\u043c \u0410. \u043e\u0431\u043c\u0435\u0436\u0435\u043d\u043e \u043e\u0441\u0443\u0434\u043d\u0438\u043c.", "\u041d\u0456, \u0443 \u0437\u0432\u2019\u044f\u0437\u043a\u0443 \u0437 \u0432\u0438\u0437\u043d\u0430\u043d\u043d\u044f\u043c \u0410. \u043d\u0435\u043e\u0441\u0443\u0434\u043d\u0438\u043c."]',	3,	'КРИМІНАЛЬНЕ ПРАВО'),
(99,	'Який документ повинен скласти прокурор для початку досудового розслідування, якщо відсутня технічна можливість доступу до Єдиного реєстру досудових розслідувань через введення воєнного стану?',	'["\u0420\u0430\u043f\u043e\u0440\u0442.", "\u041f\u043e\u0441\u0442\u0430\u043d\u043e\u0432\u0443.", "\u0423\u0445\u0432\u0430\u043b\u0443.", "\u041f\u0440\u043e\u0442\u043e\u043a\u043e\u043b."]',	1,	'КРИМІНАЛЬНО-ПРОЦЕСУАЛЬНЕ ПРАВО'),
(87,	'Яку обставину, що обтяжує покарання, суд має обовʼязково врахувати?',	'["\u0412\u0447\u0438\u043d\u0435\u043d\u043d\u044f \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u0441\u043f\u0435\u0446\u0456\u0430\u043b\u044c\u043d\u0438\u043c\u0438 \u0441\u0443\u0431\u02bc\u0454\u043a\u0442\u0430\u043c\u0438", "\u0412\u0447\u0438\u043d\u0435\u043d\u043d\u044f \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u0433\u0440\u0443\u043f\u043e\u044e \u043e\u0441\u0456\u0431 \u0431\u0435\u0437 \u043f\u043e\u043f\u0435\u0440\u0435\u0434\u043d\u044c\u043e\u0457 \u0437\u043c\u043e\u0432\u0438", "\u0412\u0447\u0438\u043d\u0435\u043d\u043d\u044f \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u0437 \u0432\u0438\u043a\u043e\u0440\u0438\u0441\u0442\u0430\u043d\u043d\u044f\u043c \u043e\u0441\u043e\u0431\u0438, \u044f\u043a\u0430 \u0441\u0442\u0440\u0430\u0436\u0434\u0430\u0454 \u043d\u0435\u0434\u043e\u0443\u043c\u0441\u0442\u0432\u043e\u043c", "\u0412\u0447\u0438\u043d\u0435\u043d\u043d\u044f \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u0432\u0430\u0433\u0456\u0442\u043d\u043e\u044e"]',	2,	'КРИМІНАЛЬНО-ПРОЦЕСУАЛЬНЕ ПРАВО'),
(88,	'Зміст якої засади кримінального провадження розкриває наступне положення: «Прокурор, керівник органу досудового розслідування, слідчий зобов’язані всебічно, повно і неупереджено дослідити обставини кримінального провадження, виявити як ті обставини, що викривають, так і що виправдовують підозрюваного, обвинуваченого, а також обставини, що пом’якшують чи обтяжують його покарання, надати їм належну правову оцінку та забезпечити прийняття законних і неупереджених процесуальних рішень»?',	'["\u0414\u043e\u0441\u0442\u0443\u043f \u0434\u043e \u043f\u0440\u0430\u0432\u043e\u0441\u0443\u0434\u0434\u044f", "\u0412\u0441\u0435\u0431\u0456\u0447\u043d\u0456\u0441\u0442\u044c, \u043f\u043e\u0432\u043d\u043e\u0442\u0430 \u0442\u0430 \u043d\u0435\u0443\u043f\u0435\u0440\u0435\u0434\u0436\u0435\u043d\u043d\u0456\u0441\u0442\u044c \u0434\u043e\u0441\u043b\u0456\u0434\u0436\u0435\u043d\u043d\u044f \u043e\u0431\u0441\u0442\u0430\u0432\u0438\u043d \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f", "\u0417\u0430\u043a\u043e\u043d\u043d\u0456\u0441\u0442\u044c", "\u041f\u0443\u0431\u043b\u0456\u0447\u043d\u0456\u0441\u0442\u044c"]',	2,	'КРИМІНАЛЬНО-ПРОЦЕСУАЛЬНЕ ПРАВО'),
(89,	'У судове засідання не з''явився цивільний позивач, який був належним чином повідомлений про дату і час судового засідання, однак жодних клопотань чи заяв від нього не надходило й про причини своєї неявки він не попереджав. Цивільний відповідач заперечує проти задоволення цивільного позову. Якими мають бути дії суду?',	'["\u0417''\u044f\u0441\u0443\u0432\u0430\u0432\u0448\u0438 \u0434\u0443\u043c\u043a\u0443 \u0456\u043d\u0448\u0438\u0445 \u0443\u0447\u0430\u0441\u043d\u0438\u043a\u0456\u0432 \u0441\u0443\u0434\u043e\u0432\u043e\u0433\u043e \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f, \u0432\u0456\u0434\u043a\u043b\u0430\u0441\u0442\u0438 \u0441\u0443\u0434\u043e\u0432\u0438\u0439 \u0440\u043e\u0437\u0433\u043b\u044f\u0434.", "\u0417\u0430\u043b\u0438\u0448\u0438\u0442\u0438 \u0446\u0438\u0432\u0456\u043b\u044c\u043d\u0438\u0439 \u043f\u043e\u0437\u043e\u0432 \u0431\u0435\u0437 \u0440\u043e\u0437\u0433\u043b\u044f\u0434\u0443.", "\u041f\u0440\u043e\u0432\u0435\u0441\u0442\u0438 \u0441\u0443\u0434\u043e\u0432\u0438\u0439 \u0440\u043e\u0437\u0433\u043b\u044f\u0434 \u0456 \u0432\u0438\u0440\u0456\u0448\u0438\u0442\u0438 \u0446\u0438\u0432\u0456\u043b\u044c\u043d\u0438\u0439 \u043f\u043e\u0437\u043e\u0432 \u0437\u0430 \u043d\u0430\u044f\u0432\u043d\u0438\u043c\u0438 \u0441\u043f\u0440\u0430\u0432\u0456 \u043c\u0430\u0442\u0435\u0440\u0456\u0430\u043b\u0430\u043c\u0438.", "\u0412\u0456\u0434\u043c\u043e\u0432\u0438\u0442\u0438 \u0432 \u0437\u0430\u0434\u043e\u0432\u043e\u043b\u0435\u043d\u043d\u0456 \u0446\u0438\u0432\u0456\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u043e\u0437\u043e\u0432\u0443."]',	1,	'КРИМІНАЛЬНО-ПРОЦЕСУАЛЬНЕ ПРАВО'),
(90,	'У якому випадку затримання та тримання під вартою можуть застосовуватися до неповнолітнього? Якщо він підозрюється або обвинувачується у вчиненні злочину',	'["\u0441\u0435\u0440\u0435\u0434\u043d\u044c\u043e\u0457 \u0442\u044f\u0436\u043a\u043e\u0441\u0442\u0456, \u0437\u0430 \u0443\u043c\u043e\u0432\u0438, \u0449\u043e \u0437\u0430\u0441\u0442\u043e\u0441\u0443\u0432\u0430\u043d\u043d\u044f \u0456\u043d\u0448\u043e\u0433\u043e \u0437\u0430\u043f\u043e\u0431\u0456\u0436\u043d\u043e\u0433\u043e \u0437\u0430\u0445\u043e\u0434\u0443 \u043d\u0435 \u0437\u0430\u0431\u0435\u0437\u043f\u0435\u0447\u0438\u0442\u044c \u0437\u0430\u043f\u043e\u0431\u0456\u0433\u0430\u043d\u043d\u044f \u0440\u0438\u0437\u0438\u043a\u0430\u043c, \u0437\u0430\u0437\u043d\u0430\u0447\u0435\u043d\u0438\u043c \u0443 \u0441\u0442\u0430\u0442\u0442\u0456 177 \u041a\u041f\u041a \u042f\u043a\u0449\u043e \u0432\u0456\u043d \u043f\u0456\u0434\u043e\u0437\u0440\u044e\u0454\u0442\u044c\u0441\u044f \u0430\u0431\u043e \u043e\u0431\u0432\u0438\u043d\u0443\u0432\u0430\u0447\u0443\u0454\u0442\u044c\u0441\u044f \u0443 \u0432\u0447\u0438\u043d\u0435\u043d\u043d\u0456 \u043e\u0441\u043e\u0431\u043b\u0438\u0432\u043e", "\u0442\u044f\u0436\u043a\u043e\u0433\u043e \u0437\u043b\u043e\u0447\u0438\u043d\u0443, \u0437\u0430 \u0443\u043c\u043e\u0432\u0438, \u0449\u043e \u0437\u0430\u0441\u0442\u043e\u0441\u0443\u0432\u0430\u043d\u043d\u044f \u0456\u043d\u0448\u043e\u0433\u043e \u0437\u0430\u043f\u043e\u0431\u0456\u0436\u043d\u043e\u0433\u043e \u0437\u0430\u0445\u043e\u0434\u0443 \u043d\u0435 \u0437\u0430\u0431\u0435\u0437\u043f\u0435\u0447\u0438\u0442\u044c \u0437\u0430\u043f\u043e\u0431\u0456\u0433\u0430\u043d\u043d\u044f \u0440\u0438\u0437\u0438\u043a\u0430\u043c, \u0437\u0430\u0437\u043d\u0430\u0447\u0435\u043d\u0438\u043c \u0443 \u0441\u0442\u0430\u0442\u0442\u0456 177 \u041a\u041f\u041a \u0423\u043a\u0440\u0430\u0457\u043d\u0438. \u042f\u043a\u0449\u043e \u0432\u0456\u043d \u043f\u0456\u0434\u043e\u0437\u0440\u044e\u0454\u0442\u044c\u0441\u044f \u0430\u0431\u043e \u043e\u0431\u0432\u0438\u043d\u0443\u0432\u0430\u0447\u0443\u0454\u0442\u044c\u0441\u044f \u0443 \u0432\u0447\u0438\u043d\u0435\u043d\u043d\u0456 \u0442\u044f\u0436\u043a\u043e\u0433\u043e \u0447\u0438", "\u043e\u0441\u043e\u0431\u043b\u0438\u0432\u043e \u0442\u044f\u0436\u043a\u043e\u0433\u043e \u0437\u043b\u043e\u0447\u0438\u043d\u0443, \u0437\u0430 \u0443\u043c\u043e\u0432\u0438, \u0449\u043e \u0437\u0430\u0441\u0442\u043e\u0441\u0443\u0432\u0430\u043d\u043d\u044f \u0456\u043d\u0448\u043e\u0433\u043e \u0437\u0430\u043f\u043e\u0431\u0456\u0436\u043d\u043e\u0433\u043e \u0437\u0430\u0445\u043e\u0434\u0443 \u043d\u0435 \u0437\u0430\u0431\u0435\u0437\u043f\u0435\u0447\u0438\u0442\u044c \u0437\u0430\u043f\u043e\u0431\u0456\u0433\u0430\u043d\u043d\u044f \u0440\u0438\u0437\u0438\u043a\u0430\u043c, \u0437\u0430\u0437\u043d\u0430\u0447\u0435\u043d\u0438\u043c \u0443 \u0441\u0442\u0430\u0442\u0442\u0456 177 \u041a\u041f\u041a \u0423\u043a\u0440\u0430\u0457\u043d\u0438.", "\u042f\u043a\u0449\u043e \u0456\u043d\u0448\u0438\u043c \u0441\u043f\u043e\u0441\u043e\u0431\u043e\u043c \u043d\u0435\u043c\u043e\u0436\u043b\u0438\u0432\u043e \u043f\u0440\u0438\u043f\u0438\u043d\u0438\u0442\u0438 \u043f\u0440\u043e\u0442\u0438\u043f\u0440\u0430\u0432\u043d\u0443 \u043f\u043e\u0432\u0435\u0434\u0456\u043d\u043a\u0443 \u043d\u0435\u043f\u043e\u0432\u043d\u043e\u043b\u0456\u0442\u043d\u044c\u043e\u0433\u043e \u043f\u0456\u0434\u043e\u0437\u0440\u044e\u0432\u0430\u043d\u043e\u0433\u043e, \u043e\u0431\u0432\u0438\u043d\u0443\u0432\u0430\u0447\u0435\u043d\u043e\u0433\u043e."]',	2,	'КРИМІНАЛЬНО-ПРОЦЕСУАЛЬНЕ ПРАВО'),
(91,	'Хто здійснює розгляд клопотань щодо негласних слідчих (розшукових) дій, який віднесений до повноважень слідчого судді?',	'["\u0421\u043b\u0456\u0434\u0447\u0438\u043c \u0441\u0443\u0434\u0434\u0435\u044e \u043c\u0456\u0441\u0446\u0435\u0432\u043e\u0433\u043e \u0441\u0443\u0434\u0443 \u0443 \u043c\u0435\u0436\u0430\u0445 \u0442\u0435\u0440\u0438\u0442\u043e\u0440\u0456\u0430\u043b\u044c\u043d\u043e\u0457 \u044e\u0440\u0438\u0441\u0434\u0438\u043a\u0446\u0456\u0457 \u044f\u043a\u043e\u0433\u043e \u0437\u043d\u0430\u0445\u043e\u0434\u0438\u0442\u044c\u0441\u044f \u043e\u0440\u0433\u0430\u043d \u0434\u043e\u0441\u0443\u0434\u043e\u0432\u043e\u0433\u043e \u0440\u043e\u0437\u0441\u043b\u0456\u0434\u0443\u0432\u0430\u043d\u043d\u044f.", "\u0413\u043e\u043b\u043e\u0432\u043e\u044e \u043c\u0456\u0441\u0446\u0435\u0432\u043e\u0433\u043e \u0441\u0443\u0434\u0443, \u0443 \u043c\u0435\u0436\u0430\u0445 \u0442\u0435\u0440\u0438\u0442\u043e\u0440\u0456\u0430\u043b\u044c\u043d\u043e\u0457 \u044e\u0440\u0438\u0441\u0434\u0438\u043a\u0446\u0456\u0457 \u044f\u043a\u043e\u0433\u043e \u0437\u043d\u0430\u0445\u043e\u0434\u0438\u0442\u044c\u0441\u044f \u043e\u0440\u0433\u0430\u043d \u0434\u043e\u0441\u0443\u0434\u043e\u0432\u043e\u0433\u043e \u0440\u043e\u0437\u0441\u043b\u0456\u0434\u0443\u0432\u0430\u043d\u043d\u044f.", "\u0421\u043b\u0456\u0434\u0447\u0438\u043c \u0441\u0443\u0434\u0434\u0435\u044e \u0430\u043f\u0435\u043b\u044f\u0446\u0456\u0439\u043d\u043e\u0433\u043e \u0441\u0443\u0434\u0443, \u0432 \u043c\u0435\u0436\u0430\u0445 \u0442\u0435\u0440\u0438\u0442\u043e\u0440\u0456\u0430\u043b\u044c\u043d\u043e\u0457 \u044e\u0440\u0438\u0441\u0434\u0438\u043a\u0446\u0456\u0457 \u044f\u043a\u043e\u0433\u043e \u0437\u043d\u0430\u0445\u043e\u0434\u0438\u0442\u044c\u0441\u044f \u043e\u0440\u0433\u0430\u043d \u0434\u043e\u0441\u0443\u0434\u043e\u0432\u043e\u0433\u043e \u0440\u043e\u0437\u0441\u043b\u0456\u0434\u0443\u0432\u0430\u043d\u043d\u044f.", "\u041a\u043e\u043b\u0435\u0433\u0456\u0454\u044e \u0443 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u0438\u0445 \u0441\u043f\u0440\u0430\u0432\u0430\u0445 \u0430\u043f\u0435\u043b\u044f\u0446\u0456\u0439\u043d\u043e\u0433\u043e \u0441\u0443\u0434\u0443, \u0443 \u043c\u0435\u0436\u0430\u0445 \u0442\u0435\u0440\u0438\u0442\u043e\u0440\u0456\u0430\u043b\u044c\u043d\u043e\u0457 \u044e\u0440\u0438\u0441\u0434\u0438\u043a\u0446\u0456\u0457 \u044f\u043a\u043e\u0433\u043e \u0437\u043d\u0430\u0445\u043e\u0434\u0438\u0442\u044c\u0441\u044f \u043e\u0440\u0433\u0430\u043d \u0434\u043e\u0441\u0443\u0434\u043e\u0432\u043e\u0433\u043e \u0440\u043e\u0437\u0441\u043b\u0456\u0434\u0443\u0432\u0430\u043d\u043d\u044f."]',	2,	'КРИМІНАЛЬНО-ПРОЦЕСУАЛЬНЕ ПРАВО'),
(109,	'Який характер має Резолюція «Мілітаризація Російською Федерацією тимчасово окупованих Автономної Республіки Крим та міста Севастополя, Україна, Чорного і Азовського морів», прийнята ОБСЄ 2019 року?',	'["\u0414\u043e\u043a\u0443\u043c\u0435\u043d\u0442 soft law.", "\u041e\u0431\u043e\u0432''\u044f\u0437\u043a\u043e\u0432\u0438\u0439 \u044e\u0440\u0438\u0434\u0438\u0447\u043d\u0438\u0439.", "\u0425\u0430\u0440\u0430\u043a\u0442\u0435\u0440 jus cogens.", "\u041d\u0435\u043e\u0431\u043e\u0432''\u044f\u0437\u043a\u043e\u0432\u0438\u0439 \u043f\u043e\u043b\u0456\u0442\u0438\u0447\u043d\u0438\u0439."]',	0,	'МІЖНАРОДНЕ ПУБЛІЧНЕ ПРАВО'),
(92,	'Які ухвали слідчого судді НЕ можуть бути оскаржені в апеляційному порядку під час досудового розслідування ?',	'["\u041f\u0440\u043e \u0432\u0456\u0434\u043c\u043e\u0432\u0443 \u0443 \u043d\u0430\u0434\u0430\u043d\u043d\u0456 \u0434\u043e\u0437\u0432\u043e\u043b\u0443 \u043d\u0430 \u0437\u0430\u0442\u0440\u0438\u043c\u0430\u043d\u043d\u044f.", "\u041f\u0440\u043e \u043f\u043e\u043c\u0456\u0449\u0435\u043d\u043d\u044f \u043e\u0441\u043e\u0431\u0438 \u0432 \u043f\u0440\u0438\u0439\u043c\u0430\u043b\u044c\u043d\u0438\u043a-\u0440\u043e\u0437\u043f\u043e\u0434\u0456\u043b\u044c\u043d\u0438\u043a \u0434\u043b\u044f \u0434\u0456\u0442\u0435\u0439 \u0430\u0431\u043e \u0432\u0456\u0434\u043c\u043e\u0432\u0443 \u0432 \u0442\u0430\u043a\u043e\u043c\u0443 \u043f\u043e\u043c\u0456\u0449\u0435\u043d\u043d\u0456.", "\u041f\u0440\u043e \u0430\u0440\u0435\u0448\u0442 \u043c\u0430\u0439\u043d\u0430 \u0430\u0431\u043e \u0432\u0456\u0434\u043c\u043e\u0432\u0443 \u0443 \u043d\u044c\u043e\u043c\u0443.", "\u041f\u0440\u043e \u043f\u0440\u043e\u0432\u0435\u0434\u0435\u043d\u043d\u044f \u043e\u0431\u0448\u0443\u043a\u0443."]',	3,	'КРИМІНАЛЬНО-ПРОЦЕСУАЛЬНЕ ПРАВО'),
(93,	'Що відповідно до КПК України НЕ є критерієм визначення розумності строку?',	'["\u043d\u0430\u044f\u0432\u043d\u0456\u0441\u0442\u044c \u043e\u0431\u0491\u0440\u0443\u043d\u0442\u043e\u0432\u0430\u043d\u043e\u0457 \u043f\u0456\u0434\u043e\u0437\u0440\u0438 \u0449\u043e\u0434\u043e \u0432\u0447\u0438\u043d\u0435\u043d\u043d\u044f \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u043f\u0456\u0434\u043e\u0437\u0440\u044e\u0432\u0430\u043d\u0438\u043c (\u043e\u0431\u0432\u0438\u043d\u0443\u0432\u0430\u0447\u0435\u043d\u0438\u043c)", "\u043f\u043e\u0432\u0435\u0434\u0456\u043d\u043a\u0430 \u0443\u0447\u0430\u0441\u043d\u0438\u043a\u0456\u0432 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f", "\u0441\u043f\u043e\u0441\u0456\u0431 \u0437\u0434\u0456\u0439\u0441\u043d\u0435\u043d\u043d\u044f \u0441\u043b\u0456\u0434\u0447\u0438\u043c, \u043f\u0440\u043e\u043a\u0443\u0440\u043e\u0440\u043e\u043c \u0456 \u0441\u0443\u0434\u043e\u043c \u0441\u0432\u043e\u0457\u0445 \u043f\u043e\u0432\u043d\u043e\u0432\u0430\u0436\u0435\u043d\u044c", "\u0441\u043a\u043b\u0430\u0434\u043d\u0456\u0441\u0442\u044c \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f"]',	0,	'КРИМІНАЛЬНО-ПРОЦЕСУАЛЬНЕ ПРАВО'),
(94,	'Заявник звернувся до слідчого із заявою про вчинення кримінального правопорушення о 10:00. Через необхідність проведення процесуальних дій в іншому провадженні слідчий вніс відомості до ЄРДР про початок досудового розслідування лише о 20:00. На наступний день заявник в 12:00 звернувся з вимогою про отримання витягу з ЄРДР. Чи зобов''язаний слідчий надати витяг ЄРДР заявнику?',	'["\u041d\u0456, \u0430\u0434\u0436\u0435 \u0432\u0438\u0442\u044f\u0433 \u0437 \u0404\u0420\u0414\u0420 \u043d\u0430\u0434\u0430\u0454\u0442\u044c\u0441\u044f \u043b\u0438\u0448\u0435 \u043f\u043e\u0442\u0435\u0440\u043f\u0456\u043b\u043e\u043c\u0443.", "\u0422\u0430\u043a, \u0432\u0438\u0442\u044f\u0433 \u0437 \u0404\u0420\u0414\u0420 \u043d\u0430\u0434\u0430\u0454\u0442\u044c\u0441\u044f \u043f\u0456\u0441\u043b\u044f 24 \u0433\u043e\u0434\u0438\u043d \u0437 \u043c\u043e\u043c\u0435\u043d\u0442\u0443 \u043f\u043e\u0432\u0456\u0434\u043e\u043c\u043b\u0435\u043d\u043d\u044f \u043f\u0440\u043e \u0432\u0447\u0438\u043d\u0435\u043d\u043d\u044f \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f.", "\u041d\u0456, \u0432\u0438\u0442\u044f\u0433 \u0437 \u0404\u0420\u0414\u0420 \u043d\u0430\u0434\u0430\u0454\u0442\u044c\u0441\u044f \u043f\u0456\u0441\u043b\u044f 24 \u0433\u043e\u0434\u0438\u043d \u0437 \u043c\u043e\u043c\u0435\u043d\u0442\u0443 \u0432\u043d\u0435\u0441\u0435\u043d\u043d\u044f \u0432\u0456\u0434\u043e\u043c\u043e\u0441\u0442\u0435\u0439 \u043f\u0440\u043e \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u0435 \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u0434\u043e \u0404\u0420\u0414\u0420.", "\u041d\u0456, \u0430\u0434\u0436\u0435 \u0432\u0438\u0442\u044f\u0433 \u0437 \u0404\u0420\u0414\u0420 \u043d\u0430\u0434\u0430\u0454\u0442\u044c\u0441\u044f \u043b\u0438\u0448\u0435 \u0432 \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f\u0445 \u043f\u0440\u0438\u0432\u0430\u0442\u043d\u043e\u0433\u043e \u043e\u0431\u0432\u0438\u043d\u0443\u0432\u0430\u0447\u0435\u043d\u043d\u044f."]',	2,	'КРИМІНАЛЬНО-ПРОЦЕСУАЛЬНЕ ПРАВО'),
(95,	'На підставі якої апеляційної скарги може бути скасований виправдувальний вирок, ухвалений судом першої інстанції?',	'["\u041f\u043e\u0434\u0430\u043d\u043e\u0457 \u043f\u0440\u043e\u043a\u0443\u0440\u043e\u0440\u043e\u043c \u0437 \u043c\u043e\u0442\u0438\u0432\u0456\u0432 \u0456 \u043f\u0456\u0434\u0441\u0442\u0430\u0432 \u0432\u0438\u043f\u0440\u0430\u0432\u0434\u0430\u043d\u043d\u044f.", "\u0426\u0438\u0432\u0456\u043b\u044c\u043d\u0438\u043c \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u0447\u0435\u043c \u0430\u0431\u043e \u0439\u043e\u0433\u043e \u043f\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043d\u0438\u043a\u043e\u043c \u0443 \u0447\u0430\u0441\u0442\u0438\u043d\u0456, \u0449\u043e \u0441\u0442\u043e\u0441\u0443\u0454\u0442\u044c\u0441\u044f \u0432\u0438\u0440\u0456\u0448\u0435\u043d\u043d\u044f \u0446\u0438\u0432\u0456\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u043e\u0437\u043e\u0432\u0443.", "\u0426\u0438\u0432\u0456\u043b\u044c\u043d\u0438\u043c \u043f\u043e\u0437\u0438\u0432\u0430\u0447\u0435\u043c, \u0439\u043e\u0433\u043e \u043f\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043d\u0438\u043a\u043e\u043c \u0430\u0431\u043e \u0437\u0430\u043a\u043e\u043d\u043d\u0438\u043c \u043f\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043d\u0438\u043a\u043e\u043c \u0443 \u0447\u0430\u0441\u0442\u0438\u043d\u0456, \u0449\u043e \u0441\u0442\u043e\u0441\u0443\u0454\u0442\u044c\u0441\u044f \u0456\u043d\u0442\u0435\u0440\u0435\u0441\u0456\u0432 \u0446\u0438\u0432\u0456\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u043e\u0437\u0438\u0432\u0430\u0447\u0430.", "\u0417\u0430\u043a\u043e\u043d\u043d\u0438\u043c \u043f\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043d\u0438\u043a\u043e\u043c \u043e\u0431\u0432\u0438\u043d\u0443\u0432\u0430\u0447\u0435\u043d\u043e\u0433\u043e \u0432 \u0456\u043d\u0442\u0435\u0440\u0435\u0441\u0430\u0445 \u043e\u0431\u0432\u0438\u043d\u0443\u0432\u0430\u0447\u0435\u043d\u043e\u0433\u043e."]',	0,	'КРИМІНАЛЬНО-ПРОЦЕСУАЛЬНЕ ПРАВО'),
(96,	'Яким субʼєктом НЕ може бути внесена застава?',	'["\u041a\u043e\u043c\u0443\u043d\u0430\u043b\u044c\u043d\u0438\u043c \u043f\u0456\u0434\u043f\u0440\u0438\u0454\u043c\u0441\u0442\u0432\u043e\u043c.", "\u0420\u043e\u0434\u0438\u0447\u0435\u043c \u043f\u0456\u0434\u043e\u0437\u0440\u044e\u0432\u0430\u043d\u043e\u0433\u043e, \u043e\u0431\u0432\u0438\u043d\u0443\u0432\u0430\u0447\u0435\u043d\u043e\u0433\u043e.", "\u0406\u043d\u043e\u0437\u0435\u043c\u0446\u0435\u043c.", "\u0417\u0430\u0445\u0438\u0441\u043d\u0438\u043a\u043e\u043c."]',	0,	'КРИМІНАЛЬНО-ПРОЦЕСУАЛЬНЕ ПРАВО'),
(97,	'Що з переліченого НЕ віднесено до повноважень суду касаційної інстанції за наслідками розгляду касаційної скарги на вирок суду першої інстанції після його перегляду в суді апеляційної інстанції?',	'["\u0421\u043a\u0430\u0441\u0443\u0432\u0430\u0442\u0438 \u0432\u0438\u0440\u043e\u043a \u0441\u0443\u0434\u0443 \u0439 \u0437\u0430\u043a\u0440\u0438\u0442\u0438 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u0435 \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f.", "\u0421\u043a\u0430\u0441\u0443\u0432\u0430\u0442\u0438 \u0432\u0438\u0440\u043e\u043a \u0441\u0443\u0434\u0443 \u0439 \u043f\u0440\u0438\u0437\u043d\u0430\u0447\u0438\u0442\u0438 \u043d\u043e\u0432\u0438\u0439 \u0440\u043e\u0437\u0433\u043b\u044f\u0434 \u0443 \u0441\u0443\u0434\u0456 \u043f\u0435\u0440\u0448\u043e\u0457 \u0447\u0438 \u0430\u043f\u0435\u043b\u044f\u0446\u0456\u0439\u043d\u043e\u0457 \u0456\u043d\u0441\u0442\u0430\u043d\u0446\u0456\u0457.", "\u0417\u043c\u0456\u043d\u0438\u0442\u0438 \u0432\u0438\u0440\u043e\u043a \u0441\u0443\u0434\u0443.", "\u0421\u043a\u0430\u0441\u0443\u0432\u0430\u0442\u0438 \u0432\u0438\u0440\u043e\u043a \u043f\u043e\u0432\u043d\u0456\u0441\u0442\u044e \u0447\u0438 \u0447\u0430\u0441\u0442\u043a\u043e\u0432\u043e \u0439 \u0443\u0445\u0432\u0430\u043b\u0438\u0442\u0438 \u043d\u043e\u0432\u0438\u0439 \u0432\u0438\u0440\u043e\u043a."]',	3,	'КРИМІНАЛЬНО-ПРОЦЕСУАЛЬНЕ ПРАВО'),
(98,	'Яке рішення має бути прийнято у кримінальному провадженні щодо умисного ухилення від сплати податків, якщо досягнутий податковий компроміс?',	'["\u0417\u0443\u043f\u0438\u043d\u0438\u0442\u0438 \u0434\u043e\u0441\u0443\u0434\u043e\u0432\u0435 \u0440\u043e\u0437\u0441\u043b\u0456\u0434\u0443\u0432\u0430\u043d\u043d\u044f.", "\u0417\u0430\u043a\u0440\u0438\u0442\u0438 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u0435 \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f.", "\u0423\u043a\u043b\u0430\u0441\u0442\u0438 \u0443\u0433\u043e\u0434\u0443 \u043f\u0440\u043e \u0432\u0438\u0437\u043d\u0430\u043d\u043d\u044f \u0432\u0438\u043d\u0438.", "\u0423\u043a\u043b\u0430\u0441\u0442\u0438 \u0443\u0433\u043e\u0434\u0443 \u043f\u0440\u043e \u043f\u0440\u0438\u043c\u0438\u0440\u0435\u043d\u043d\u044f."]',	1,	'КРИМІНАЛЬНО-ПРОЦЕСУАЛЬНЕ ПРАВО'),
(100,	'Під час досудового розслідування прокурором прийнято рішення про складання клопотання про звільнення особи від кримінальної відповідальності у зв''язку із зміною обстановки. Підозрюваний не погоджувався із підставою звільнення та наполягав на звільнені у зв''язку з дійовим каяттям. Захисник суді просив задовольнити клопотання прокурора. Яке рішення повинен ухвалити суд?',	'["\u0412\u0456\u0434\u043c\u043e\u0432\u0438\u0442\u0438 \u0432 \u0437\u0430\u0434\u043e\u0432\u043e\u043b\u0435\u043d\u043d\u0456 \u043a\u043b\u043e\u043f\u043e\u0442\u0430\u043d\u043d\u044f \u0442\u0430 \u043f\u0440\u0438\u0437\u043d\u0430\u0447\u0438\u0442\u0438 \u0441\u0443\u0434\u043e\u0432\u0438\u0439 \u0440\u043e\u0437\u0433\u043b\u044f\u0434 \u043f\u043e \u0441\u0443\u0442\u0456 \u043e\u0431\u0432\u0438\u043d\u0443\u0432\u0430\u0447\u0435\u043d\u043d\u044f.", "\u0417\u0430\u0434\u043e\u0432\u043e\u043b\u044c\u043d\u0438\u0442\u0438 \u043a\u043b\u043e\u043f\u043e\u0442\u0430\u043d\u043d\u044f \u043f\u0440\u043e\u043a\u0443\u0440\u043e\u0440\u0430 \u0442\u0430 \u0437\u0432\u0456\u043b\u044c\u043d\u0438\u0442\u0438 \u043f\u0456\u0434\u043e\u0437\u0440\u044e\u0432\u0430\u043d\u043e\u0433\u043e \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0457 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0456 \u0443 \u0437\u0432''\u044f\u0437\u043a\u0443 \u0456\u0437 \u0437\u043c\u0456\u043d\u043e\u044e \u043e\u0431\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0438.", "\u0417\u0430\u0434\u043e\u0432\u043e\u043b\u044c\u043d\u0438\u0442\u0438 \u043a\u043b\u043e\u043f\u043e\u0442\u0430\u043d\u043d\u044f \u043f\u0456\u0434\u043e\u0437\u0440\u044e\u0432\u0430\u043d\u043e\u0433\u043e \u0442\u0430 \u0437\u0432\u0456\u043b\u044c\u043d\u0438\u0442\u0438 \u0439\u043e\u0433\u043e \u0432\u0456\u0434 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0457 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0456 \u0443 \u0437\u0432''\u044f\u0437\u043a\u0443 \u0437 \u0434\u0456\u0439\u043e\u0432\u0438\u043c \u043a\u0430\u044f\u0442\u0442\u044f\u043c.", "\u0412\u0456\u0434\u043c\u043e\u0432\u0438\u0442\u0438 \u0432 \u0437\u0430\u0434\u043e\u0432\u043e\u043b\u0435\u043d\u043d\u0456 \u043a\u043b\u043e\u043f\u043e\u0442\u0430\u043d\u043d\u044f \u0442\u0430 \u043f\u043e\u0432\u0435\u0440\u043d\u0443\u0442\u0438 \u0439\u043e\u0433\u043e \u043f\u0440\u043e\u043a\u0443\u0440\u043e\u0440\u0443 \u0434\u043b\u044f \u0437\u0434\u0456\u0439\u0441\u043d\u0435\u043d\u043d\u044f \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f \u0432 \u0437\u0430\u0433\u0430\u043b\u044c\u043d\u043e\u043c\u0443 \u043f\u043e\u0440\u044f\u0434\u043a\u0443."]',	3,	'КРИМІНАЛЬНО-ПРОЦЕСУАЛЬНЕ ПРАВО'),
(101,	'Касаційна скарга подана особою, яка не має права подавати таку скаргу. Яке рішення слід прийняти суду у даному випадку?',	'["\u0417\u0430\u043b\u0438\u0448\u0438\u0442\u0438 \u043a\u0430\u0441\u0430\u0446\u0456\u0439\u043d\u0443 \u0441\u043a\u0430\u0440\u0433\u0443 \u0431\u0435\u0437 \u0440\u0443\u0445\u0443.", "\u0412\u0456\u0434\u043c\u043e\u0432\u0438\u0442\u0438 \u0443 \u0432\u0456\u0434\u043a\u0440\u0438\u0442\u0442\u0456 \u043a\u0430\u0441\u0430\u0446\u0456\u0439\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u044f.", "\u0417\u0430\u043b\u0438\u0448\u0438\u0442\u0438 \u043a\u0430\u0441\u0430\u0446\u0456\u0439\u043d\u0443 \u0441\u043a\u0430\u0440\u0433\u0443 \u0431\u0435\u0437 \u0440\u043e\u0437\u0433\u043b\u044f\u0434\u0443.", "\u041f\u043e\u0432\u0435\u0440\u043d\u0443\u0442\u0438 \u043a\u0430\u0441\u0430\u0446\u0456\u0439\u043d\u0443 \u0441\u043a\u0430\u0440\u0433\u0443."]',	3,	'КРИМІНАЛЬНО-ПРОЦЕСУАЛЬНЕ ПРАВО'),
(102,	'За наслідками розгляду апеляційної скарги прокурора суд апеляційної інстанції прийшов до висновку про необхідність скасувати виправдувальний вирок з мотивів істотного порушення прав обвинуваченого. Чи правомірні дії суду?',	'["\u0422\u0430\u043a, \u0441\u0443\u0434 \u0430\u043f\u0435\u043b\u044f\u0446\u0456\u0439\u043d\u043e\u0457 \u0456\u043d\u0441\u0442\u0430\u043d\u0446\u0456\u0457 \u0432\u043f\u0440\u0430\u0432\u0456 \u0441\u043a\u0430\u0441\u0443\u0432\u0430\u0442\u0438 \u0432\u0438\u043f\u0440\u0430\u0432\u0434\u0443\u0432\u0430\u043b\u044c\u043d\u0438\u0439 \u0432\u0438\u0440\u043e\u043a \u0432\u0438\u043a\u043b\u044e\u0447\u043d\u043e \u0437 \u043c\u043e\u0442\u0438\u0432\u0456\u0432 \u0456\u0441\u0442\u043e\u0442\u043d\u043e\u0433\u043e \u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u043f\u0440\u0430\u0432 \u043e\u0431\u0432\u0438\u043d\u0443\u0432\u0430\u0447\u0435\u043d\u043e\u0433\u043e.", "\u041d\u0456, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u043d\u0430 \u0432\u0438\u043f\u0440\u0430\u0432\u0434\u0443\u0432\u0430\u043b\u044c\u043d\u0438\u0439 \u0432\u0438\u0440\u043e\u043a \u0430\u043f\u0435\u043b\u044f\u0446\u0456\u0439\u043d\u0430 \u0441\u043a\u0430\u0440\u0433\u0430 \u0432\u0437\u0430\u0433\u0430\u043b\u0456 \u043c\u043e\u0436\u0435 \u0431\u0443\u0442\u0438 \u043f\u043e\u0434\u0430\u043d\u0430.", "\u041d\u0456, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0441\u0443\u0434 \u0430\u043f\u0435\u043b\u044f\u0446\u0456\u0439\u043d\u043e\u0457 \u0456\u043d\u0441\u0442\u0430\u043d\u0446\u0456 \u043d\u0435 \u0434\u043e\u0441\u043b\u0456\u0434\u0436\u0443\u0454 \u0444\u0430\u043a\u0442 \u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u043f\u0440\u0430\u0432 \u043e\u0431\u0432\u0438\u043d\u0443\u0432\u0430\u0447\u0435\u043d\u043e\u0433\u043e \u043f\u0456\u0434 \u0447\u0430\u0441 \u0441\u0443\u0434\u043e\u0432\u043e\u0433\u043e \u0440\u043e\u0437\u0433\u043b\u044f\u0434\u0443 \u0432 \u0441\u0443\u0434\u0456 \u043f\u0435\u0440\u0448\u043e\u0457 \u0456\u043d\u0441\u0442\u0430\u043d\u0446\u0456\u0457", "\u041d\u0456, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0441\u0443\u0434 \u0430\u043f\u0435\u043b\u044f\u0446\u0456\u0439\u043d\u043e\u0457 \u0456\u043d\u0441\u0442\u0430\u043d\u0446\u0456\u0457 \u043d\u0435 \u0432\u043f\u0440\u0430\u0432\u0456 \u0441\u043a\u0430\u0441\u043e\u0432\u0443\u0432\u0430\u0442\u0438 \u0432\u0438\u043f\u0440\u0430\u0432\u0434\u0443\u0432\u0430\u043b\u044c\u043d\u0438\u0439 \u0432\u0438\u0440\u043e\u043a \u043b\u0438\u0448\u0435 \u0437 \u043c\u043e\u0442\u0438\u0432\u0456\u0432 \u0456\u0441\u0442\u043e\u0442\u043d\u043e\u0433\u043e \u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u043f\u0440\u0430\u0432 \u043e\u0431\u0432\u0438\u043d\u0443\u0432\u0430\u0447\u0435\u043d\u043e\u0433\u043e."]',	3,	'КРИМІНАЛЬНО-ПРОЦЕСУАЛЬНЕ ПРАВО'),
(103,	'Яке з цих тверджень щодо порядку обʼєднання кримінальних проваджень є НЕ правильним ?',	'["\u0412 \u043e\u0434\u043d\u043e\u043c\u0443 \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u0456 \u043c\u043e\u0436\u0443\u0442\u044c \u0431\u0443\u0442\u0438 \u043e\u0431\u2019\u0454\u0434\u043d\u0430\u043d\u0456 \u043c\u0430\u0442\u0435\u0440\u0456\u0430\u043b\u0438 \u0434\u043e\u0441\u0443\u0434\u043e\u0432\u0438\u0445 \u0440\u043e\u0437\u0441\u043b\u0456\u0434\u0443\u0432\u0430\u043d\u044c \u0449\u043e\u0434\u043e \u0434\u0435\u043a\u0456\u043b\u044c\u043a\u043e\u0445 \u043e\u0441\u0456\u0431, \u043f\u0456\u0434\u043e\u0437\u0440\u044e\u0432\u0430\u043d\u0438\u0445 \u0443 \u0432\u0447\u0438\u043d\u0435\u043d\u043d\u0456 \u043e\u0434\u043d\u043e\u0433\u043e \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f.", "\u0412 \u043e\u0434\u043d\u043e\u043c\u0443 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u043c\u0443 \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u0456 \u043c\u043e\u0436\u0443\u0442\u044c \u0431\u0443\u0442\u0438 \u043e\u0431\u2019\u0454\u0434\u043d\u0430\u043d\u0456 \u043c\u0430\u0442\u0435\u0440\u0456\u0430\u043b\u0438 \u0434\u043e\u0441\u0443\u0434\u043e\u0432\u0438\u0445 \u0440\u043e\u0437\u0441\u043b\u0456\u0434\u0443\u0432\u0430\u043d\u044c \u0449\u043e\u0434\u043e \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0441\u0442\u0443\u043f\u043a\u0443 \u0442\u0430 \u0449\u043e\u0434\u043e \u0437\u043b\u043e\u0447\u0438\u043d\u0443, \u0432\u0447\u0438\u043d\u0435\u043d\u0438\u0445 \u043e\u0434\u043d\u0456\u0454\u044e \u043e\u0441\u043e\u0431\u043e\u044e.", "\u0412 \u043e\u0434\u043d\u043e\u043c\u0443 \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u0456 \u043c\u043e\u0436\u0443\u0442\u044c \u0431\u0443\u0442\u0438 \u043e\u0431\u2019\u0454\u0434\u043d\u0430\u043d\u0456 \u043c\u0430\u0442\u0435\u0440\u0456\u0430\u043b\u0438 \u0434\u043e\u0441\u0443\u0434\u043e\u0432\u0438\u0445 \u0440\u043e\u0437\u0441\u043b\u0456\u0434\u0443\u0432\u0430\u043d\u044c \u0449\u043e\u0434\u043e \u043e\u0434\u043d\u0456\u0454\u0457 \u043e\u0441\u043e\u0431\u0438, \u043f\u0456\u0434\u043e\u0437\u0440\u044e\u0432\u0430\u043d\u043e\u0457 \u0443 \u0432\u0447\u0438\u043d\u0435\u043d\u043d\u0456 \u043a\u0456\u043b\u044c\u043a\u043e\u0445 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u0438\u0445 \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u044c. \u0412 \u043e\u0434\u043d\u043e\u043c\u0443 \u043f\u0440\u043e\u0432\u0430\u0434\u0436\u0435\u043d\u043d\u0456 \u043c\u043e\u0436\u0443\u0442\u044c \u0431\u0443\u0442\u0438 \u043e\u0431\u2019\u0454\u0434\u043d\u0430\u043d\u0456 \u043c\u0430\u0442\u0435\u0440\u0456\u0430\u043b\u0438 \u0434\u043e\u0441\u0443\u0434\u043e\u0432\u0438\u0445", "\u0440\u043e\u0437\u0441\u043b\u0456\u0434\u0443\u0432\u0430\u043d\u044c, \u043f\u043e \u044f\u043a\u0438\u0445 \u043d\u0435 \u0432\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u043e \u043f\u0456\u0434\u043e\u0437\u0440\u044e\u0432\u0430\u043d\u0438\u0445, \u043f\u0440\u043e\u0442\u0435 \u0454 \u0434\u043e\u0441\u0442\u0430\u0442\u043d\u0456 \u043f\u0456\u0434\u0441\u0442\u0430\u0432\u0438 \u0432\u0432\u0430\u0436\u0430\u0442\u0438, \u0449\u043e \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u0456 \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f, \u0449\u043e\u0434\u043e \u044f\u043a\u0438\u0445 \u0437\u0434\u0456\u0439\u0441\u043d\u044e\u044e\u0442\u044c\u0441\u044f \u0446\u0456 \u0440\u043e\u0437\u0441\u043b\u0456\u0434\u0443\u0432\u0430\u043d\u043d\u044f, \u0432\u0447\u0438\u043d\u0435\u043d\u0456 \u043e\u0434\u043d\u0456\u0454\u044e \u043e\u0441\u043e\u0431\u043e\u044e (\u043e\u0441\u043e\u0431\u0430\u043c\u0438)."]',	1,	'КРИМІНАЛЬНО-ПРОЦЕСУАЛЬНЕ ПРАВО'),
(104,	'Коли може ініціюватися укладення угоди про примирення?',	'["\u0417 \u043c\u043e\u043c\u0435\u043d\u0442\u0443 \u0432\u043d\u0435\u0441\u0435\u043d\u043d\u044f \u0432\u0456\u0434\u043e\u043c\u043e\u0441\u0442\u0435\u0439 \u043f\u0440\u043e \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u0435 \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u0434\u043e \u0404\u0420\u0414\u0420 \u0442\u0430 \u0434\u043e \u0443\u0445\u0432\u0430\u043b\u0435\u043d\u043d\u044f \u0432\u0438\u0440\u043e\u043a\u0443.", "\u0417 \u043c\u043e\u043c\u0435\u043d\u0442\u0443 \u0437\u0430\u0442\u0440\u0438\u043c\u0430\u043d\u043d\u044f \u043e\u0441\u043e\u0431\u0438 \u0437\u0430 \u043f\u0456\u0434\u043e\u0437\u0440\u043e\u044e \u0443 \u0432\u0447\u0438\u043d\u0435\u043d\u043d\u0456 \u043a\u0440\u0438\u043c\u0456\u043d\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u0434\u043e \u043f\u043e\u0447\u0430\u0442\u043a\u0443 \u0441\u0443\u0434\u043e\u0432\u043e\u0433\u043e \u0440\u043e\u0437\u0433\u043b\u044f\u0434\u0443.", "\u0417 \u043c\u043e\u043c\u0435\u043d\u0442\u0443 \u043f\u043e\u0432\u0456\u0434\u043e\u043c\u043b\u0435\u043d\u043d\u044f \u043e\u0441\u043e\u0431\u0456 \u043f\u0440\u043e \u043f\u0456\u0434\u043e\u0437\u0440\u0443 \u0434\u043e \u0432\u0438\u0445\u043e\u0434\u0443 \u0441\u0443\u0434\u0443 \u0434\u043e \u043d\u0430\u0440\u0430\u0434\u0447\u043e\u0457 \u043a\u0456\u043c\u043d\u0430\u0442\u0438 \u0434\u043b\u044f \u0443\u0445\u0432\u0430\u043b\u0435\u043d\u043d\u044f \u0432\u0438\u0440\u043e\u043a\u0443.", "\u0417 \u043c\u043e\u043c\u0435\u043d\u0442\u0443 \u0441\u043a\u043b\u0430\u0434\u0435\u043d\u043d\u044f \u043e\u0431\u0432\u0438\u043d\u0443\u0432\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0430\u043a\u0442\u0443 \u0434\u043e \u0432\u0438\u0445\u043e\u0434\u0443 \u0441\u0443\u0434\u0443 \u0434\u043b\u044f \u0443\u0445\u0432\u0430\u043b\u0435\u043d\u043d\u044f \u0432\u0438\u0440\u043e\u043a\u0443. \u041f\u0423\u0411\u041b\u0406\u0427\u041d\u0415"]',	2,	'МІЖНАРОДНЕ ПУБЛІЧНЕ ПРАВО'),
(105,	'Яким актом за своєю юридичною природою є Меморандум про гарантії безпеки у зв’язку з приєднанням України до Договору про нерозповсюдження ядерної зброї (5 грудня 1994р.) (Будапештський меморандум)?',	'["\u041c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u0438\u0439 \u0434\u043e\u0433\u043e\u0432\u0456\u0440.", "\u041c\u0435\u043c\u043e\u0440\u0430\u043d\u0434\u0443\u043c \u043f\u0440\u043e \u0432\u0437\u0430\u0454\u043c\u043e\u0440\u043e\u0437\u0443\u043c\u0456\u043d\u043d\u044f.", "\u041f\u0440\u043e\u0442\u043e\u043a\u043e\u043b \u043f\u0440\u043e \u043d\u0430\u043c\u0456\u0440\u0438.", "\u041f\u043e\u043b\u0456\u0442\u0438\u0447\u043d\u0430 \u0443\u0433\u043e\u0434\u0430."]',	0,	'МІЖНАРОДНЕ ПУБЛІЧНЕ ПРАВО'),
(106,	'Які наслідки матиме для держави вчинення її дипломатичним представником дій, що являють собою втручання у внутрішні справи держави перебування?',	'["\u0411\u0443\u0434\u0435 \u043d\u0435\u0441\u0442\u0438 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u0456\u0441\u0442\u044c \u0443 \u0431\u0443\u0434\u044c-\u044f\u043a\u043e\u043c\u0443 \u0432\u0438\u043f\u0430\u0434\u043a\u0443.", "\u0411\u0443\u0434\u0435 \u043d\u0435\u0441\u0442\u0438 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u0456\u0441\u0442\u044c \u043b\u0438\u0448\u0435 \u044f\u043a\u0449\u043e \u0434\u0435\u0440\u0436\u0430\u0432\u0430 \u043f\u0435\u0440\u0435\u0431\u0443\u0432\u0430\u043d\u043d\u044f \u043e\u0433\u043e\u043b\u043e\u0441\u0438\u0442\u044c \u0434\u0438\u043f\u043b\u043e\u043c\u0430\u0442\u0438\u0447\u043d\u043e\u0433\u043e \u043f\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043d\u0438\u043a\u0430 persona non grata.", "\u041d\u0435 \u0431\u0443\u0434\u0435 \u043d\u0435\u0441\u0442\u0438 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0456, \u0442\u0430\u043a \u044f\u043a \u0434\u0438\u043f\u043b\u043e\u043c\u0430\u0442\u0438\u0447\u043d\u0438\u0439 \u043f\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043d\u0438\u043a \u0434\u0456\u044f\u0432 \u0437 \u043f\u0435\u0440\u0435\u0432\u0438\u0449\u0435\u043d\u043d\u044f\u043c \u0441\u0432\u043e\u0457\u0445 \u043f\u043e\u0432\u043d\u043e\u0432\u0430\u0436\u0435\u043d\u044c.", "\u041d\u0435 \u0431\u0443\u0434\u0435 \u043d\u0435\u0441\u0442\u0438 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0456, \u0442\u0430\u043a \u044f\u043a \u0434\u0438\u043f\u043b\u043e\u043c\u0430\u0442\u0438\u0447\u043d\u0438\u0439 \u043f\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043d\u0438\u043a \u043a\u043e\u0440\u0438\u0441\u0442\u0443\u0454\u0442\u044c\u0441\u044f \u0434\u0438\u043f\u043b\u043e\u043c\u0430\u0442\u0438\u0447\u043d\u0438\u043c\u0438 \u0456\u043c\u0443\u043d\u0456\u0442\u0435\u0442\u0430\u043c\u0438"]',	0,	'МІЖНАРОДНЕ ПУБЛІЧНЕ ПРАВО'),
(107,	'Держава спорудила штучний острів на відстані 30 морських миль від свого узбережжя та встановила навколо нього зону безпеки розміром одна морська миля від зовнішнього краю споруди острова. Як кваліфікувати дії держави?',	'["\u0414\u0456\u0457 \u043f\u0440\u0430\u0432\u043e\u043c\u0456\u0440\u043d\u0456, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0434\u0435\u0440\u0436\u0430\u0432\u0430 \u043c\u0430\u0454 \u043f\u0440\u0430\u0432\u043e \u0441\u043f\u043e\u0440\u0443\u0434\u0436\u0443\u0432\u0430\u0442\u0438 \u0448\u0442\u0443\u0447\u043d\u0456 \u043e\u0441\u0442\u0440\u043e\u0432\u0438.", "\u0414\u0456\u0457 \u043f\u0440\u0430\u0432\u043e\u043c\u0456\u0440\u043d\u0456, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0437\u043e\u043d\u0430 \u0431\u0435\u0437\u043f\u0435\u043a\u0438 \u043d\u0435 \u043f\u0435\u0440\u0435\u0432\u0438\u0449\u0443\u0454 12 \u043c\u043e\u0440\u0441\u044c\u043a\u0438\u0445 \u043c\u0438\u043b\u044c.", "\u0414\u0456\u0457 \u043d\u0435\u043f\u0440\u0430\u0432\u043e\u043c\u0456\u0440\u043d\u0456, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0448\u0442\u0443\u0447\u043d\u0456 \u043e\u0441\u0442\u0440\u043e\u0432\u0438 \u043c\u043e\u0436\u043d\u0430 \u0441\u043f\u043e\u0440\u0443\u0434\u0436\u0443\u0432\u0430\u0442\u0438 \u043b\u0438\u0448\u0435 \u0432 \u0442\u0435\u0440\u0438\u0442\u043e\u0440\u0456\u0430\u043b\u044c\u043d\u0438\u0445 \u0432\u043e\u0434\u0430\u0445.", "\u0414\u0456\u0457 \u043d\u0435\u043f\u0440\u0430\u0432\u043e\u043c\u0456\u0440\u043d\u0456, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0434\u0435\u0440\u0436\u0430\u0432\u0430 \u043f\u043e\u0440\u0443\u0448\u0438\u043b\u0430 \u0434\u043e\u043f\u0443\u0441\u0442\u0438\u043c\u0443 \u0448\u0438\u0440\u0438\u043d\u0443 \u0437\u043e\u043d\u0438 \u0431\u0435\u0437\u043f\u0435\u043a\u0438."]',	3,	'МІЖНАРОДНЕ ПУБЛІЧНЕ ПРАВО'),
(108,	'Як називається особлива категорія зобов’язань перед міжнародним співтовариством в цілому, що мають для нього життєво важливе значення і забезпечуються в особливому порядку?',	'["\u0417\u043e\u0431\u043e\u0432\u2019\u044f\u0437\u0430\u043d\u043d\u044f jus cogens.", "\u0417\u043e\u0431\u043e\u0432\u2019\u044f\u0437\u0430\u043d\u043d\u044f erga omnes.", "\u0417\u043e\u0431\u043e\u0432\u2019\u044f\u0437\u0430\u043d\u043d\u044f ex officio.", "\u0417\u043e\u0431\u043e\u0432\u2019\u044f\u0437\u0430\u043d\u043d\u044f in statu nascendi."]',	1,	'МІЖНАРОДНЕ ПУБЛІЧНЕ ПРАВО'),
(110,	'Як за конвенційним міжнародним гуманітарним правом повинна бути кваліфікована окупація, встановлена без застосування військової сили?',	'["\u0417\u0430 \u0431\u0443\u0434\u044c-\u044f\u043a\u0438\u0445 \u0443\u043c\u043e\u0432 \u044f\u043a \u0437\u0431\u0440\u043e\u0439\u043d\u0438\u0439 \u043a\u043e\u043d\u0444\u043b\u0456\u043a\u0442 \u043c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u043e\u0433\u043e \u0445\u0430\u0440\u0430\u043a\u0442\u0435\u0440\u0443", "\u042f\u043a \u0437\u0431\u0440\u043e\u0439\u043d\u0438\u0439 \u043a\u043e\u043d\u0444\u043b\u0456\u043a\u0442 \u043c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u043e\u0433\u043e \u0445\u0430\u0440\u0430\u043a\u0442\u0435\u0440\u0443 \u0437\u0430 \u0434\u043e\u0442\u0440\u0438\u043c\u0430\u043d\u043d\u044f \u0443\u043c\u043e\u0432, \u0432\u0438\u0437\u043d\u0430\u0447\u0435\u043d\u0438\u0445 \u0414\u043e\u0434\u0430\u0442\u043a\u043e\u0432\u0438\u043c \u043f\u0440\u043e\u0442\u043e\u043a\u043e\u043b\u043e\u043c 1 1977 \u0440.", "\u042f\u043a \u0437\u0431\u0440\u043e\u0439\u043d\u0438\u0439 \u043a\u043e\u043d\u0444\u043b\u0456\u043a\u0442 \u043d\u0435\u043c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u043e\u0433\u043e \u0445\u0430\u0440\u0430\u043a\u0442\u0435\u0440\u0443.", "\u042f\u043a \u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u0432\u043d\u0443\u0442\u0440\u0456\u0448\u043d\u044c\u043e\u0433\u043e \u043f\u043e\u0440\u044f\u0434\u043a\u0443 \u0447\u0438 \u0432\u0438\u043d\u0438\u043a\u043d\u0435\u043d\u043d\u044f \u043e\u0431\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0438 \u0432\u043d\u0443\u0442\u0440\u0456\u0448\u043d\u044c\u043e\u0433\u043e \u043d\u0430\u043f\u0440\u0443\u0436\u0435\u043d\u043d\u044f."]',	0,	'МІЖНАРОДНЕ ПУБЛІЧНЕ ПРАВО'),
(111,	'На що НЕ розповсюджується правонаступництво у міжнародному праві?',	'["\u0414\u0435\u0440\u0436\u0430\u0432\u043d\u0443 \u0432\u043b\u0430\u0441\u043d\u0456\u0441\u0442\u044c.", "\u0414\u0435\u0440\u0436\u0430\u0432\u043d\u0456 \u0431\u043e\u0440\u0433\u0438.", "\u0414\u0435\u0440\u0436\u0430\u0432\u043d\u0438\u0439 \u0431\u044e\u0434\u0436\u0435\u0442.", "\u0414\u0435\u0440\u0436\u0430\u0432\u043d\u0456 \u0430\u0440\u0445\u0456\u0432\u0438."]',	2,	'МІЖНАРОДНЕ ПУБЛІЧНЕ ПРАВО'),
(112,	'Положення якого міжнародного договору НЕ потребують імплементації в українському законодавстві?',	'["\u0423\u0433\u043e\u0434\u0430 \u043f\u0440\u043e \u0430\u0441\u043e\u0446\u0456\u0430\u0446\u0456\u044e \u043c\u0456\u0436 \u0423\u043a\u0440\u0430\u0457\u043d\u043e\u044e \u0442\u0430 \u0404\u0421.", "\u041c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u0438\u0439 \u043f\u0430\u043a\u0442 \u043f\u0440\u043e \u0433\u0440\u043e\u043c\u0430\u0434\u044f\u043d\u0441\u044c\u043a\u0456 \u0442\u0430 \u043f\u043e\u043b\u0456\u0442\u0438\u0447\u043d\u0456 \u043f\u0440\u0430\u0432\u0430.", "\u041a\u043e\u043d\u0432\u0435\u043d\u0446\u0456\u044f \u041e\u041e\u041d \u0437 \u043c\u043e\u0440\u0441\u044c\u043a\u043e\u0433\u043e \u043f\u0440\u0430\u0432\u0430.", "\u0421\u0442\u0430\u0442\u0443\u0442 \u0421\u043f\u0456\u0432\u0434\u0440\u0443\u0436\u043d\u043e\u0441\u0442\u0456 \u041d\u0435\u0437\u0430\u043b\u0435\u0436\u043d\u0438\u0445 \u0414\u0435\u0440\u0436\u0430\u0432."]',	3,	'МІЖНАРОДНЕ ПУБЛІЧНЕ ПРАВО'),
(113,	'За якої з перелічених умов застосування контрзаходів потерпілою державою буде правомірним відповідно до міжнародного права?',	'["\u041a\u043e\u043d\u0442\u0440\u0437\u0430\u0445\u043e\u0434\u0438 \u043f\u0440\u043e\u043f\u043e\u0440\u0446\u0456\u0439\u043d\u0456 \u0437\u0430\u043f\u043e\u0434\u0456\u044f\u043d\u0456\u0439 \u0448\u043a\u043e\u0434\u0456.", "\u041a\u043e\u043d\u0442\u0440\u0437\u0430\u0445\u043e\u0434\u0438 \u043d\u043e\u0441\u044f\u0442\u044c \u043f\u0440\u0435\u0432\u0435\u043d\u0442\u0438\u0432\u043d\u0438\u0439 \u0445\u0430\u0440\u0430\u043a\u0442\u0435\u0440.", "\u041a\u043e\u043d\u0442\u0440\u0437\u0430\u0445\u043e\u0434\u0438 \u0437\u0430\u0442\u0432\u0435\u0440\u0434\u0436\u0443\u044e\u0442\u044c\u0441\u044f \u0440\u0456\u0448\u0435\u043d\u043d\u044f\u043c \u0420\u0430\u0434\u0438 \u0411\u0435\u0437\u043f\u0435\u043a\u0438 \u041e\u041e\u041d.", "\u041a\u043e\u043d\u0442\u0440\u0437\u0430\u0445\u043e\u0434\u0438 \u0437\u0430\u0441\u0442\u043e\u0441\u043e\u0432\u0443\u044e\u0442\u044c\u0441\u044f \u0437 \u043c\u0435\u0442\u043e\u044e \u043f\u043e\u043a\u0430\u0440\u0430\u043d\u043d\u044f."]',	0,	'МІЖНАРОДНЕ ПУБЛІЧНЕ ПРАВО'),
(114,	'Держава, яка є стороною у міжнародному збройному конфлікті, має намір застосувати проти супротивника метод ведення бойових дій у відповідності до норм міжнародного гуманітарного права. Який із перелічених методів НЕ є забороненим нормами міжнародного гуманітарного права?',	'["\u041d\u0430\u043f\u0430\u0434 \u043d\u0430 \u043e\u0441\u0456\u0431, \u0449\u043e \u0432\u0438\u0431\u0443\u043b\u0438 \u0437\u0456 \u0441\u0442\u0440\u043e\u044e \u0447\u0435\u0440\u0435\u0437 \u043f\u043e\u0440\u0430\u043d\u0435\u043d\u043d\u044f.", "\u0421\u0438\u043c\u0443\u043b\u044e\u0432\u0430\u043d\u043d\u044f \u043d\u0430\u043c\u0456\u0440\u0443 \u0432\u0435\u0441\u0442\u0438 \u043f\u0435\u0440\u0435\u0433\u043e\u0432\u043e\u0440\u0438.", "\u041d\u0435\u0432\u0438\u0431\u0456\u0440\u043a\u043e\u0432\u0438\u0439 \u043d\u0430\u043f\u0430\u0434.", "\u0412\u0438\u043a\u043e\u0440\u0438\u0441\u0442\u0430\u043d\u043d\u044f \u0434\u0435\u0437\u0456\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0456\u0457."]',	3,	'МІЖНАРОДНЕ ПУБЛІЧНЕ ПРАВО'),
(115,	'У державі А. відбувається збройний конфлікт (ЗК) між урядом й антиурядовими силами, за якого урядові війська витіснили антиурядові сили на територію держави Б. Антиурядові сили почали контролювати частину території держави Б. й здійснювати звідти напади на територію держави А. Який тип збройного конфлікту між державою А. й антиурядовими силами має місце в цій ситуації і чому?',	'["\u0412\u043d\u0443\u0442\u0440\u0456\u0448\u043d\u0456\u0439 \u0417\u041a, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0432\u0456\u043d \u043f\u043e\u0447\u0430\u0432\u0441\u044f \u043d\u0430 \u0442\u0435\u0440\u0438\u0442\u043e\u0440\u0456\u0457 \u0434\u0435\u0440\u0436\u0430\u0432\u0438 \u0410.", "\u0406\u043d\u0442\u0435\u0440\u043d\u0430\u0446\u0456\u043e\u043d\u0430\u043b\u0456\u0437\u043e\u0432\u0430\u043d\u0438\u0439 \u0417\u041a, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0439\u043e\u0433\u043e \u0441\u0442\u043e\u0440\u043e\u043d\u0430\u043c\u0438 \u0454 \u0434\u0435\u0440\u0436\u0430\u0432\u0438 \u0410., \u0411. \u0442\u0430 \u0430\u043d\u0442\u0438\u0443\u0440\u044f\u0434\u043e\u0432\u0456 \u0441\u0438\u043b\u0438.", "\u041c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u0438\u0439 \u0417\u041a, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0437\u0430\u0441\u0442\u043e\u0441\u043e\u0432\u0443\u0454\u0442\u044c\u0441\u044f \u043c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u0435 \u043f\u0440\u0430\u0432\u043e.", "\u041d\u0435\u043c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u0438\u0439 \u0417\u041a, \u043e\u0441\u043a\u0456\u043b\u044c\u043a\u0438 \u0439\u043e\u0433\u043e \u0443\u0447\u0430\u0441\u043d\u0438\u043a\u0430\u043c\u0438 \u0454 \u0434\u0435\u0440\u0436\u0430\u0432\u0430 \u0410 \u0442\u0430 \u0430\u043d\u0442\u0438\u0443\u0440\u044f\u0434\u043e\u0432\u0456 \u0441\u0438\u043b\u0438."]',	3,	'МІЖНАРОДНЕ ПУБЛІЧНЕ ПРАВО'),
(116,	'Верховний Суд Держави Х. у своїй постанові зазначив таке: «Міжнародне право є за своєю суттю міждержавним, тоді як внутрішнє право держави регулює відносини між особами, що перебувають під юрисдикцією, між собою та із державою. Жодна з цих правових систем не може напряму створювати або змінювати норми іншої. Застосування норми міжнародного права судами держави можливе лише за умови, що це передбачено нормою національної правової системи». Якій теорії співвідношення міжнародного та національного права відповідає така позиція Верховного суду?',	'["\u041f\u043b\u044e\u0440\u0430\u043b\u0456\u0441\u0442\u0438\u0447\u043d\u0456\u0439.", "\u0414\u0443\u0430\u043b\u0456\u0441\u0442\u0438\u0447\u043d\u0456\u0439.", "\u041c\u043e\u043d\u0456\u0441\u0442\u0438\u0447\u043d\u0456\u0439.", "\u041a\u043e\u043e\u0440\u0434\u0438\u043d\u0430\u0446\u0456\u0439\u043d\u0438\u0439."]',	1,	'МІЖНАРОДНЕ ПУБЛІЧНЕ ПРАВО'),
(117,	'Держава А. постійний член Ради Безпеки ООН. У неї існує спір1 і спірна ситуація з державою Б. Якою за Статутом ООН має бути участь держави А. в голосуванні щодо обох питань у Раді Безпеки ООН?',	'["\u0412 \u043e\u0431\u043e\u0445 \u0432\u0438\u043f\u0430\u0434\u043a\u0430\u0445 \u043c\u0430\u0454 \u0443\u0442\u0440\u0438\u043c\u0430\u0442\u0438\u0441\u044f \u0432\u0456\u0434 \u0433\u043e\u043b\u043e\u0441\u0443\u0432\u0430\u043d\u043d\u044f.", "\u0423 \u0432\u0438\u043f\u0430\u0434\u043a\u0443 \u0441\u043f\u0456\u0440\u043d\u043e\u0457 \u0441\u0438\u0442\u0443\u0430\u0446\u0456\u0457 \u043c\u0430\u0454 \u0443\u0442\u0440\u0438\u043c\u0430\u0442\u0438\u0441\u044f \u0432\u0456\u0434 \u0433\u043e\u043b\u043e\u0441\u0443\u0432\u0430\u043d\u043d\u044f.", "\u0423 \u0432\u0438\u043f\u0430\u0434\u043a\u0443 \u0441\u043f\u043e\u0440\u0443 \u043c\u0430\u0454 \u0443\u0442\u0440\u0438\u043c\u0430\u0442\u0438\u0441\u044f \u0432\u0456\u0434 \u0433\u043e\u043b\u043e\u0441\u0443\u0432\u0430\u043d\u043d\u044f.", "\u0412 \u043e\u0431\u043e\u0445 \u0432\u0438\u043f\u0430\u0434\u043a\u0430\u0445 \u043c\u043e\u0436\u0435 \u0433\u043e\u043b\u043e\u0441\u0443\u0432\u0430\u0442\u0438."]',	2,	'МІЖНАРОДНЕ ПУБЛІЧНЕ ПРАВО'),
(118,	'Як називається документ держави перебування, який допускає главу консульської установи до виконання своїх функцій?',	'["\u0410\u0433\u0440\u0435\u043c\u0430\u043d.", "\u041f\u0430\u0442\u0435\u043d\u0442.", "\u0415\u043a\u0437\u0435\u043a\u0432\u0430\u0442\u0443\u0440\u0430.", "\u0406\u043d\u0434\u0443\u043b\u044c\u0433\u0435\u043d\u0446\u0456\u044f."]',	2,	'МІЖНАРОДНЕ ПУБЛІЧНЕ ПРАВО'),
(119,	'У державі А. сталася аварія на сталеливарному заводі, унаслідок чого отруйні речовини потрапили до транскордонного водотоку й спричинили неможливість використання цих вод у державі Б. Це спричинило потребу очищення їх і знезараження державою Б. Як кваліфікується ця ситуація за міжнародно-правовою відповідальністю (МПВ)?',	'["\u041d\u0435\u043c\u0430\u0454 \u041c\u041f\u0412 \u0432\u043d\u0430\u0441\u043b\u0456\u0434\u043e\u043a \u043b\u0438\u0445\u0430.", "\u041d\u0435\u043c\u0430\u0454 \u041c\u041f\u0412 \u0432\u043d\u0430\u0441\u043b\u0456\u0434\u043e\u043a \u0444\u043e\u0440\u0441-\u043c\u0430\u0436\u043e\u0440\u0443.", "\u041d\u0430\u0441\u0442\u0430\u043d\u043d\u044f \u041c\u041f\u0412 \u0437\u0430 \u043f\u0440\u0430\u0432\u043e\u043c\u0456\u0440\u043d\u0443 \u0434\u0456\u044f\u043b\u044c\u043d\u0456\u0441\u0442\u044c.", "\u041d\u0430\u0441\u0442\u0430\u043d\u043d\u044f \u041c\u041f\u0412 \u0437\u0430 \u043c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u043e-\u043f\u0440\u043e\u0442\u0438\u043f\u0440\u0430\u0432\u043d\u0443 \u0434\u0456\u044f\u043b\u044c\u043d\u0456\u0441\u0442\u044c."]',	2,	'МІЖНАРОДНЕ ПУБЛІЧНЕ ПРАВО'),
(120,	'Під час офіційного прийому військовий держави А. застрелив посла держави Б. що намагався вбити ножем присутніх на прийомі. Якою є кваліфікація ситуації для держави А. з погляду настання міжнародно-правової відповідальності?',	'["\u0421\u0442\u0430\u043d \u043b\u0438\u0445\u0430, \u0449\u043e \u0432\u0438\u043a\u043b\u044e\u0447\u0430\u0454 \u043c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u043e-\u043f\u0440\u0430\u0432\u043e\u0432\u0443 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u0456\u0441\u0442\u044c.", "\u041c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u043e-\u043f\u0440\u043e\u0442\u0438\u043f\u0440\u0430\u0432\u043d\u0435 \u0434\u0456\u044f\u043d\u043d\u044f, \u0449\u043e \u043f\u0435\u0440\u0435\u0434\u0431\u0430\u0447\u0430\u0454 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u0456\u0441\u0442\u044c.", "\u0421\u0430\u043c\u043e\u043e\u0431\u043e\u0440\u043e\u043d\u0430, \u0449\u043e \u0432\u0438\u043a\u043b\u044e\u0447\u0430\u0454 \u043c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u043e-\u043f\u0440\u0430\u0432\u043e\u0432\u0443 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u0456\u0441\u0442\u044c.", "\u041c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u043e-\u043f\u0440\u0430\u0432\u043e\u0432\u0430 \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u0456\u0441\u0442\u044c \u0437\u0430 \u0434\u0456\u0457, \u0449\u043e \u043d\u0435 \u0437\u0430\u0431\u043e\u0440\u043e\u043d\u0435\u043d\u0456 \u043c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u0438\u043c \u043f\u0440\u0430\u0432\u043e\u043c."]',	0,	'МІЖНАРОДНЕ ПУБЛІЧНЕ ПРАВО'),
(133,	'На якому принципі ґрунтується позиція Європейського суду прав людини про те, що він НЕ є судом четвертої інстанції?',	'["\u0412\u0435\u0440\u0445\u043e\u0432\u0435\u043d\u0441\u0442\u0432\u0430 \u043f\u0440\u0430\u0432\u0430.", "\u0406\u043d\u0441\u0442\u0430\u043d\u0446\u0456\u0439\u043d\u043e\u0441\u0442\u0456 \u0441\u0443\u0434\u043e\u0432\u043e\u0457 \u0441\u0438\u0441\u0442\u0435\u043c\u0438.", "\u0421\u0443\u0431\u0441\u0438\u0434\u0456\u0430\u0440\u043d\u043e\u0441\u0442\u0456.", "\u041d\u0435\u043e\u0431\u0445\u0456\u0434\u043d\u043e\u0441\u0442\u0456 \u0432 \u0434\u0435\u043c\u043e\u043a\u0440\u0430\u0442\u0438\u0447\u043d\u043e\u043c\u0443 \u0441\u0443\u0441\u043f\u0456\u043b\u044c\u0441\u0442\u0432\u0456."]',	2,	'МІЖНАРОДНИЙ ЗАХИСТ ПРАВ ЛЮДИНИ'),
(121,	'Чия поведінка розглядається як діяння держави, за яке вона нестиме міжнародно-правову відповідальність?',	'["\u041f\u043e\u0441\u0430\u0434\u043e\u0432\u0438\u0445 \u043e\u0441\u0456\u0431 \u0434\u0435\u0440\u0436\u0430\u0432\u0438, \u044f\u043a\u0449\u043e \u0432\u043e\u043d\u0438 \u0434\u0456\u044f\u043b\u0438 \u0432\u0438\u043a\u043b\u044e\u0447\u043d\u043e \u0432 \u043c\u0435\u0436\u0430\u0445 \u043f\u043e\u0432\u043d\u043e\u0432\u0430\u0436\u0435\u043d\u044c \u0437\u0430 \u043f\u043e\u0441\u0430\u0434\u043e\u044e.", "\u0411\u0443\u0434\u044c-\u044f\u043a\u043e\u0433\u043e \u043e\u0440\u0433\u0430\u043d\u0443 \u0434\u0435\u0440\u0436\u0430\u0432\u0438, \u043d\u0430\u0432\u0456\u0442\u044c \u044f\u043a\u0449\u043e \u043f\u0435\u0440\u0435\u0432\u0438\u0449\u0435\u043d\u043e \u043f\u043e\u0432\u043d\u043e\u0432\u0430\u0436\u0435\u043d\u043d\u044f \u0430\u0431\u043e \u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043e \u0456\u043d\u0441\u0442\u0440\u0443\u043a\u0446\u0456\u0457.", "\u041e\u0440\u0433\u0430\u043d\u0456\u0432 \u0437\u0430\u043a\u043e\u043d\u043e\u0434\u0430\u0432\u0447\u043e\u0457 \u0442\u0430 \u0432\u0438\u043a\u043e\u043d\u0430\u0432\u0447\u043e\u0457 \u0432\u043b\u0430\u0434\u0438 \u0434\u0435\u0440\u0436\u0430\u0432\u0438.", "\u0426\u0435\u043d\u0442\u0440\u0430\u043b\u044c\u043d\u0438\u0445 \u043e\u0440\u0433\u0430\u043d\u0456\u0432 \u0434\u0435\u0440\u0436\u0430\u0432\u0438, \u0432\u0438\u043a\u043b\u044e\u0447\u043d\u043e \u044f\u043a\u0449\u043e \u043d\u0435 \u043f\u0435\u0440\u0435\u0432\u0438\u0449\u0435\u043d\u043e \u043f\u043e\u0432\u043d\u043e\u0432\u0430\u0436\u0435\u043d\u044c \u0430\u0431\u043e \u043d\u0435 \u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043e \u0456\u043d\u0441\u0442\u0440\u0443\u043a\u0446\u0456\u0439."]',	1,	'МІЖНАРОДНЕ ПУБЛІЧНЕ ПРАВО'),
(122,	'Після проголошення незалежності держава А. визнала міжнародні кордони держави В. відповідно до принципу uti possidetis. Через 5 років держава А. предʼявила територіальні претензії державі В. пославшись на те, що принцип uti possidetis щодо її кордонів не діє. Яку концепцію міжнародного права порушує держава А.?',	'["\u0414\u0430\u0432\u043d\u043e\u0441\u0442\u0456 \u0432\u043e\u043b\u043e\u0434\u0456\u043d\u043d\u044f.", "\u0415\u0441\u0442\u043e\u043f\u0435\u043b\u044f.", "\u0427\u0438\u0441\u0442\u043e\u0457 \u0434\u043e\u0448\u043a\u0438.", "\u041a\u043e\u043d\u0442\u0438\u043d\u0443\u0457\u0442\u0435\u0442\u0443. \u0417\u0410\u0425\u0418\u0421\u0422 \u041f\u0420\u0410\u0412 \u041b\u042e\u0414\u0418\u041d\u0418"]',	1,	'МІЖНАРОДНИЙ ЗАХИСТ ПРАВ ЛЮДИНИ'),
(123,	'Які з перелічених прав, що захищаються Конвенцією по захист1 прав людини і основоположних свобод, НЕ підлягають жодним обмеженням і НЕ допускають жодних винятків?',	'["\u041f\u0440\u0430\u0432\u043e \u043d\u0430 \u0436\u0438\u0442\u0442\u044f.", "\u041f\u0440\u0430\u0432\u043e \u043d\u0430 \u0432\u0438\u0440\u0430\u0436\u0435\u043d\u043d\u044f \u0441\u0432\u043e\u0457\u0445 \u043f\u043e\u0433\u043b\u044f\u0434\u0456\u0432.", "\u0417\u0430\u0431\u043e\u0440\u043e\u043d\u0430 \u043d\u0435\u043b\u044e\u0434\u0441\u044c\u043a\u043e\u0433\u043e \u043f\u043e\u0432\u043e\u0434\u0436\u0435\u043d\u043d\u044f.", "\u041f\u0440\u0430\u0432\u043e \u043d\u0430 \u0441\u0432\u043e\u0431\u043e\u0434\u0443 \u0442\u0430 \u043e\u0441\u043e\u0431\u0438\u0441\u0442\u0443 \u043d\u0435\u0434\u043e\u0442\u043e\u0440\u043a\u0430\u043d\u0456\u0441\u0442\u044c."]',	2,	'МІЖНАРОДНИЙ ЗАХИСТ ПРАВ ЛЮДИНИ'),
(124,	'Скарга якого з наведених суб’єктів проти України є неприйнятною у Європейському Суді з прав людини?',	'["\u0456\u043d\u043e\u0437\u0435\u043c\u0446\u044f, \u0449\u043e \u043d\u0435\u0437\u0430\u043a\u043e\u043d\u043d\u043e \u043f\u0440\u043e\u0436\u0438\u0432\u0430\u0454 \u0432 \u0423\u043a\u0440\u0430\u0457\u043d\u0456", "\u0456\u043d\u0448\u043e\u0457 \u0414\u043e\u0433\u043e\u0432\u0456\u0440\u043d\u043e\u0457 \u0441\u0442\u043e\u0440\u043e\u043d\u0438 \u041a\u043e\u043d\u0432\u0435\u043d\u0446\u0456\u0457", "\u0432\u0441\u0435\u0443\u043a\u0440\u0430\u0457\u043d\u0441\u044c\u043a\u043e\u0457 \u043f\u0440\u043e\u0444\u0435\u0441\u0456\u0439\u043d\u043e\u0457 \u0441\u043f\u0456\u043b\u043a\u0438", "\u0434\u0435\u0440\u0436\u0430\u0432\u043d\u043e\u0433\u043e \u043f\u0456\u0434\u043f\u0440\u0438\u0454\u043c\u0441\u0442\u0432\u0430"]',	3,	'МІЖНАРОДНИЙ ЗАХИСТ ПРАВ ЛЮДИНИ'),
(125,	'У яких випадках застосування смертної кари НЕ є порушенням1 ст. 2 «Право на життя» Конвенції про захист прав людини і основоположних свобод та Протоколів 6 і 13 до неї?',	'["\u0443 \u0432\u0438\u043f\u0430\u0434\u043a\u0443 \u0432\u0438\u043d\u0435\u0441\u0435\u043d\u043d\u044f \u0441\u0443\u0434\u043e\u043c \u0441\u043c\u0435\u0440\u0442\u043d\u043e\u0433\u043e \u0432\u0438\u0440\u043e\u043a\u0443 \u0437\u0430 \u0432\u0447\u0438\u043d\u0435\u043d\u043d\u044f \u0437\u043b\u043e\u0447\u0438\u043d\u0443, \u0437\u0430 \u044f\u043a\u0438\u0439 \u043f\u0435\u0440\u0435\u0434\u0431\u0430\u0447\u0435\u043d\u043e \u0442\u0430\u043a\u0438\u0439 \u0432\u0438\u0434 \u043f\u043e\u043a\u0430\u0440\u0430\u043d\u043d\u044f.", "\u0443 \u0432\u0438\u043f\u0430\u0434\u043a\u0443 \u0432\u0456\u0434\u0441\u0442\u0443\u043f\u0443 \u0432\u0456\u0434 \u0437\u043e\u0431\u043e\u0432\u02bc\u044f\u0437\u0430\u043d\u044c \u043f\u0456\u0434 \u0447\u0430\u0441 \u0432\u0456\u0439\u043d\u0438 \u0430\u0431\u043e \u0456\u043d\u0448\u043e\u0457 \u0441\u0443\u0441\u043f\u0456\u043b\u044c\u043d\u043e\u0457 \u043d\u0435\u0431\u0435\u0437\u043f\u0435\u043a\u0438, \u044f\u043a\u0430 \u0437\u0430\u0433\u0440\u043e\u0436\u0443\u0454 \u0436\u0438\u0442\u0442\u044e \u043d\u0430\u0446\u0456\u0457,", "\u0437 \u0443\u0440\u0430\u0445\u0443\u0432\u0430\u043d\u043d\u044f\u043c \u043f\u0440\u043e\u0442\u043e\u043a\u043e\u043b\u0456\u0432 6 \u0442\u0430 13, \u0437\u0430\u0441\u0442\u043e\u0441\u0443\u0432\u0430\u043d\u043d\u044f \u0441\u043c\u0435\u0440\u0442\u043d\u043e\u0457 \u043a\u0430\u0440\u0438 \u0454 \u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f\u043c \u0441\u0442. 2 \u0443 \u0431\u0443\u0434\u044c-\u044f\u043a\u043e\u043c\u0443 \u0432\u0438\u043f\u0430\u0434\u043a\u0443.", "\u0443 \u0432\u0438\u043f\u0430\u0434\u043a\u0443 \u0437\u0430\u0441\u0443\u0434\u0436\u0435\u043d\u043d\u044f \u043e\u0441\u043e\u0431\u0438 \u0437\u0430 \u0437\u043b\u043e\u0447\u0438\u043d\u0438 \u043f\u0440\u043e\u0442\u0438 \u043c\u0438\u0440\u0443, \u0431\u0435\u0437\u043f\u0435\u043a\u0438 \u043b\u044e\u0434\u0441\u0442\u0432\u0430 \u0442\u0430 \u043c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u043e\u0433\u043e \u043f\u0440\u0430\u0432\u043e\u043f\u043e\u0440\u044f\u0434\u043a\u0443."]',	2,	'МІЖНАРОДНИЙ ЗАХИСТ ПРАВ ЛЮДИНИ'),
(126,	'Яка з наведених цілей НЕ може бути легітимною метою обмеження права на свободу мирних зібрань згідно зі статтею 11 Конвенції про захист прав людини і основоположних свобод?',	'["\u041e\u0445\u043e\u0440\u043e\u043d\u0430 \u0437\u0434\u043e\u0440\u043e\u0432\u2019\u044f \u0442\u0430 \u043c\u043e\u0440\u0430\u043b\u0456.", "\u041f\u0456\u0434\u0442\u0440\u0438\u043c\u0430\u043d\u043d\u044f \u0430\u0432\u0442\u043e\u0440\u0438\u0442\u0435\u0442\u0443 \u0442\u0430 \u0431\u0435\u0437\u0441\u0442\u043e\u0440\u043e\u043d\u043d\u043e\u0441\u0442\u0456 \u0441\u0443\u0434\u0443.", "\u0417\u0430\u0445\u0438\u0441\u0442 \u043f\u0440\u0430\u0432 \u0442\u0430 \u0441\u0432\u043e\u0431\u043e\u0434 \u0456\u043d\u0448\u0438\u0445 \u043b\u044e\u0434\u0435\u0439.", "\u041d\u0430\u0446\u0456\u043e\u043d\u0430\u043b\u044c\u043d\u0430 \u0430\u0431\u043e \u0433\u0440\u043e\u043c\u0430\u0434\u0441\u044c\u043a\u0430 \u0431\u0435\u0437\u043f\u0435\u043a\u0430."]',	1,	'МІЖНАРОДНИЙ ЗАХИСТ ПРАВ ЛЮДИНИ'),
(127,	'Що з наведеного, згідно українського законодавства, НЕ є способом відновлення попереднього юридичного стану особи, щодо якої Європейським судом з прав людини встановлено порушення Конвенції про захист прав людини і основоположних свобод?',	'["\u0432\u0438\u043f\u043b\u0430\u0442\u0430 \u0432\u0456\u0434\u0448\u043a\u043e\u0434\u0443\u0432\u0430\u043d\u043d\u044f \u0432\u0438\u0442\u0440\u0430\u0442 \u043d\u0430 \u043f\u0440\u0430\u0432\u043e\u0432\u0443 \u0434\u043e\u043f\u043e\u043c\u043e\u0433\u0443;", "\u043f\u043e\u0432\u0442\u043e\u0440\u043d\u0438\u0439 \u0440\u043e\u0437\u0433\u043b\u044f\u0434 \u0441\u043f\u0440\u0430\u0432\u0438 \u0430\u0434\u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0430\u0442\u0438\u0432\u043d\u0438\u043c \u043e\u0440\u0433\u0430\u043d\u043e\u043c;", "\u043f\u0440\u0438\u0442\u044f\u0433\u043d\u0435\u043d\u043d\u044f \u0434\u043e \u0432\u0456\u0434\u043f\u043e\u0432\u0456\u0434\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u0456 \u043e\u0441\u0456\u0431, \u0447\u0438\u0457 \u0434\u0456\u0457 \u0441\u043f\u0440\u0438\u0447\u0438\u043d\u0438\u043b\u0438 \u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u043f\u0440\u0430\u0432;", "\u0432\u043d\u0435\u0441\u0435\u043d\u043d\u044f \u0437\u043c\u0456\u043d \u0434\u043e \u0447\u0438\u043d\u043d\u043e\u0433\u043e \u0437\u0430\u043a\u043e\u043d\u043e\u0434\u0430\u0432\u0441\u0442\u0432\u0430 \u0442\u0430 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0438 \u0439\u043e\u0433\u043e \u0437\u0430\u0441\u0442\u043e\u0441\u0443\u0432\u0430\u043d\u043d\u044f."]',	3,	'МІЖНАРОДНИЙ ЗАХИСТ ПРАВ ЛЮДИНИ'),
(128,	'Відповідно до тлумачень ст. 10 Конвенції про захист прав людини та основоположних свобод Європейським судом з прав людини, яка з названих категорій осіб має найнижчий рівень захисту від критики чи висловлювання оцінок та суджень про неї, які вона вважає критичними?',	'["\u043f\u0440\u043e\u043a\u0443\u0440\u043e\u0440 \u043c\u0456\u0441\u0442\u0430;", "\u043c\u0456\u043d\u0456\u0441\u0442\u0440 \u041a\u0430\u0431\u0456\u043d\u0435\u0442\u0443 \u043c\u0456\u043d\u0456\u0441\u0442\u0440\u0456\u0432;", "\u0437\u0432\u0438\u0447\u0430\u0439\u043d\u0438\u0439 \u0433\u0440\u043e\u043c\u0430\u0434\u044f\u043d\u0438\u043d;", "\u0436\u0443\u0440\u043d\u0430\u043b\u0456\u0441\u0442."]',	1,	'МІЖНАРОДНИЙ ЗАХИСТ ПРАВ ЛЮДИНИ'),
(129,	'З якого моменту набуває чинності для України Конвенція про захист прав людини і основоположних свобод (визначте загальний принцип)?',	'["\u0417 \u0434\u0430\u0442\u0438 \u0457\u0457 \u043f\u0456\u0434\u043f\u0438\u0441\u0430\u043d\u043d\u044f.", "\u0417 \u0434\u0430\u0442\u0438 \u0457\u0457 \u0440\u0430\u0442\u0438\u0444\u0456\u043a\u0430\u0446\u0456\u0457.", "\u0417 \u0434\u0430\u0442\u0438 \u0434\u0435\u043f\u043e\u043d\u0443\u0432\u0430\u043d\u043d\u044f \u0440\u0430\u0442\u0438\u0444\u0456\u043a\u0430\u0446\u0456\u0439\u043d\u043e\u0457 \u0433\u0440\u0430\u043c\u043e\u0442\u0438 \u0432 \u0420\u0430\u0434\u0456 \u0404\u0432\u0440\u043e\u043f\u0438.", "\u0417 \u0434\u0430\u0442\u0438 \u043e\u0442\u0440\u0438\u043c\u0430\u043d\u043d\u044f \u043f\u0435\u0440\u0448\u043e\u0457 \u0441\u043a\u0430\u0440\u0433\u0438 \u0434\u043e \u0404\u0432\u0440\u043e\u043f\u0435\u0439\u0441\u044c\u043a\u043e\u0433\u043e \u0421\u0443\u0434\u0443 \u0437 \u043f\u0440\u0430\u0432 \u043b\u044e\u0434\u0438\u043d\u0438."]',	2,	'МІЖНАРОДНИЙ ЗАХИСТ ПРАВ ЛЮДИНИ'),
(130,	'Який орган був створений на підставі Факультативного протоколу до Конвенції проти катувань та інших жорстоких, нелюдських або таких, що принижують гідність, видів поводження та покарання?',	'["\u041a\u043e\u043c\u0456\u0442\u0435\u0442 \u043f\u0440\u043e\u0442\u0438 \u043a\u0430\u0442\u0443\u0432\u0430\u043d\u044c.", "\u041f\u0456\u0434\u043a\u043e\u043c\u0456\u0442\u0435\u0442 \u0437 \u043d\u0435\u0434\u043e\u043f\u0443\u0449\u0435\u043d\u043d\u044f \u043a\u0430\u0442\u0443\u0432\u0430\u043d\u044c.", "\u041a\u043e\u043c\u0456\u0441\u0456\u044f \u0437 \u043d\u0435\u0434\u043e\u043f\u0443\u0449\u0435\u043d\u043d\u044f \u043a\u0430\u0442\u0443\u0432\u0430\u043d\u044c.", "\u0423\u043f\u0440\u0430\u0432\u043b\u0456\u043d\u043d\u044f \u043d\u0435\u0434\u043e\u043f\u0443\u0449\u0435\u043d\u043d\u044f \u043a\u0430\u0442\u0443\u0432\u0430\u043d\u044c."]',	1,	'МІЖНАРОДНИЙ ЗАХИСТ ПРАВ ЛЮДИНИ'),
(131,	'було порушено кримінальне провадження щодо згаданого вчителя. Заявниця також звернулася до поліції й надала свідчення про епізоди сексуального насильства відносно неї. Відтак заявницю було направлено до безкоштовного психолога, який допоміг їй подолати результати психологічної травми. Слідство було проведено оперативно, учитель, який здійснював домагання, нині відбуває покарання у вигляді позбавлення волі.',	'["\u041f\u043e\u0440\u0443\u0448\u0435\u043d\u043e \u043f\u043e\u0437\u0438\u0442\u0438\u0432\u043d\u0456 \u0437\u043e\u0431\u043e\u0432''\u044f\u0437\u0430\u043d\u043d\u044f \u0434\u0435\u0440\u0436\u0430\u0432\u0438 \u0437\u0430 \u0441\u0442\u0430\u0442\u0442\u0435\u044e 3 \u041a\u043e\u043d\u0432\u0435\u043d\u0446\u0456\u0457 \u0443 \u043c\u0430\u0442\u0435\u0440\u0456\u0430\u043b\u044c\u043d\u043e\u043c\u0443 \u0430\u0441\u043f\u0435\u043a\u0442\u0456.", "\u041f\u043e\u0440\u0443\u0448\u0435\u043d\u043e \u043d\u0435\u0433\u0430\u0442\u0438\u0432\u043d\u0456 \u0437\u043e\u0431\u043e\u0432''\u044f\u0437\u0430\u043d\u043d\u044f \u0434\u0435\u0440\u0436\u0430\u0432\u0438 \u0437\u0430 \u0441\u0442\u0430\u0442\u0442\u0435\u044e 3 \u041a\u043e\u043d\u0432\u0435\u043d\u0446\u0456\u0457.", "\u041f\u043e\u0440\u0443\u0448\u0435\u043d\u043e \u043f\u043e\u0437\u0438\u0442\u0438\u0432\u043d\u0456 \u0437\u043e\u0431\u043e\u0432''\u044f\u0437\u0430\u043d\u043d\u044f \u0434\u0435\u0440\u0436\u0430\u0432\u0438 \u0437\u0430 \u0441\u0442\u0430\u0442\u0442\u0435\u044e 3 \u041a\u043e\u043d\u0432\u0435\u043d\u0446\u0456\u0457 \u043f\u0440\u043e\u0446\u0435\u0434\u0443\u0440\u043d\u043e\u043c\u0443 \u0430\u0441\u043f\u0435\u043a\u0442\u0456.", "\u041f\u043e\u0440\u0443\u0448\u0435\u043d\u043e \u043f\u043e\u0437\u0438\u0442\u0438\u0432\u043d\u0456 \u0437\u043e\u0431\u043e\u0432''\u044f\u0437\u0430\u043d\u043d\u044f \u0434\u0435\u0440\u0436\u0430\u0432\u0438 \u0437\u0430 \u0441\u0442\u0430\u0442\u0442\u0435\u044e 3 \u041a\u043e\u043d\u0432\u0435\u043d\u0446\u0456\u0457 \u0443 \u043f\u0440\u043e\u0446\u0435\u0434\u0443\u0440\u043d\u043e\u043c\u0443, \u0442\u0430\u043a \u0456 \u0432 \u043c\u0430\u0442\u0435\u0440\u0456\u0430\u043b\u044c\u043d\u043e\u043c\u0443 \u0430\u0441\u043f\u0435\u043a\u0442\u0430\u0445."]',	0,	'МІЖНАРОДНИЙ ЗАХИСТ ПРАВ ЛЮДИНИ'),
(132,	'Яку умову виправданості втручання в право на повагу до приватного життя порушено державою-відповідачем у справі «S and Marper проти Сполученого Королівства»?',	'["\u0417\u0430\u043a\u043e\u043d\u043d\u0456\u0441\u0442\u044c.", "\u041d\u0435\u043e\u0431\u0445\u0456\u0434\u043d\u0456\u0441\u0442\u044c \u0443 \u0434\u0435\u043c\u043e\u043a\u0440\u0430\u0442\u0438\u0447\u043d\u043e\u043c\u0443 \u0441\u0443\u0441\u043f\u0456\u043b\u044c\u0441\u0442\u0432\u0456.", "\u041d\u0430\u044f\u0432\u043d\u0456\u0441\u0442\u044c \u043b\u0435\u0433\u0456\u0442\u0438\u043c\u043d\u043e\u0457 \u043c\u0435\u0442\u0438.", "\u042f\u043a\u0456\u0441\u0442\u044c \u0437\u0430\u043a\u043e\u043d\u0443."]',	1,	'МІЖНАРОДНИЙ ЗАХИСТ ПРАВ ЛЮДИНИ'),
(134,	'Які принципи щодо права власності застосував Європейський суд з прав людини у справі «Зеленчук і Цицюра проти України», Nº і Nº 1075/16, 2018 р.?',	'["\u0421\u0443\u0431\u0441\u0438\u0434\u0456\u0430\u0440\u043d\u043e\u0441\u0442\u0456 \u0442\u0430 \u0434\u0435\u043c\u043e\u043a\u0440\u0430\u0442\u0438\u0437\u043c\u0443.", "\u0412\u043e\u043b\u043e\u0434\u0456\u043d\u043d\u044f, \u043a\u043e\u0440\u0438\u0441\u0442\u0443\u0432\u0430\u043d\u043d\u044f \u0442\u0430 \u0440\u043e\u0437\u043f\u043e\u0440\u044f\u0434\u0436\u0435\u043d\u043d\u044f \u043c\u0430\u0439\u043d\u043e\u043c.", "\u0417\u0430\u043a\u043e\u043d\u043d\u043e\u0441\u0442\u0456, \u0437\u0430\u0433\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0456\u043d\u0442\u0435\u0440\u0435\u0441\u0443 \u0442\u0430 \u043f\u0440\u043e\u043f\u043e\u0440\u0446\u0456\u0439\u043d\u043e\u0441\u0442\u0456.", "\u0412\u0456\u043b\u044c\u043d\u043e\u0457 \u043a\u043e\u043d\u043a\u0443\u0440\u0435\u043d\u0446\u0456\u0457 \u0442\u0430 \u0441\u0432\u043e\u0431\u043e\u0434\u0438."]',	2,	'МІЖНАРОДНИЙ ЗАХИСТ ПРАВ ЛЮДИНИ'),
(135,	'У рішенні з якої справи Європейський суд з прав людини констатував порушення статті 2 «Право на життя» Конвенції про захист прав людини і основоположних свобод указавши, що дії співробітників британських спецслужб, які призвели до вбивства трьох членів ІРА не можна вважати таким застосуванням сили, яке було «абсолютно необхідним»?',	'["\u00ab\u0413\u0440\u0456\u0431\u0431\u0435\u043d \u043f\u0440\u043e\u0442\u0438 \u0421\u043f\u043e\u043b\u0443\u0447\u0435\u043d\u043e\u0433\u043e \u041a\u043e\u0440\u043e\u043b\u0456\u0432\u0441\u0442\u0432\u0430\u00bb.", "\u00ab\u0421\u044c\u043e\u0440\u0456\u043d\u0433 \u043f\u0440\u043e\u0442\u0438 \u0421\u043f\u043e\u043b\u0443\u0447\u0435\u043d\u043e\u0433\u043e \u041a\u043e\u0440\u043e\u043b\u0456\u0432\u0441\u0442\u0432\u0430\u00bb,", "\u00ab\u041c\u0430\u043a\u043a\u043e\u0433\u0456 \u0442\u0430 \u0456\u043d\u0448\u0456 \u043f\u0440\u043e\u0442\u0438 \u0421\u043f\u043e\u043b\u0443\u0447\u0435\u043d\u043e\u0433\u043e \u041a\u043e\u0440\u043e\u043b\u0456\u0432\u0441\u0442\u0432\u0430\u00bb.", "\u00ab\u041c\u0430\u043a\u043a\u0430\u043d \u0442\u0430 \u0456\u043d\u0448\u0438 \u043f\u0440\u043e\u0442\u0438 \u0421\u043f\u043e\u043b\u0443\u0447\u0435\u043d\u043e\u0433\u043e \u041a\u043e\u0440\u043e\u043b\u0456\u0432\u0441\u0442\u0432\u0430\u00bb."]',	3,	'МІЖНАРОДНИЙ ЗАХИСТ ПРАВ ЛЮДИНИ'),
(136,	'Оберіть варіант, який містить коректне твердження про Африканський механізм захисту прав людини',	'["\u0410\u0444\u0440\u0438\u043a\u0430\u043d\u0441\u044c\u043a\u0438\u0439 \u043c\u0435\u0445\u0430\u043d\u0456\u0437\u043c \u0437\u0430\u0445\u0438\u0441\u0442\u0443 \u043f\u0440\u0430\u0432 \u043b\u044e\u0434\u0438\u043d\u0438 \u043f\u043e\u0447\u0430\u0432 \u0444\u0443\u043d\u043a\u0446\u0456\u043e\u043d\u0443\u0432\u0430\u0442\u0438 \u0432\u0456\u0434\u0440\u0430\u0437\u0443 \u043f\u0456\u0441\u043b\u044f \u0414\u0440\u0443\u0433\u043e\u0457 \u0441\u0432\u0456\u0442\u043e\u0432\u043e\u0457 \u0432\u0456\u0439\u043d\u0438 \u0456 \u043d\u0430\u0442\u0435\u043f\u0435\u0440 \u0454 \u043d\u0430\u0439\u0435\u0444\u0435\u043a\u0442\u0438\u0432\u043d\u0456\u0448\u0438\u043c \u0440\u0435\u0433\u0456\u043e\u043d\u0430\u043b\u044c\u043d\u0438\u043c \u043c\u0435\u0445\u0430\u043d\u0456\u0437\u043c\u043e\u043c \u0437\u0430\u0445\u0438\u0441\u0442\u0443 \u043f\u0440\u0430\u0432 \u043b\u044e\u0434\u0438\u043d\u0438", "\u0410\u0444\u0440\u0438\u043a\u0430\u043d\u0441\u044c\u043a\u0438\u0439 \u043c\u0435\u0445\u0430\u043d\u0456\u0437\u043c \u0437\u0430\u0445\u0438\u0441\u0442\u0443 \u043f\u0440\u0430\u0432 \u043b\u044e\u0434\u0438\u043d\u0438 \u0441\u043a\u043b\u0430\u0434\u0430\u0454\u0442\u044c\u0441\u044f \u0437 \u041a\u043e\u043c\u0456\u0442\u0435\u0442\u0443 \u043b\u044e\u0434\u0441\u044c\u043a\u0438\u0445 \u043f\u0440\u0430\u0432 \u0442\u0430 \u0410\u0444\u0440\u0438\u043a\u0430\u043d\u0441\u044c\u043a\u043e\u0457 \u043a\u043e\u043c\u0456\u0441\u0456\u0457 \u0437 \u0433\u0435\u043d\u0434\u0435\u0440\u043d\u043e\u0457 \u0440\u0456\u0432\u043d\u043e\u0441\u0442\u0456", "\u0410\u0444\u0440\u0438\u043a\u0430\u043d\u0441\u044c\u043a\u0438\u0439 \u043c\u0435\u0445\u0430\u043d\u0456\u0437\u043c \u0437\u0430\u0445\u0438\u0441\u0442\u0443 \u043f\u0440\u0430\u0432 \u043b\u044e\u0434\u0438\u043d\u0438 \u0440\u043e\u0437\u043f\u043e\u0447\u0430\u0432 \u043f\u043e\u0432\u043d\u043e\u0446\u0456\u043d\u043d\u0435 \u0444\u0443\u043d\u043a\u0446\u0456\u043e\u043d\u0443\u0432\u0430\u043d\u043d\u044f \u0432\u0436\u0435 \u0443 \u0425\u0425\u0406 \u0441\u0442\u043e\u043b\u0456\u0442\u0442\u0456", "\u0410\u0444\u0440\u0438\u043a\u0430\u043d\u0441\u044c\u043a\u0438\u0439 \u043c\u0435\u0445\u0430\u043d\u0456\u0437\u043c \u0437\u0430\u0445\u0438\u0441\u0442\u0443 \u043f\u0440\u0430\u0432 \u043b\u044e\u0434\u0438\u043d\u0438 \u0444\u0430\u043a\u0442\u0438\u0447\u043d\u043e \u043d\u0435 \u0456\u0441\u043d\u0443\u0454, \u0436\u043e\u0434\u043d\u0438\u0445 \u0440\u0435\u0433\u0456\u043e\u043d\u0430\u043b\u044c\u043d\u0438\u0445 \u0434\u043e\u043a\u0443\u043c\u0435\u043d\u0442\u0456\u0432, \u0441\u043f\u0440\u044f\u043c\u043e\u0432\u0430\u043d\u0438\u0445 \u043d\u0430 \u0437\u0430\u0445\u0438\u0441\u0442 \u043f\u0440\u0430\u0432 \u043b\u044e\u0434\u0438\u043d\u0438, \u043d\u0435 \u0443\u0445\u0432\u0430\u043b\u0435\u043d\u043e"]',	2,	'МІЖНАРОДНИЙ ЗАХИСТ ПРАВ ЛЮДИНИ'),
(137,	'Які з наведених нижче категорій осіб, відповідно до усталеної практики ЄСПЛ, НЕ користуються захистом статті 10 ЄКПЛ як «сторожові пси» у демократичному суспільстві?',	'["\u0416\u0443\u0440\u043d\u0430\u043b\u0456\u0441\u0442\u0438 \u0456\u043d\u0442\u0435\u0440\u043d\u0435\u0442-\u0432\u0438\u0434\u0430\u043d\u044c", "\u0410\u043a\u0430\u0434\u0435\u043c\u0456\u0447\u043d\u0456 \u0434\u043e\u0441\u043b\u0456\u0434\u043d\u0438\u043a\u0438", "\u041f\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043d\u0438\u043a\u0438 \u043d\u0435\u0443\u0440\u044f\u0434\u043e\u0432\u0438\u0445 \u043e\u0440\u0433\u0430\u043d\u0456\u0437\u0430\u0446\u0456\u0439", "\u041f\u0440\u0435\u0441-\u0441\u0435\u043a\u0440\u0435\u0442\u0430\u0440\u0456 \u043e\u0440\u0433\u0430\u043d\u0456\u0432 \u0434\u0435\u0440\u0436\u0430\u0432\u043d\u043e\u0457 \u0432\u043b\u0430\u0434\u0438 \u0437 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u043e\u044e \u0404\u0432\u0440\u043e\u043f\u0435\u0439\u0441\u044c\u043a\u043e\u0433\u043e \u0441\u0443\u0434\u0443 \u0437 \u043f\u0440\u0430\u0432 \u043b\u044e\u0434\u0438\u043d\u0438 (\u0404\u0421\u041f\u041b), \"\u0441\u0442\u043e\u0440\u043e\u0436\u043e\u0432\u0438\u043c\u0438 \u0434\u0435\u043c\u043e\u043a\u0440\u0430\u0442\u0438\u0447\u043d\u043e\u0433\u043e \u0441\u0443\u0441\u043f\u0456\u043b\u044c\u0441\u0442\u0432\u0430 \u0454 \u0436\u0443\u0440\u043d\u0430\u043b\u0456\u0441\u0442\u0438, \u043f\u0440\u0430\u0432\u043e\u0437\u0430\u0445\u0438\u0441\u043d\u0438\u043a\u0438, \u0433\u0440\u043e\u043c\u0430\u0434\u0441\u044c\u043a\u0456 \u0434\u0456\u044f\u0447\u0456, \u043d\u0430\u0443\u043a\u043e\u0432\u0446\u0456 \u0442\u0430 \u043f\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043d\u0438\u043a\u0438 \u043d\u0435\u0443\u0440\u044f\u0434\u043e\u0432\u0438\u0445 \u043e\u0440\u0433\u0430\u043d\u0456\u0437\u0430\u0446\u0456\u0439, \u044f\u043a\u0456 \u0430\u043a\u0442\u0438\u0432\u043d\u043e \u0442\u0430 \u0437\u0430\u0445\u0438\u0449\u0430\u044e\u0442\u044c \u043f\u0440\u0430\u0432\u0430 \u043b\u044e\u0434\u0438\u043d\u0438, \u0432\u0438\u043a\u0440\u0438\u0432\u0430\u044e\u0442\u044c \u0437\u043b\u043e\u0432\u0436\u0438\u0432\u0430\u043d\u043d\u044f \u0432\u043b\u0430\u0434\u043e\u044e, \u0442\u0430"]',	3,	'МІЖНАРОДНИЙ ЗАХИСТ ПРАВ ЛЮДИНИ'),
(138,	'Які умови є визначальними для висновку про те, що конкретне місце проживання особи є «житлом» у розумінні його захисту на підставі ст. 8 ЄКПЛ?',	'["\u041d\u0430\u044f\u0432\u043d\u0456\u0441\u0442\u044c \u0434\u043e\u0441\u0442\u0430\u0442\u043d\u0456\u0445 \u0442\u0430 \u0442\u0440\u0438\u0432\u0430\u044e\u0447\u0438\u0445 \u0437\u0432\u2019\u044f\u0437\u043a\u0456\u0432 \u043e\u0441\u043e\u0431\u0438 \u0456\u0437 \u043f\u0440\u0438\u043c\u0456\u0449\u0435\u043d\u043d\u044f\u043c, \u043d\u0435\u0437\u0430\u043b\u0435\u0436\u043d\u043e \u0432\u0456\u0434 \u0437\u0430\u043a\u043e\u043d\u043d\u043e\u0441\u0442\u0456 \u0439\u043e\u0433\u043e \u0437\u0430\u0439\u043d\u044f\u0442\u0442\u044f.", "\u0414\u043e\u0432\u0435\u0434\u0435\u043d\u0438\u0439 \u0444\u0430\u043a\u0442 \u0437\u0430\u043a\u043e\u043d\u043d\u043e\u0441\u0442\u0456 \u0437\u0430\u0439\u043d\u044f\u0442\u0442\u044f \u043e\u0441\u043e\u0431\u043e\u044e \u043f\u0440\u0438\u043c\u0456\u0449\u0435\u043d\u043d\u044f, \u043d\u0435\u0437\u0430\u043b\u0435\u0436\u043d\u043e \u0432\u0456\u0434 \u0442\u0440\u0438\u0432\u0430\u043b\u043e\u0441\u0442\u0456 \u043f\u0435\u0440\u0435\u0431\u0443\u0432\u0430\u043d\u043d\u044f \u0432 \u043d\u044c\u043e\u043c\u0443.", "\u041e\u0431\u0491\u0440\u0443\u043d\u0442\u043e\u0432\u0430\u043d\u0435 \u043f\u0440\u0438\u043f\u0443\u0449\u0435\u043d\u043d\u044f \u0437\u0430\u043a\u043e\u043d\u043d\u043e\u0441\u0442\u0456 \u0437\u0430\u0439\u043d\u044f\u0442\u0442\u044f \u043e\u0441\u043e\u0431\u043e\u044e \u043f\u0440\u0438\u043c\u0456\u0449\u0435\u043d\u043d\u044f, \u043d\u0435\u0437\u0430\u043b\u0435\u0436\u043d\u043e \u0432\u0456\u0434 \u0442\u0440\u0438\u0432\u0430\u043b\u043e\u0441\u0442\u0456 \u043f\u0435\u0440\u0435\u0431\u0443\u0432\u0430\u043d\u043d\u044f \u0432 \u043d\u044c\u043e\u043c\u0443.", "\u0411\u0443\u0434\u044c-\u044f\u043a\u0438\u0439 \u0437\u0432\u2019\u044f\u0437\u043e\u043a \u043e\u0441\u043e\u0431\u0438 \u0456\u0437 \u043f\u0440\u0438\u043c\u0456\u0449\u0435\u043d\u043d\u044f\u043c, \u043d\u0435\u0437\u0430\u043b\u0435\u0436\u043d\u043e \u0432\u0456\u0434 \u0439\u043e\u0433\u043e \u0442\u0440\u0438\u0432\u0430\u043b\u043e\u0441\u0442\u0456 \u0442\u0430 \u0434\u043e\u0441\u0442\u0430\u0442\u043d\u043e\u0441\u0442\u0456."]',	0,	'МІЖНАРОДНИЙ ЗАХИСТ ПРАВ ЛЮДИНИ'),
(139,	'У чому полягає суть свободи розсуду держави згідно з принципами тлумачення ЄСПЛ?',	'["\u041d\u0430\u0446\u0456\u043e\u043d\u0430\u043b\u044c\u043d\u0456 \u043e\u0440\u0433\u0430\u043d\u0438, \u0443 \u043f\u0435\u0440\u0448\u0443 \u0447\u0435\u0440\u0433\u0443, \u043f\u043e\u0432\u0438\u043d\u043d\u0456 \u0432\u0440\u0430\u0445\u043e\u0432\u0443\u0432\u0430\u0442\u0438 \u0441\u043f\u0435\u0446\u0438\u0444\u0456\u043a\u0443 \u0440\u0430\u0442\u0438\u0444\u0456\u043a\u043e\u0432\u0430\u043d\u0438\u0445 \u043c\u0456\u0436\u043d\u0430\u0440\u043e\u0434\u043d\u0438\u0445 \u0442\u0430 \u0454\u0432\u0440\u043e\u043f\u0435\u0439\u0441\u044c\u043a\u0438\u0445 \u043a\u043e\u043d\u0432\u0435\u043d\u0446\u0456\u0439.", "\u041e\u0431\u043e\u0432\u2019\u044f\u0437\u043e\u043a \u0437\u0430\u0441\u0442\u043e\u0441\u043e\u0432\u0443\u0432\u0430\u0442\u0438, \u0442\u043b\u0443\u043c\u0430\u0447\u0438\u0442\u0438 \u0442\u0430 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u0438\u0437\u0443\u0432\u0430\u0442\u0438 \u043d\u043e\u0440\u043c\u0438 \u0404\u041a\u041f\u041b \u043f\u043e\u043a\u043b\u0430\u0434\u0430\u044e\u0442\u044c\u0441\u044f, \u0443 \u043f\u0435\u0440\u0448\u0443 \u0447\u0435\u0440\u0433\u0443, \u043d\u0430 \u043d\u0430\u0446\u0456\u043e\u043d\u0430\u043b\u044c\u043d\u0456 \u043e\u0440\u0433\u0430\u043d\u0438.", "\u0412\u0440\u0430\u0445\u043e\u0432\u0443\u0432\u0430\u0442\u0438, \u0449\u043e \u0412\u0438\u0441\u043e\u043a\u0456 \u0414\u043e\u0433\u043e\u0432\u0456\u0440\u043d\u0456 \u0421\u0442\u043e\u0440\u043e\u043d\u0438 \u0437\u043e\u0431\u043e\u0432\u2019\u044f\u0437\u0443\u044e\u0442\u044c\u0441\u044f \u0432\u0438\u043a\u043e\u043d\u0443\u0432\u0430\u0442\u0438 \u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u0435 \u0440\u0456\u0448\u0435\u043d\u043d\u044f \u0404\u0421\u041f\u041b \u0432 \u0431\u0443\u0434\u044c-\u044f\u043a\u0456\u0439 \u0441\u043f\u0440\u0430\u0432\u0456, \u0434\u0435 \u0432\u043e\u043d\u0438 \u0454 \u0441\u0442\u043e\u0440\u043e\u043d\u0430\u043c\u0438.", "\u0412\u0440\u0430\u0445\u043e\u0432\u0443\u0432\u0430\u0442\u0438 \u0440\u0435\u043a\u043e\u043c\u0435\u043d\u0434\u0430\u0446\u0456\u0457 \u041f\u043b\u0435\u043d\u0443\u043c\u0443 \u0412\u0435\u0440\u0445\u043e\u0432\u043d\u043e\u0433\u043e \u0421\u0443\u0434\u0443 \u0449\u043e\u0434\u043e \u0432\u0456\u043b\u044c\u043d\u043e\u0457 \u043e\u0446\u0456\u043d\u043a\u0438, \u0443 \u043f\u0435\u0440\u0448\u0443 \u0447\u0435\u0440\u0433\u0443, \u0434\u043e\u043f\u0443\u0441\u0442\u0438\u043c\u043e\u0441\u0442\u0456 \u043e\u0431\u043c\u0435\u0436\u0435\u043d\u043d\u044f \u043f\u0440\u0430\u0432 \u0456 \u0441\u0432\u043e\u0431\u043e\u0434."]',	1,	'МІЖНАРОДНИЙ ЗАХИСТ ПРАВ ЛЮДИНИ'),
(140,	'Яке рішення ухвалив Європейський суд з прав людини у справі «Пічкур проти України»?',	'["\u0414\u0438\u0441\u043a\u0440\u0438\u043c\u0456\u043d\u0430\u0446\u0456\u0439\u043d\u0435 \u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u043f\u0440\u0430\u0432\u0430 \u043d\u0430 \u0432\u043b\u0430\u0441\u043d\u0456\u0441\u0442\u044c.", "\u041f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u043f\u0440\u0430\u0432\u0430 \u043d\u0430 \u0432\u043b\u0430\u0441\u043d\u0456\u0441\u0442\u044c \u043d\u0435\u0434\u0438\u0441\u043a\u0440\u0438\u043c\u0456\u043d\u0430\u0446\u0456\u0439\u043d\u043e\u0433\u043e \u0445\u0430\u0440\u0430\u043a\u0442\u0435\u0440\u0443.", "\u041f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u043f\u0440\u0430\u0432\u0430 \u043d\u0430 \u043f\u043e\u0432\u0430\u0433\u0443 \u0434\u043e \u043f\u0440\u0438\u0432\u0430\u0442\u043d\u043e\u0433\u043e \u0436\u0438\u0442\u0442\u044f.", "\u041d\u0435\u043c\u0430\u0454 \u043f\u043e\u0440\u0443\u0448\u0435\u043d\u043d\u044f \u0431\u0443\u0434\u044c-\u044f\u043a\u0438\u0445 \u043f\u0440\u0430\u0432, \u0433\u0430\u0440\u0430\u043d\u0442\u043e\u0432\u0430\u043d\u0438\u0445 \u041a\u043e\u043d\u0432\u0435\u043d\u0446\u0456\u0454\u044e. \u043d\u0435 \u043a \u044d\u0442\u043e\u043c\u0443 \u043a\u043e\u043d\u0442\u0435\u043d\u0442\u0443. \u0441 \u0432\u043b\u0430\u0434\u0435\u043b\u044c\u0446\u0435\u043c \u0444\u043e\u0440\u043c\u044b \u0423\u0441\u043b\u043e\u0432\u0438\u044f \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u0438\u044f \u041f\u043e\u043b\u0438\u0442\u0438\u043a\u0430 \u042d\u0442\u0430 \u0444\u043e\u0440\u043c\u0430 \u043a\u0430\u0436\u0435\u0442\u0441\u044f \u0432\u0430\u043c \u043f\u043e\u0434\u043e\u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0439? \u041f\u043e\u0436\u0430\u043b\u043e\u0432\u0430\u0442\u044c\u0441\u044f \u0424\u043e\u0440\u043c\u044b"]',	0,	'МІЖНАРОДНИЙ ЗАХИСТ ПРАВ ЛЮДИНИ');
